def _forager_bundle_root_dir() -> str:
    """Root folder for ``dashboard.py`` / ``static/`` — PyInstaller extracts to ``_MEIPASS``."""
    if getattr(sys, "frozen", False):
        meipass = getattr(sys, "_MEIPASS", "")
        if meipass:
            return meipass
    return os.path.dirname(os.path.abspath(__file__))


def _forager_embedded_webview() -> bool:
    """True when the UI runs inside pywebview / WebView2 (embedded launcher shell)."""
    return str(os.environ.get("FORAGER_EMBEDDED_WEBVIEW", "")).strip().lower() in {
        "1",
        "true",
        "yes",
        "on",
    }


def _forager_motion_background_path() -> Optional[str]:
    if _forager_embedded_webview():
        return None
    p = os.path.join(_forager_bundle_root_dir(), "static", "forager_bg.mp4")
    return p if os.path.isfile(p) else None


# Slightly under 1× avoids “busy” motion; very low rates + WebView can look steppy between frames.
_FORAGER_MOTION_PLAYBACK_RATE = 0.78


def _forager_motion_background_url() -> str:
    """Streamlit serves ./static beside the running script under ``app/static/<file>``, not ``/static/``.

    Honors ``server.baseUrlPath`` when set. See Streamlit ``url_util.is_relative_static_url``.
    """
    try:
        from streamlit import config as st_config
        from streamlit.url_util import make_url_path

        base = (st_config.get_option("server.baseUrlPath") or "").strip()
        return make_url_path(base, "app/static/forager_bg.mp4")
    except Exception:
        return "/app/static/forager_bg.mp4"


def _forager_static_app_url(*segments: str) -> str:
    """URL for files beside the Streamlit entrypoint under ``static/`` (``app/static/...``)."""
    try:
        from streamlit import config as st_config
        from streamlit.url_util import make_url_path

        base = (st_config.get_option("server.baseUrlPath") or "").strip()
        rel = "/".join(["app", "static", *segments])
        return make_url_path(base, rel)
    except Exception:
        return "/app/static/" + "/".join(segments)


def _forager_three_script_src() -> str:
    """Prefer bundled ``static/vendor/three.min.js`` (offline); fallback to CDN."""
    try:
        local = os.path.join(_forager_bundle_root_dir(), "static", "vendor", "three.min.js")
        if os.path.isfile(local):
            return _forager_static_app_url("vendor", "three.min.js")
    except OSError:
        pass
    return "https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"


def _render_forager_motion_background() -> None:
    """Fullscreen looping video behind chrome: ``markdown`` mounts the clip; optional ``st.html`` nudge for WebView autoplay."""
    if _forager_motion_background_path() is None:
        return

    motion_src_xml = html.escape(_forager_motion_background_url(), quote=True)
    st.markdown(
        f"""
<style>
    #forager-motion-md.forager-motion-bg {{
        position: fixed !important;
        inset: 0 !important;
        width: 100% !important;
        height: 100% !important;
        /* Must stay below in-flow Streamlit blocks; z-index:1 sat above later widgets and hid the UI. */
        z-index: -1 !important;
        pointer-events: none !important;
        overflow: hidden !important;
        /* Own compositor layer + layout isolation: fewer main-thread repaints beside Streamlit chrome */
        isolation: isolate;
        contain: strict;
        transform: translateZ(0);
    }}
    #forager-motion-md.forager-motion-bg video {{
        position: absolute;
        left: 50%;
        top: 50%;
        width: auto;
        height: auto;
        min-width: 100%;
        min-height: 100%;
        transform: translate3d(-50%, -50%, 0);
        backface-visibility: hidden;
        object-fit: cover;
        /* Keep effects off the video element — filter() often makes WebView/Chromium frame delivery choppy */
        opacity: 0.28;
    }}
    #forager-motion-md .forager-motion-scrim {{
        position: absolute;
        inset: 0;
        pointer-events: none;
        /* Lighter veil so bokeh survives; UI chrome still dominates */
        background: linear-gradient(
            185deg,
            rgba(5, 10, 8, 0.5) 0%,
            rgba(4, 6, 5, 0.55) 50%,
            rgba(3, 4, 3, 0.58) 100%
        );
    }}
</style>
<div id="forager-motion-md" class="forager-motion-bg" aria-hidden="true">
    <video autoplay muted loop playsinline preload="auto" disablepictureinpicture>
        <source src="{motion_src_xml}" type="video/mp4" />
    </video>
    <div class="forager-motion-scrim"></div>
</div>
""",
        unsafe_allow_html=True,
    )
    # WebView2 occasionally needs an explicit muted play(); markdown video alone can appear "frozen".
    _inject_forager_motion_play_nudge()


def _inject_forager_motion_play_nudge() -> None:
    """Best-effort: call ``video.play()`` after the markdown node mounts (frozen WebView quirks)."""
    if _forager_embedded_webview():
        return
    html_fn = getattr(st, "html", None)
    if not callable(html_fn):
        return
    rate = float(_FORAGER_MOTION_PLAYBACK_RATE)
    try:
        html_fn(
            f"""<script>
(function () {{
  var p = window.parent || window;
  if (p.__foragerMotionPlayNudgeDone) return;
  p.__foragerMotionPlayNudgeDone = 1;
  var _pr = {rate};
  function tryPlay() {{
    var d = p.document || document;
    var v = d.querySelector("#forager-motion-md video");
    if (!v) return false;
    try {{ v.muted = true; }} catch (e) {{}}
    try {{ v.loop = true; }} catch (e2) {{}}
    function applyRate() {{
      try {{ v.playbackRate = _pr; }} catch (ePR) {{}}
    }}
    applyRate();
    if (!v.foragerRateArmed) {{
      v.foragerRateArmed = true;
      try {{
        v.addEventListener("loadeddata", applyRate);
        v.addEventListener("canplay", applyRate);
      }} catch (eL) {{}}
    }}
    try {{
      var playP = v.play();
      if (playP && typeof playP.catch === "function") playP.catch(function () {{}});
    }} catch (e3) {{}}
    return true;
  }}
  if (!tryPlay()) {{
    var i = 0;
    var t = window.setInterval(function () {{
      if (tryPlay() || ++i >= 24) window.clearInterval(t);
    }}, 80);
  }}
}})();
</script>""",
            unsafe_allow_javascript=True,
        )
    except Exception:
        pass


