def _resolve_app_packs_directory() -> str:
    """Writable pack folders root (each pack = one subdirectory with ``pack.manifest.json``).

    Resolution order:

    1. **`FORAGER_PACKS_DIR`** — folder that *contains* your pack dirs (same layout as repo ``packs/MyPack/...``).
       Point the frozen ``.exe`` at your git checkout packs without copying.
    2. **Frozen**: ``packs`` next to ``sys.executable`` (persistent; not under PyInstaller ``_MEIPASS``).
    3. **Source**: ``packs`` next to ``dashboard.py``.

    Older frozen builds resolved ``packs`` under the extraction temp folder, so packs in the repo were invisible.
    """
    override = (os.getenv("FORAGER_PACKS_DIR") or "").strip()
    if override:
        return os.path.normpath(os.path.expanduser(override))
    if getattr(sys, "frozen", False):
        return os.path.join(os.path.dirname(os.path.abspath(sys.executable)), "packs")
    return os.path.join(os.path.dirname(os.path.abspath(__file__)), "packs")


PACKS_DIR = _resolve_app_packs_directory()


def _workspace_pack_dir_names() -> List[str]:
    """Live listing of child folders under ``PACKS_DIR`` (used by Power Lab pickers)."""
    try:
        return sorted(
            d
            for d in os.listdir(PACKS_DIR)
            if os.path.isdir(os.path.join(PACKS_DIR, d)) and not str(d).startswith(".")
        )
    except OSError:
        return []


def _ensure_default_pack_when_empty_portable() -> None:
    """Frozen app: guarantee at least `StarterPack` so the unified Forager lane works without manual mkdir."""
    os.makedirs(PACKS_DIR, exist_ok=True)
    if not getattr(sys, "frozen", False):
        return
    mark = os.getenv("FORAGER_NO_AUTO_PACK", "").strip().lower()
    if mark in {"1", "true", "yes", "on"}:
        return
    try:
        subs = [
            entry
            for entry in os.listdir(PACKS_DIR)
            if os.path.isdir(os.path.join(PACKS_DIR, entry)) and not entry.startswith(".")
        ]
    except OSError:
        return
    if subs:
        return
    starter = os.path.join(PACKS_DIR, "StarterPack")
    try:
        os.makedirs(starter, exist_ok=True)
        init_pack_manifest(starter, pack_id="StarterPack")
    except OSError:
        pass

