def _forager_nav_history_commit(current: str) -> None:
    """Record forward navigation so Back / mouse-back can restore the previous route."""
    old = st.session_state.get("_forager_nav_history_last")
    if st.session_state.pop("_forager_nav_history_skip_push", False):
        st.session_state["_forager_nav_history_last"] = current
        return
    if old == current:
        return
    stack = st.session_state.setdefault("forager_nav_history_stack", [])
    if old is not None:
        stack.append(old)
        while len(stack) > FORGER_NAV_HISTORY_LIMIT:
            stack.pop(0)
    st.session_state["_forager_nav_history_last"] = current


def _forager_nav_history_go_back() -> bool:
    stack = st.session_state.get("forager_nav_history_stack") or []
    if not stack:
        return False
    prev = stack.pop()
    st.session_state["forager_nav_history_stack"] = stack
    st.session_state["forager_nav"] = prev
    st.session_state["_forager_nav_history_skip_push"] = True
    return True


def _forager_nav_history_can_back() -> bool:
    return bool(st.session_state.get("forager_nav_history_stack"))


def _forager_nav_reset_main_scroll_after_route_change(current_page: str) -> None:
    """Scroll the host main column to the top when the sidebar/query route changes.

    Streamlit reruns replace widget output, but the browser often keeps the prior
    scroll offset on the main scroller. After a long **Browse Modpacks** session,
    switching to **My Packs** could leave the viewport scrolled deep in the layout,
    so the new page reads like a short header with the old screen still visible
    below (especially in embedded webview shells).
    """
    prev = st.session_state.get("_forager_prev_page")
    if not isinstance(prev, str) or prev == current_page:
        return
    components.html(
        "<script>(function(){function go(){try{"
        "var d=window.parent&&window.parent.document;if(!d)return;"
        "var sels=['section[data-testid=\"stMain\"]','[data-testid=\"stAppViewContainer\"]','section.main','.main'];"
        "for(var i=0;i<sels.length;i++){var el=d.querySelector(sels[i]);if(el)try{el.scrollTop=0;}catch(e){}}"
        "try{if(window.parent.scrollY>0)window.parent.scrollTo(0,0);}catch(e2){}"
        "}catch(x){}}"
        "var raf=window.requestAnimationFrame||function(f){setTimeout(f,0);};"
        "raf(function(){raf(function(){go();});});})();</script>",
        height=0,
        width=0,
    )


def _forager_instances_sync_pack_grid_from_query() -> None:
    """Apply ``?forager_pack_cols=`` (2–6) from the resize probe, then strip it from the URL."""
    _gqp = st.query_params.get("forager_pack_cols")
    if not _gqp:
        return
    try:
        _raw = _gqp[0] if isinstance(_gqp, list) else _gqp
        _n = int(_raw)
        st.session_state["_forager_pack_grid_cols"] = max(2, min(6, _n))
    except Exception:
        pass
    try:
        del st.query_params["forager_pack_cols"]
    except Exception:
        pass


def _forager_instances_pack_grid_resize_probe() -> None:
    """Listen for host resize only — never force a Streamlit reload (WebView2 + ``location.replace`` froze the shell)."""
    if _forager_embedded_webview():
        return
    components.html(
        "<script>(function(){var p=window.parent;try{"
        "function infer(){try{var w=p.innerWidth||1200;return Math.max(2,Math.min(6,Math.floor((w-300)/280)));}catch(e){return 4;}}"
        "function apply(){var n=infer(),last=-999;try{last=parseInt(p.sessionStorage.getItem('forager_pack_cols_n')||'-999',10);}"
        "catch(e1){}if(last===n)return;try{p.sessionStorage.setItem('forager_pack_cols_n',String(n));}catch(e2){}"
        "try{var u=new URL(p.location.href);u.searchParams.set('forager_pack_cols',String(n));p.location.replace(String(u));}catch(e3){}}"
        "if(!p.__foragerPackGridResizeHook){p.__foragerPackGridResizeHook=1;var t;function deb(){clearTimeout(t);t=setTimeout(apply,420);}"
        "try{p.addEventListener('resize',deb,{passive:true});}catch(e4){}}"
        "}catch(x){}})();</script>",
        height=0,
        width=0,
    )


def _forager_runtime_fingerprint() -> Tuple[str, Dict[str, str]]:
    """Short label + detail map so you can confirm the UI is this checkout / build, not a stale exe."""
    bundle = getattr(sys, "_MEIPASS", None)
    root = os.path.dirname(os.path.abspath(__file__))
    mode = "frozen exe" if bundle else "source / dev"
    details: Dict[str, str] = {
        "UI revision": FORAGER_UI_REVISION,
        "Run mode": mode,
        "dashboard folder": root,
        "Writable packs/": PACKS_DIR,
    }
    if bundle:
        details["PyInstaller MEIPASS"] = str(bundle)
    dash_py = os.path.join(root, "dashboard.py")
    try:
        mtime = os.path.getmtime(dash_py)
        details["dashboard.py changed"] = datetime.fromtimestamp(mtime, tz=timezone.utc).strftime(
            "%Y-%m-%d %H:%M UTC"
        )
    except OSError:
        details["dashboard.py"] = "not found beside module"
    details["Python"] = f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}"
    details["Streamlit"] = str(getattr(st, "__version__", "?"))
    log_p = os.path.join(tempfile.gettempdir(), "forager_launcher.log")
    details["Launcher log"] = log_p
    tls = (os.environ.get("FORAGER_STRICT_TLS") or "").strip()
    details["FORAGER_STRICT_TLS"] = (
        tls if tls else "(unset — catalog APIs may retry with verify=False if certs fail)"
    )
    pk_ov = (os.getenv("FORAGER_PACKS_DIR") or "").strip()
    if pk_ov:
        details["FORAGER_PACKS_DIR"] = os.path.normpath(os.path.expanduser(pk_ov))
    label = f"{FORAGER_UI_REVISION} · {mode}"
    return label, details


def _forager_chrome_scope_line(page: str) -> str:
    """Short scope hint for sticky chrome (configure route, install target, etc.)."""
    bits: List[str] = []
    cfg = (st.session_state.get("forager_config_instance") or "").strip()
    if cfg:
        bits.append(f"Configure pack · {cfg}")
    if page in ("ai_architect", "power_center"):
        _ai_ws = (st.session_state.get(FORAGER_AI_POWER_LAB_PACK_KEY) or "").strip()
        if _ai_ws:
            bits.append(f"AI lab · packs/{_ai_ws}")
    if page == "mods":
        it = str(st.session_state.get("mods_install_target") or "")
        if it.startswith("Minecraft"):
            ti = (st.session_state.get("mods_target_instance") or "").strip()
            if ti:
                bits.append(f"Browse installs · {ti}")
        elif it.startswith("Pack"):
            tp = (st.session_state.get("mods_target_pack") or "").strip()
            if tp:
                bits.append(f"Browse installs · packs/{tp}")
    if page == "instances" and (st.session_state.get("instance_library_filter") or "").strip():
        bits.append(f"Library filter · “{(st.session_state.get('instance_library_filter') or '').strip()[:48]}”")
    if page == "pack_create":
        bits.append("New native instance under packs/")
    return " · ".join(bits) if bits else ""


def _forager_activity_push(message: str) -> None:
    """Append a short line to the sticky footer activity strip (dedupe consecutive repeats)."""
    log = st.session_state.setdefault("forager_activity_log", [])
    ts = datetime.now(timezone.utc).strftime("%H:%M UTC")
    line = f"{ts} — {message}"
    if log and log[-1] == line:
        return
    log.append(line)
    st.session_state["forager_activity_log"] = log[-12:]


def _forager_activity_footer_html() -> str:
    log = st.session_state.get("forager_activity_log") or []
    if not log:
        return ""
    tail = log[-3:]
    esc = " · ".join(html.escape(x) for x in tail)
    return f'<div class="forager-ft-activity" title="{html.escape(chr(10).join(log))}">{esc}</div>'


@contextmanager
def _perf_span(name: str):
    """Tiny opt-in runtime probe for hot sections (shown only when enabled in session)."""
    t0 = time.perf_counter()
    try:
        yield
    finally:
        if bool(st.session_state.get("forager_perf_debug")):
            took = (time.perf_counter() - t0) * 1000.0
            rows = st.session_state.setdefault("_forager_perf_rows", [])
            rows.append({"name": str(name), "ms": round(took, 2)})
            st.session_state["_forager_perf_rows"] = rows[-40:]


def _render_council_merged_card(chair: Dict[str, Any]) -> None:
    """Chair merge: verdict, actions, lessons — keep full JSON elsewhere."""
    if not isinstance(chair, dict) or not chair:
        return
    verdict = str(chair.get("final_verdict") or "revise").strip().lower()
    vcol = {"pass": "#34d399", "revise": "#fbbf24", "block": "#f87171"}.get(verdict, "#94a3b8")
    st.markdown(
        f'<div class="forager-council-merge" style="border-left:4px solid {vcol};padding:0.5rem 0.75rem;margin:0.35rem 0;'
        f'background:rgba(15,23,42,0.65);border-radius:8px;border:1px solid rgba(148,163,184,0.22);">'
        f'<div style="font-size:0.72rem;text-transform:uppercase;letter-spacing:0.12em;color:#94a3b8;font-weight:700;">'
        f"Merged recommendation (Chair)</div>"
        f'<div style="font-size:1.05rem;font-weight:800;color:{vcol};margin-top:0.2rem;">Verdict: {html.escape(verdict)}</div>'
        "</div>",
        unsafe_allow_html=True,
    )
    acts = chair.get("recommended_actions") or []
    if isinstance(acts, list) and acts:
        st.markdown("**Recommended actions**")
        for i, a in enumerate(acts[:12], start=1):
            st.markdown(f"{i}. {html.escape(str(a))}")
    less = str(chair.get("synthesized_lessons") or "").strip()
    if less:
        st.markdown("**Synthesized lessons**")
        st.caption(less[:2400])
    issues = chair.get("issues") or []
    if isinstance(issues, list) and issues:
        with st.expander("Chair issues (detail)", expanded=False):
            for it in issues[:24]:
                if not isinstance(it, dict):
                    continue
                sev = str(it.get("severity") or "low")
                det = str(it.get("detail") or "")
                own = str(it.get("owner") or "")
                st.markdown(f"- **{html.escape(sev)}** ({html.escape(own)}): {html.escape(det)}")


