def _curseforge_downloader_ready(downloader) -> bool:
    """True if a CurseForge API key is available (works with cached launcher instances from older code)."""
    fn = getattr(downloader, "curseforge_configured", None)
    if callable(fn):
        return bool(fn())
    override = getattr(downloader, "_curseforge_key_override", None)
    if isinstance(override, str) and override.strip():
        return True
    return bool((os.environ.get("CURSEFORGE_API_KEY") or "").strip())


def _probe_curseforge_api_key(key: str) -> tuple[bool, str]:
    """Return ``(ok, message)`` after a minimal ``GET /v1/games`` probe (does not persist anything)."""
    k = (key or "").strip()
    if not k:
        return False, "Key is empty — paste the token from your CurseForge developer console, then save."
    try:
        r = requests.get(
            "https://api.curseforge.com/v1/games",
            headers={"Accept": "application/json", "x-api-key": k},
            timeout=20,
        )
    except requests.RequestException as exc:
        return False, f"Could not reach CurseForge (network / firewall / VPN). `{exc}`"
    if r.status_code == 200:
        return True, "CurseForge accepted this key (HTTP 200)."
    if r.status_code in (401, 403):
        return (
            False,
            f"CurseForge rejected this key (HTTP {r.status_code}). "
            "Paste the full **Core API** token from the console (often a long random string). "
            "If the console only shows a short `$2a$…` fragment, use **Copy** — the real token is usually longer.",
        )
    snippet = (r.text or "").strip().replace("\n", " ")[:220]
    return False, f"Unexpected HTTP {r.status_code}: {snippet!r}"


def _image_mime(data: bytes, fallback_path: str = "") -> str:
    if data.startswith(b"\x89PNG\r\n\x1a\n"):
        return "image/png"
    if data.startswith(b"\xff\xd8"):
        return "image/jpeg"
    if data[:6] in (b"GIF87a", b"GIF89a"):
        return "image/gif"
    if len(data) >= 12 and data[:4] == b"RIFF" and data[8:12] == b"WEBP":
        return "image/webp"
    suffix = Path(fallback_path).suffix.lower()
    if suffix in {".jpg", ".jpeg"}:
        return "image/jpeg"
    if suffix == ".webp":
        return "image/webp"
    return "image/png"


def _local_image_to_data_uri(path: str) -> Optional[str]:
    p = Path(str(path or "")).expanduser()
    if not p.is_file():
        return None
    try:
        data = p.read_bytes()
    except OSError:
        return None
    # Keep Streamlit markdown light; pack thumbnails are usually small.
    if not data or len(data) > 1_250_000:
        return None
    mime = _image_mime(data, str(p))
    return f"data:{mime};base64,{base64.b64encode(data).decode('ascii')}"


def _read_json_file(path: str) -> Dict[str, Any]:
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except (OSError, json.JSONDecodeError, TypeError):
        return {}


def _instance_metadata_path(instance: MinecraftInstance) -> Optional[str]:
    root = Path(instance.instance_path)
    source = (getattr(instance, "linked_source", "") or "").lower()
    candidates: List[Path] = []
    if source == "curseforge":
        candidates.extend([root / "minecraftinstance.json", root.parent / "minecraftinstance.json"])
    elif source == "modrinth":
        candidates.extend([root / "profile.json", root.parent / "profile.json"])
    for p in candidates:
        if p.is_file():
            return str(p)
    # Walk up: CurseForge often sets installPath to a subfolder without minecraftinstance.json beside it.
    try:
        cur = root
        for _ in range(12):
            cand = cur / "minecraftinstance.json"
            if cand.is_file():
                return str(cand)
            if cur.parent == cur:
                break
            cur = cur.parent
    except OSError:
        pass
    # Modrinth profile.json may live only under the global profiles folder; walk-up for local copies.
    if source == "modrinth":
        try:
            cur = root
            for _ in range(12):
                cand = cur / "profile.json"
                if cand.is_file():
                    return str(cand)
                if cur.parent == cur:
                    break
                cur = cur.parent
        except OSError:
            pass
    return None


def _launcher_external_scan_roots() -> Tuple[List[str], List[str]]:
    cfg = getattr(launcher, "config", None) or {}
    if not isinstance(cfg, dict):
        return [], []
    cf_root = (cfg.get("curseforge_instances_root") or "").strip()
    mr_root = (cfg.get("modrinth_profiles_root") or "").strip()
    return ([cf_root] if cf_root else [], [mr_root] if mr_root else [])


def _source_pack_metadata(instance: MinecraftInstance) -> Dict[str, Any]:
    data: Dict[str, Any] = {}
    meta_path = _instance_metadata_path(instance)
    if meta_path:
        data = _read_json_file(meta_path)
    source = (getattr(instance, "linked_source", "") or "").lower()
    cf_extra, mr_extra = _launcher_external_scan_roots()
    if source == "curseforge":
        cf_disk = curseforge_metadata_for_game_root(instance.instance_path, extra_roots=cf_extra)
        if cf_disk:
            data = {**data, **cf_disk}
        leid = str(getattr(instance, "linked_external_id", None) or "").strip()
        if not leid or not leid.startswith("cf:"):
            recovered = curseforge_lookup_stable_id_by_game_root(
                instance.instance_path, extra_roots=cf_extra
            )
            if recovered:
                leid = recovered
                setattr(instance, "linked_external_id", recovered)
                _lm = globals().get("launcher")
                if _lm is not None:
                    try:
                        _lm.instance_manager.update_instance(instance.name, linked_external_id=recovered)
                    except Exception:
                        pass
        cf_row = curseforge_minecraftinstance_by_linked_id(leid, extra_roots=cf_extra)
        if cf_row:
            data = {**data, **cf_row}
    if source == "modrinth":
        mr_disk = modrinth_profile_for_game_root(instance.instance_path, extra_roots=mr_extra)
        if mr_disk:
            data = {**mr_disk, **data}
    try:
        idx_path = Path(instance.instance_path) / "modrinth.index.json"
        if idx_path.is_file():
            idx_data = _read_json_file(str(idx_path))
            if idx_data:
                data = {**idx_data, **data}
    except OSError:
        pass
    return data if data else {}


def _authors_blob_to_text(raw: Any) -> str:
    """Normalize author / authors fields from launcher JSON (str, dict, or list)."""
    if raw is None:
        return ""
    if isinstance(raw, str):
        return raw.strip()
    if isinstance(raw, dict):
        for key in ("name", "author", "displayName", "display_name"):
            val = str(raw.get(key) or "").strip()
            if val:
                return val
        return ""
    if isinstance(raw, list):
        parts: List[str] = []
        for item in raw[:6]:
            val = _authors_blob_to_text(item)
            if val and val not in parts:
                parts.append(val)
        return ", ".join(parts)
    return ""


def _pack_author_from_metadata(data: Dict[str, Any]) -> str:
    """Best-effort modpack author from CurseForge / Modrinth profile JSON already on disk."""
    if not isinstance(data, dict) or not data:
        return ""
    for key in ("author", "authors", "owner", "ownerName", "team"):
        val = _authors_blob_to_text(data.get(key))
        if val:
            return val
    for nest_key in ("baseModPack", "installedModpack", "metadata", "linked_data", "modrinth", "pack", "profile"):
        nest = data.get(nest_key)
        if isinstance(nest, dict):
            for key in ("author", "authors", "owner", "ownerName", "team"):
                val = _authors_blob_to_text(nest.get(key))
                if val:
                    return val
    return ""


def _instance_pack_author_label(instance: MinecraftInstance) -> str:
    """Modpack author for tile subtitles — disk metadata only (no catalog API calls)."""
    data = _source_pack_metadata(instance)
    author = _pack_author_from_metadata(data)
    if author:
        return author
    try:
        root = Path(instance.instance_path)
        for manifest in (root / "manifest.json", root.parent / "manifest.json"):
            if not manifest.is_file():
                continue
            mj = _read_json_file(str(manifest))
            author = _pack_author_from_metadata(mj)
            if author:
                return author
    except OSError:
        pass
    return ""


def _instance_tile_subtitle_line(instance: MinecraftInstance) -> str:
    loader_txt = _loader_badge_text(instance.loader)
    mc_txt = str(instance.minecraft_version or "?")
    tech_line = f"{loader_txt} {mc_txt}".strip()
    linked_source = getattr(instance, "linked_source", None)
    if not linked_source:
        return f"{tech_line} · My creation" if tech_line else "My creation"
    source_label = (
        "CurseForge"
        if str(linked_source or "").lower() == "curseforge"
        else "Modrinth"
        if str(linked_source or "").lower() == "modrinth"
        else "Forager"
    )
    author = _instance_pack_author_label(instance)
    tail = f"by {author}" if author else f"By {source_label}"
    return f"{tech_line} · {tail}" if tech_line else tail


def _deep_scan_curseforge_numeric_project_ids(obj: Any, depth: int = 0) -> List[int]:
    """Find likely CurseForge pack project ids in launcher JSON (avoid per-mod file entry ids)."""
    found: List[int] = []
    if depth > 10:
        return found
    skip_nested = {"files", "installedmods", "installedaddons", "installed_mods", "addons", "mods"}
    if isinstance(obj, dict):
        for k, v in obj.items():
            ks = str(k).lower()
            if ks in skip_nested:
                continue
            if any(
                x in ks
                for x in ("project", "curse", "package", "modpack")
            ) and "file" not in ks and v is not None:
                try:
                    n = int(v)
                    if 50 < n < 2_000_000_000:
                        found.append(n)
                except (TypeError, ValueError):
                    pass
            found.extend(_deep_scan_curseforge_numeric_project_ids(v, depth + 1))
    elif isinstance(obj, list):
        for item in obj[:40]:
            found.extend(_deep_scan_curseforge_numeric_project_ids(item, depth + 1))
    return found


def _uniq_ints_preserve(values: List[int]) -> List[int]:
    seen = set()
    out: List[int] = []
    for v in values:
        if v not in seen:
            seen.add(v)
            out.append(v)
    return out


def _modrinth_project_id_token(s: str) -> bool:
    """True for Modrinth slug or project UUID (Theseus stores UUID in profile ids)."""
    t = str(s).strip()
    if len(t) < 2 or len(t) > 64:
        return False
    if re.fullmatch(r"(?i)[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}", t):
        return True
    return bool(re.fullmatch(r"(?i)[a-z0-9][a-z0-9_.-]{0,62}", t))


def _modrinth_profile_icon_lookups(data: Dict[str, Any]) -> List[str]:
    """Project id / slug values to pass to Modrinth GET /project/{id}."""
    out: List[str] = []

    def _push(v: Any) -> None:
        if v is None:
            return
        s = str(v).strip()
        if s and _modrinth_project_id_token(s) and s not in out:
            out.append(s)

    for key in ("project_id", "projectId", "linked_project_id", "modrinth_project_id"):
        _push(data.get(key))
    _push(data.get("id"))
    md = data.get("metadata")
    if isinstance(md, dict):
        for key in ("project_id", "projectId", "slug"):
            _push(md.get(key))
    for key in ("slug", "project_slug"):
        _push(data.get(key))
    for nest_key in ("linked_data", "modrinth", "pack", "profile"):
        nest = data.get(nest_key)
        if isinstance(nest, dict):
            for key in ("project_id", "projectId", "id", "slug", "project"):
                _push(nest.get(key))
    return out


def _manifest_pack_project_id(instance_path: str) -> Optional[int]:
    """CurseForge modpack manifest.json: pack projectID at root only.

    Do not read ``files[0].projectID`` — that is often a **dependency mod**, not the pack,
    which produces wrong CurseForge thumbnails.
    """
    root = Path(os.path.normpath(os.path.expandvars(os.path.expanduser(instance_path))))
    for manifest in (root / "manifest.json", root.parent / "manifest.json"):
        if not manifest.is_file():
            continue
        raw = _read_json_file(str(manifest))
        if not raw:
            continue
        pid = raw.get("projectID") or raw.get("projectId")
        if pid is None:
            continue
        try:
            return int(pid)
        except (TypeError, ValueError):
            continue
    return None


def _curseforge_base_modpack_project_id(data: Dict[str, Any]) -> Optional[int]:
    """minecraftinstance.json: ``baseModPack`` / ``installedModpack`` hold the real pack project id."""
    for key in ("baseModPack", "installedModpack"):
        v = data.get(key)
        if not isinstance(v, dict):
            continue
        for k2 in ("projectID", "projectId", "id"):
            if k2 not in v:
                continue
            try:
                n = int(v[k2])
                if n > 0:
                    return n
            except (TypeError, ValueError, KeyError):
                continue
    return None


def _metadata_curseforge_project_id(data: Dict[str, Any]) -> Optional[int]:
    """minecraftinstance.json and related launcher files store the CurseForge project id under a few keys."""
    for key in ("projectID", "projectId", "curseProjectId", "curse_project_id", "curseprojectid"):
        v = data.get(key)
        if v is None:
            continue
        try:
            n = int(v)
            if n > 0:
                return n
        except (TypeError, ValueError):
            continue
    return None


def _pack_display_name_queries(instance: MinecraftInstance, data: Dict[str, Any]) -> List[str]:
    """Names to try when searching Modrinth / CF / web for pack art (instance display name often differs)."""
    out: List[str] = []
    man = data.get("manifest")
    manifest_name: Optional[str] = None
    if isinstance(man, dict):
        manifest_name = str(man.get("name") or "").strip() or None
    if not manifest_name:
        try:
            mp = Path(instance.instance_path) / "manifest.json"
            if mp.is_file():
                mj = _read_json_file(str(mp))
                if isinstance(mj, dict):
                    manifest_name = str(mj.get("name") or "").strip() or None
        except OSError:
            pass
    for raw in (instance.name, data.get("name"), manifest_name):
        s = str(raw or "").strip()
        if s and s not in out:
            out.append(s)
    bmp = data.get("baseModPack")
    if isinstance(bmp, dict):
        bn = str(bmp.get("name") or "").strip()
        if bn and bn not in out:
            out.insert(0, bn)
    return out


def _extract_nested_icon_url(data: Dict[str, Any]) -> Optional[str]:
    keys = ("iconUrl", "icon_url", "thumbnailUrl", "logoUrl", "logo_url", "avatarUrl")
    for key in keys:
        val = data.get(key)
        if isinstance(val, str) and val.strip():
            return val.strip()
    for key in ("icon", "logo", "image", "thumbnail", "avatar", "images"):
        val = data.get(key)
        if isinstance(val, str) and val.strip():
            return val.strip()
        if isinstance(val, dict):
            found = _extract_nested_icon_url(val)
            if found:
                return found
        if isinstance(val, list):
            for item in val:
                if isinstance(item, str) and item.strip():
                    return item.strip()
                if isinstance(item, dict):
                    found = _extract_nested_icon_url(item)
                    if found:
                        return found
    return None


def _is_probably_local_image(value: str) -> bool:
    if not value or value.startswith(("http://", "https://", "data:")):
        return False
    suffix = Path(value).suffix.lower()
    return suffix in {".png", ".jpg", ".jpeg", ".webp", ".gif"}


def _norm_pack_name(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).strip()


def _pack_name_score(query: str, candidate: str) -> int:
    q = _norm_pack_name(query)
    c = _norm_pack_name(candidate)
    if not q or not c:
        return 0
    if q == c:
        return 120
    q_words = {w for w in q.split() if len(w) > 1}
    c_words = {w for w in c.split() if len(w) > 1}
    overlap = len(q_words & c_words)
    score = overlap * 18
    if len(q) >= 6 and q in c:
        score += 70
    if len(c) >= 6 and c in q:
        score += 58
    return score


def _curseforge_known_modpack_slugs(base: str) -> List[str]:
    """Official CurseForge ``/minecraft/modpacks/{slug}`` paths for packs whose folder names
    do not match hyphen slugs (e.g. ``RL Craft`` → ``rl-craft`` is wrong; must be ``rlcraft``).

    Tried first by ``_curseforge_public_pack_image`` so OG cover art matches the real pack.
    """
    out: List[str] = []
    # RLCraft — instance names are usually "RL Craft" (two words); heuristics yield "rl-craft".
    if "rl craft" in base or base.replace(" ", "") == "rlcraft":
        out.append("rlcraft")
    # MC Eternal 1 vs 2 — ambiguous names: prefer "2" when the display name signals sequel.
    if "mc eternal" in base:
        if re.search(r"\b2\b", base) or re.search(r"\bii\b", base):
            out.extend(["mc-eternal-2", "mc-eternal"])
        else:
            out.extend(["mc-eternal", "mc-eternal-2"])
    # SUPERIOR - RPG (Curse slug is not "superior-rpg"); titles vary ("SUPERIOR", "Superior RPG").
    if "superior" in base and ("rpg" in base or "greatest" in base):
        out.append("superior-the-greatest-rpg-modpack-ever-made")
    # Vault Hunters — edition slugs are not "vault-hunters" alone.
    if "vault" in base and "hunter" in base:
        out.extend(
            [
                "vault-hunters-1-18-2",
                "vault-hunters-official-modpack",
            ]
        )
    # SteamPunk [LPS] is the common "steampunk" hit; distinct from Steampunk's Paradise.
    if "steampunk" in base or "steam punk" in base:
        out.extend(["steam-punk", "steampunks-paradise", "steampunk-craft-modpack"])
    return out


def _curseforge_slug_candidates(name: str) -> List[str]:
    base = _norm_pack_name(name)
    if not base:
        return []
    words = base.split()
    candidates: List[str] = []
    candidates.extend(_curseforge_known_modpack_slugs(base))
    candidates.extend(
        [
            "-".join(words),
            "-".join(w for w in words if not re.fullmatch(r"atm\d+|rpg|lps|official|modpack|third|edition", w)),
        ]
    )
    if "atm" in base and any(w.isdigit() for w in words):
        for w in words:
            if w.isdigit():
                candidates.append(f"all-the-mods-{w}")
    if "rlcraft" in base:
        candidates.append("rlcraft")
    out: List[str] = []
    seen: set[str] = set()
    for c in candidates:
        c = re.sub(r"-+", "-", c.strip("-").lower())
        if c and c not in seen:
            seen.add(c)
            out.append(c)
    return out[:12]


def _requests_get_with_tls_fallback(
    url: str,
    *,
    timeout: int = 22,
    headers: Optional[Dict[str, str]] = None,
):
    """
    GET with verify=True, then verify=False on any RequestException.

    On some Windows/Python builds the trust store fails verification; caching those
    failures (or empty JSON) made pack art stay broken for 24h.
    """
    hdrs = {**(headers or {})}
    if not any(k.lower() == "user-agent" for k in hdrs):
        hdrs["User-Agent"] = "ForagerAI/1.0 (pack art; +https://github.com/forager-ai)"
    for verify in (True, False):
        try:
            return requests.get(url, timeout=timeout, headers=hdrs, verify=verify)
        except requests.RequestException:
            if verify:
                continue
    return None


def _http_json_with_tls_fallback(url: str) -> Dict[str, Any]:
    """Fetch JSON from a URL; do not cache (avoids freezing failed TLS/empty payloads)."""
    response = _requests_get_with_tls_fallback(url, timeout=18)
    if response is None or response.status_code >= 400:
        return {}
    try:
        data = response.json()
    except ValueError:
        return {}
    return data if isinstance(data, dict) else {}


def _curseforge_mirror_mod_summary(
    project_id: str,
) -> Tuple[Optional[str], Optional[str], Optional[int], Optional[str]]:
    """api.curse.tools mod: logo URL, display name, classId, slug."""
    pid = str(project_id or "").strip()
    if not pid or not pid.isdigit():
        return None, None, None, None
    payload = _http_json_with_tls_fallback(f"https://api.curse.tools/v1/cf/mods/{pid}")
    data: Dict[str, Any] = {}
    if isinstance(payload.get("data"), dict):
        data = payload["data"]
    elif isinstance(payload, dict) and ("logo" in payload or "name" in payload):
        data = payload
    if not isinstance(data, dict):
        return None, None, None, None
    logo = None
    lg = data.get("logo")
    if isinstance(lg, dict):
        logo = safe_http_icon_url(str(lg.get("url") or lg.get("thumbnailUrl") or "").strip())
    name = str(data.get("name") or "").strip() or None
    slug = str(data.get("slug") or "").strip() or None
    cid: Optional[int] = None
    raw_cid = data.get("classId")
    if raw_cid is not None:
        try:
            cid = int(raw_cid)
        except (TypeError, ValueError):
            cid = None
    return logo, name, cid, slug


def _curseforge_junk_public_image_url(url: str) -> bool:
    """Generic Curse/author placeholders that are not pack cover art."""
    low = str(url or "").lower()
    if not low.startswith(("http://", "https://")):
        return True
    return any(
        x in low
        for x in (
            "banners-image-url",
            "authors_70.webp",
            "images/rev/authors",
            "jtvnw.net/jtv_user",
            "twemoji",
            "youtube.com/vi/",
            "img.youtube.com",
        )
    )


def _curseforge_html_embedded_project_id(html: str) -> Optional[int]:
    """CurseForge Next.js pages embed JSON with ``projectId``; the HTML may omit ``og:image``."""
    for pat in (
        r'"projectId"\s*:\s*(\d{5,})',
        r'"id"\s*:\s*(\d{5,})\s*,\s*"gameId"',
        r"Project ID\s*(?:</[^>]+>\s*)?(\d{5,})",
    ):
        m = re.search(pat, html, flags=re.I)
        if m:
            try:
                n = int(m.group(1))
                if 10_000 < n < 2_000_000_000:
                    return n
            except ValueError:
                continue
    return None


def _curseforge_html_logo_urls(html: str) -> List[str]:
    """Dehydrated logo URLs from page JSON / avatar links (fallback when og:image missing)."""
    out: List[str] = []
    seen: set[str] = set()
    for pat in (
        r'"primaryLogoUrl"\s*:\s*"([^"]+)"',
        r'"logoUrl"\s*:\s*"([^"\']+)"',
        r'"thumbnailUrl"\s*:\s*"([^"]+)"',
        r'https://media\.forgecdn\.net/avatars/(?:thumbnails/)?[\d/]+[^\s"\'<>)]+\.(?:png|webp|jpg)',
    ):
        for m in re.finditer(pat, html, flags=re.I):
            raw = m.group(1) if m.lastindex else m.group(0)
            u = safe_http_icon_url(html.unescape(str(raw).strip()))
            if u and u not in seen:
                seen.add(u)
                out.append(u)
    # Prefer full-size avatar paths over .../thumbnails/... when both appear.
    non_tn = [u for u in out if "/thumbnails/" not in u.lower()]
    return non_tn + [u for u in out if u not in non_tn]


def _curseforge_og_image_for_modpack_slug(slug: str) -> Optional[str]:
    """Pack artwork from the public CurseForge modpack page + mirror API by embedded project id."""
    s = str(slug or "").strip()
    if not s or any(c in s for c in "/\\?#"):
        return None
    headers = {"User-Agent": "Mozilla/5.0 ForagerAI/1.0 (pack art; +https://github.com/forager-ai)"}
    page_url = f"https://www.curseforge.com/minecraft/modpacks/{s}"
    response = _requests_get_with_tls_fallback(page_url, timeout=16, headers=headers)
    if response is None or response.status_code >= 400:
        return None
    text = response.text or ""
    patterns = [
        r'<meta\s+property=["\']og:image["\']\s+content=["\']([^"\']+)["\']',
        r'<meta\s+content=["\']([^"\']+)["\']\s+property=["\']og:image["\']',
        r'<meta\s+name=["\']twitter:image["\']\s+content=["\']([^"\']+)["\']',
    ]
    for pattern in patterns:
        match = re.search(pattern, text, flags=re.I)
        if match:
            safe = safe_http_icon_url(html.unescape(match.group(1)))
            if safe and not _curseforge_junk_public_image_url(safe):
                return safe
    pid = _curseforge_html_embedded_project_id(text)
    if pid is not None:
        logo, _, _, _ = _curseforge_mirror_mod_summary(str(pid))
        if logo and not _curseforge_junk_public_image_url(logo):
            return logo
    for cand in _curseforge_html_logo_urls(text):
        if not _curseforge_junk_public_image_url(cand):
            return cand
    return None


def _curseforge_public_pack_image(name: str) -> Optional[str]:
    for slug in _curseforge_slug_candidates(name):
        hit = _curseforge_og_image_for_modpack_slug(slug)
        if hit:
            return hit
    return None


def _ddgs_image_client_cls():
    """Prefer the maintained ``ddgs`` package; fall back to ``duckduckgo_search``."""
    try:
        from ddgs import DDGS  # type: ignore

        return DDGS
    except ImportError:
        try:
            from duckduckgo_search import DDGS  # type: ignore

            return DDGS
        except ImportError:
            return None


def _web_image_search_pack_artwork(queries: List[str]) -> Optional[str]:
    """
    Last-resort pack art similar to an image search: DuckDuckGo image results via ``ddgs``.

    Off by default (results are often unrelated mods). Set ``FORAGER_ENABLE_WEB_PACK_ART=1`` to opt in.
    ``FORAGER_DISABLE_WEB_IMAGE_SEARCH=1`` still forces skip.
    """
    raw = str(os.environ.get("FORAGER_DISABLE_WEB_IMAGE_SEARCH") or "").strip().lower()
    if raw in ("1", "true", "yes", "on"):
        return None
    ena = str(os.environ.get("FORAGER_ENABLE_WEB_PACK_ART") or "").strip().lower()
    if ena not in ("1", "true", "yes", "on"):
        return None
    DDGS = _ddgs_image_client_cls()
    if DDGS is None:
        return None
    junk = (
        "gravatar.com",
        "/avatar",
        "favicon.ico",
        "emoji",
        "twemoji",
        "gstatic.com/chrome",
    )
    seen: set[str] = set()
    ordered = [q.strip() for q in queries if str(q or "").strip()]
    if not ordered:
        return None
    for q in ordered:
        for search_phrase in (f"{q} minecraft modpack", q):
            try:
                with DDGS() as ddgs:
                    rows = list(ddgs.images(search_phrase, max_results=14))
            except Exception:
                rows = []
            for hit in rows:
                if not isinstance(hit, dict):
                    continue
                raw_url = str(hit.get("image") or hit.get("thumbnail") or "").strip()
                url = safe_http_icon_url(raw_url)
                if not url or url in seen:
                    continue
                seen.add(url)
                low = url.lower()
                if any(j in low for j in junk):
                    continue
                w = hit.get("width")
                h = hit.get("height")
                try:
                    iw = int(w) if w is not None else 0
                    ih = int(h) if h is not None else 0
                except (TypeError, ValueError):
                    iw = ih = 0
                if iw and ih and max(iw, ih) < 96:
                    continue
                if iw and ih and iw * ih < 6000:
                    continue
                return url
    return None


def _pick_named_icon(hits: List[ModInfo], query: str, threshold: int = 70) -> Optional[str]:
    best_icon: Optional[str] = None
    best_score = threshold - 1
    for idx, hit in enumerate(hits):
        icon = safe_http_icon_url(hit.icon_url)
        if not icon:
            continue
        score = _pack_name_score(query, hit.name) - idx
        if score > best_score:
            best_score = score
            best_icon = icon
    return best_icon


def _instance_icon_src(instance: MinecraftInstance) -> Optional[str]:
    raw = (getattr(instance, "icon", None) or "").strip()
    if not raw:
        return None
    if raw.startswith("data:image/"):
        return raw
    safe = safe_http_icon_url(raw)
    if safe:
        return safe
    if _is_probably_local_image(raw):
        return _local_image_to_data_uri(raw)
    return None


def _resolve_instance_artwork(instance: MinecraftInstance) -> Optional[str]:
    """Best-effort pack art: CurseForge/Modrinth APIs and slug pages, then on-disk pack files, then fallbacks."""
    data = _source_pack_metadata(instance)
    manifest_file_pid = _manifest_pack_project_id(instance.instance_path)
    base_modpack_pid = _curseforge_base_modpack_project_id(data)
    meta_pid = _metadata_curseforge_project_id(data)
    trusted_pack_pid: Optional[int] = manifest_file_pid or base_modpack_pid

    root_path = Path(instance.instance_path)
    local_candidates = [
        root_path / "pack.png",
        root_path / "icon.png",
        root_path / "profile.png",
        root_path / "thumbnail.png",
        root_path / "minecraftinstance.png",
        root_path.parent / "pack.png",
        root_path.parent / "icon.png",
        root_path.parent / "profile.png",
        root_path.parent / "thumbnail.png",
    ]

    # Pack project id from manifest.json on disk or baseModPack in minecraftinstance.json — not launcher icon URLs
    # (those thumbnails are often stale, generic, or for another mod).
    trusted_tried = False
    if trusted_pack_pid is not None:
        trusted_tried = True
        logo, _, _, slug_cf = _curseforge_mirror_mod_summary(str(trusted_pack_pid))
        if logo:
            return logo
        if slug_cf:
            og = _curseforge_og_image_for_modpack_slug(slug_cf)
            if og:
                return og

    # Slug / display-name CurseForge pages (works when folder name != Curse slug or manifest is missing).
    for query in _pack_display_name_queries(instance, data):
        q = (query or "").strip()
        if not q:
            continue
        icon = _curseforge_public_pack_image(q)
        if icon and not _curseforge_junk_public_image_url(icon):
            return icon

    dl = launcher.mod_downloader
    primary_cf: List[int] = []
    for raw in (
        manifest_file_pid,
        base_modpack_pid,
        trusted_pack_pid,
        meta_pid,
        data.get("projectID"),
        data.get("projectId"),
    ):
        if raw is None:
            continue
        try:
            primary_cf.append(int(raw))
        except (TypeError, ValueError):
            pass
    primary_cf = _uniq_ints_preserve(primary_cf)
    nested_cf = _uniq_ints_preserve(_deep_scan_curseforge_numeric_project_ids(data))
    secondary_cf = [n for n in nested_cf if n not in set(primary_cf)]

    queries_nm0 = _pack_display_name_queries(instance, data)
    for pid in primary_cf:
        if trusted_tried and trusted_pack_pid is not None and pid == trusted_pack_pid:
            continue
        logo, mod_name, _cid, slug_cf = _curseforge_mirror_mod_summary(str(pid))
        name_ok = True
        if mod_name and queries_nm0:
            name_ok = max((_pack_name_score(q, mod_name) for q in queries_nm0), default=0) >= 32
        elif not mod_name:
            name_ok = False
        if logo and name_ok:
            return logo
        if slug_cf and name_ok:
            og = _curseforge_og_image_for_modpack_slug(slug_cf)
            if og:
                return og

    for pid in secondary_cf:
        logo, mod_name, cid, _ = _curseforge_mirror_mod_summary(str(pid))
        if not logo or not mod_name:
            continue
        if cid == 6:
            continue
        queries_nm = _pack_display_name_queries(instance, data)
        if not queries_nm:
            continue
        if max((_pack_name_score(q, mod_name) for q in queries_nm), default=0) < 48:
            continue
        return logo

    for lookup in _modrinth_profile_icon_lookups(data):
        det = dl.get_modrinth_project_detail(lookup)
        icon = safe_http_icon_url((det or {}).get("icon_url"))
        if icon:
            return icon

    if _curseforge_downloader_ready(dl):
        queries_dl = _pack_display_name_queries(instance, data)
        for pid in primary_cf:
            if pid > 0:
                detail = dl.get_curseforge_mod_detail(str(pid))
                icon = safe_http_icon_url((detail or {}).get("icon_url"))
                if not icon:
                    continue
                mname = str((detail or {}).get("title") or "").strip()
                if trusted_pack_pid is not None and pid == trusted_pack_pid:
                    return icon
                if mname and queries_dl and max((_pack_name_score(q, mname) for q in queries_dl), default=0) >= 32:
                    return icon
        for pid in secondary_cf:
            if pid <= 0:
                continue
            detail = dl.get_curseforge_mod_detail(str(pid))
            mname = str((detail or {}).get("title") or "").strip()
            if not mname:
                continue
            queries_cf = _pack_display_name_queries(instance, data)
            if max((_pack_name_score(q, mname) for q in queries_cf), default=0) < 48:
                continue
            icon = safe_http_icon_url((detail or {}).get("icon_url"))
            if icon:
                return icon
        for query in _pack_display_name_queries(instance, data):
            if not query.strip():
                continue
            hits = dl.search_curseforge(
                query.strip(),
                minecraft_version=instance.minecraft_version,
                loader=instance.loader,
                limit=12,
                class_id=4471,
                catalog_kind="modpack",
            )
            if not hits:
                hits = dl.search_curseforge(
                    query.strip(),
                    None,
                    None,
                    limit=15,
                    class_id=4471,
                    catalog_kind="modpack",
                )
            th = 62 if len(hits) > 1 else 38
            icon = _pick_named_icon(hits, query.strip(), threshold=th)
            if icon:
                return icon

    # Fallback: many CurseForge packs are mirrored or similarly named on Modrinth.
    for query in _pack_display_name_queries(instance, data):
        if not query.strip():
            continue
        hits = dl.search_modrinth(
            query.strip(),
            minecraft_version=instance.minecraft_version,
            loader=instance.loader,
            limit=12,
            project_type="modpack",
            catalog_kind="modpack",
        )
        if not hits:
            hits = dl.search_modrinth(
                query.strip(),
                None,
                None,
                limit=15,
                project_type="modpack",
                catalog_kind="modpack",
            )
        th = 35 if len(hits) == 1 else 48
        icon = _pick_named_icon(hits, query.strip(), threshold=th)
        if icon:
            return icon

    # On-disk images after remote resolution: user may ship custom pack.png.
    for candidate in local_candidates:
        if _local_image_to_data_uri(str(candidate)):
            return str(candidate)

    # Launcher explicit profile paths (paths on disk, not random CDN thumbnails).
    for key in ("profileImagePath", "iconPath", "imagePath"):
        val = data.get(key)
        if isinstance(val, str) and _local_image_to_data_uri(val):
            return val

    # Nested icon URLs from launcher JSON (often wrong); only after authoritative sources.
    local_url = _extract_nested_icon_url(data)
    if local_url:
        safe = safe_http_icon_url(local_url)
        if safe:
            return safe
        if _is_probably_local_image(local_url) and _local_image_to_data_uri(local_url):
            return local_url

    web = _web_image_search_pack_artwork(_pack_display_name_queries(instance, data))
    if web:
        return web
    return None


def ensure_instance_artwork(instance: MinecraftInstance, *, allow_remote: bool = False) -> Optional[str]:
    cached = _instance_icon_src(instance)
    if cached:
        if (
            allow_remote
            and cached.startswith(("http://", "https://"))
            and (getattr(instance, "icon", None) or "").strip().startswith(("http://", "https://"))
        ):
            local_path = _persist_pack_artwork_to_cache(cached, instance.name)
            if local_path:
                launcher.instance_manager.update_instance(instance.name, icon=local_path)
                instance.icon = local_path
                cached = _instance_icon_src(instance)
        return cached
    if not allow_remote:
        return None
    candidate = _resolve_instance_artwork(instance)
    if candidate:
        stored: Optional[str] = candidate
        if candidate.startswith(("http://", "https://")):
            local_path = _persist_pack_artwork_to_cache(candidate, instance.name)
            if local_path:
                stored = local_path
        launcher.instance_manager.update_instance(instance.name, icon=stored)
        instance.icon = stored
        return _instance_icon_src(instance)
    return None


def _data_uri_to_cache_png_file(data_uri: str, cache_key: str) -> Optional[str]:
    """Write a data: URI to a PNG file so st.image() can load it (HTML <img data:> is unreliable in WebView)."""
    if not data_uri.startswith("data:image"):
        return None
    m = re.match(r"data:image/[^;]+;base64,(.+)", data_uri, re.DOTALL)
    if not m:
        return None
    b64 = re.sub(r"\s+", "", m.group(1))
    try:
        raw = base64.b64decode(b64, validate=False)
    except Exception:
        return None
    if not raw:
        return None
    safe = re.sub(r"[^a-zA-Z0-9_-]+", "_", cache_key)[:64] or "uri"
    digest = hashlib.sha256(data_uri[:4096].encode("utf-8", errors="ignore")).hexdigest()[:18]
    path = os.path.join(_preview_cache_dir(), f"tileimg_{digest}_{safe}.png")
    if os.path.isfile(path):
        return path
    try:
        with open(path, "wb") as fh:
            fh.write(raw)
        return path
    except OSError:
        return None


def _tile_pack_image_path(instance: MinecraftInstance) -> str:
    """
    Filesystem path for st.image(). Prefer local paths / downloaded cache; decode data: URIs to disk.

    The embedded pywebview shell often fails to render data: URIs inside markdown HTML for pack tiles.
    """
    # Keep rerenders local/fast; explicit refresh actions can force remote artwork resolution.
    ensure_instance_artwork(instance, allow_remote=False)
    raw_stored = (getattr(instance, "icon", None) or "").strip()
    if raw_stored and os.path.isfile(raw_stored):
        return os.path.abspath(raw_stored)
    disp = _instance_icon_src(instance)
    if not disp:
        return _make_placeholder_image(instance.name, kind="modpack")
    if disp.startswith("data:"):
        cached = _data_uri_to_cache_png_file(disp, instance.name)
        return cached or _make_placeholder_image(instance.name, kind="modpack")
    if disp.startswith(("http://", "https://")):
        lp = _persist_pack_artwork_to_cache(disp, instance.name)
        if lp and os.path.isfile(lp):
            launcher.instance_manager.update_instance(instance.name, icon=lp)
            instance.icon = lp
            return lp
        return _make_placeholder_image(instance.name, kind="modpack")
    try:
        expanded = Path(disp).expanduser()
        if expanded.is_file():
            return str(expanded.resolve())
    except OSError:
        pass
    return _make_placeholder_image(instance.name, kind="modpack")


def _my_packs_sync_external_profiles(launcher: Any) -> Tuple[int, int]:
    """Scan configured launcher folders and link new external profiles into My Packs."""
    r = launcher.instance_manager.sync_discovered_externals(launcher.config)
    _invalidate_external_instances_cache()
    _invalidate_forager_instance_list_cache()
    return int(r.get("imported", 0) or 0), int(r.get("skipped", 0) or 0)


def _my_packs_refresh_pack_artwork(launcher: Any, instances: Sequence[Any]) -> int:
    """Clear cached icons and re-fetch artwork for every tracked pack."""
    for _k in list(st.session_state.keys()):
        if isinstance(_k, str) and _k.startswith("icon_lookup::"):
            del st.session_state[_k]
    updated_icons = 0
    for artwork_instance in instances:
        launcher.instance_manager.update_instance(artwork_instance.name, icon=None)
        artwork_instance.icon = None
        if ensure_instance_artwork(artwork_instance, allow_remote=True):
            updated_icons += 1
    return updated_icons


def _my_packs_library_chrome_html(
    *,
    instances_n: int,
    linked_n: int,
    running_n: int,
    active: Literal["library", "create"] = "library",
) -> str:
    """Unified Modpack Library header: title/stats + quick-nav in one chrome surface."""
    return (
        '<div class="forager-library-chrome">'
        '<div class="forager-library-toolbar forager-library-toolbar--compact forager-library-toolbar--in-chrome">'
        '<div><div class="forager-library-title">Modpack Library</div>'
        '<div class="forager-library-copy">Native instances + linked CurseForge/Modrinth profiles.</div></div>'
        '<div class="forager-instance-stats">'
        f'<span class="forager-instance-chip ok">{instances_n} packs</span>'
        f'<span class="forager-instance-chip">{linked_n} linked</span>'
        f'<span class="forager-instance-chip">{running_n} running</span>'
        "</div></div>"
        '<div class="forager-library-chrome-divider" aria-hidden="true"></div>'
        f'<div class="forager-instance-pack-head forager-instance-pack-head--in-chrome">'
        f"{_my_packs_instance_pack_head_html(active)}"
        "</div>"
        "</div>"
    )


def _my_packs_instance_pack_head_html(active: Literal["library", "create"]) -> str:
    """Pack row: **My modpacks** (same pill style as Create pack → Home) + **Create pack** CTA, then quick links on the right."""
    create_aria = ' aria-current="page"' if active == "create" else ""
    create_cls = "forager-pack-create-cta"
    if active == "create":
        create_cls += " forager-pack-create-cta--active"
    title_el = (
        '<a class="forager-pack-create-cta" target="_self" href="?forager_nav=instances" '
        'title="Open My Packs (auto-detected CurseForge/Modrinth installs)">My modpacks</a>'
    )
    create_el = (
        f'<a class="{create_cls}" target="_self" href="?forager_nav=pack_create"{create_aria}>'
        "Create pack</a>"
    )
    nav_inner: List[str] = []
    if active == "create":
        nav_inner.append('<a target="_self" href="?forager_nav=instances">My modpacks</a>')
    nav_inner.extend(
        [
            '<a target="_self" href="?forager_nav=mods">Browse mods</a>',
            '<a target="_self" href="?forager_nav=home">Home</a>',
        ]
    )
    nav_el = '<nav class="forager-cf-subnav" aria-label="Quick links">' + "".join(nav_inner) + "</nav>"
    return (
        '<div class="forager-instance-pack-head-primary">'
        f"{title_el}{create_el}"
        "</div>"
        f"{nav_el}"
    )


