def _render_create_pack_form(launcher: Any) -> None:
    """Forager-native instance scaffold (widget keys must stay stable for session state)."""
    try:
        _create_border = st.container(border=True)
    except TypeError:
        _create_border = st.container()
    with _create_border:
        st.markdown(
            '<div class="forager-create-pack-head">'
            '<div class="forager-create-pack-kicker">New instance</div>'
            '<div class="forager-create-pack-title">Create pack</div>'
            "<p class=\"forager-create-pack-lead\">Adds a <strong>Forager-native</strong> folder under "
            "<code>packs/&lt;name&gt;</code>. Heap targets map to <strong>-Xms</strong> / <strong>-Xmx</strong> on launch.</p>"
            "</div>",
            unsafe_allow_html=True,
        )

        with st.form("create_instance"):
            st.markdown('<div class="forager-create-pack-section">Identity</div>', unsafe_allow_html=True)
            name = st.text_input(
                "Pack / instance name",
                placeholder="e.g. ATM10 remix",
                key="create_inst_name",
                help="Shown in My Packs and used as the on-disk folder name under packs/.",
            )
            description = st.text_area(
                "Description",
                placeholder="Optional — what you are building, target audience, or mod focus.",
                height=88,
                key="create_inst_desc",
            )

            st.markdown('<div class="forager-create-pack-section">Game target</div>', unsafe_allow_html=True)
            mc_versions = launcher.version_manager.get_minecraft_versions()
            mc_version_names = [v.id for v in mc_versions[:30]]
            _mc_idx = 0
            if mc_version_names and "1.20.1" in mc_version_names:
                _mc_idx = int(mc_version_names.index("1.20.1"))
            _ldr_opts = ["forge", "fabric", "quilt", "vanilla"]
            _ldr_idx = int(_ldr_opts.index("forge"))
            _cg1, _cg2 = st.columns(2, gap="small")
            with _cg1:
                if mc_version_names:
                    selected_mc = st.selectbox(
                        "Minecraft",
                        mc_version_names,
                        index=_mc_idx,
                        key="create_inst_mc_ver",
                        help="Pulled from the version index (first 30). Refresh from Settings if this looks wrong.",
                    )
                else:
                    selected_mc = (
                        st.text_input(
                            "Minecraft (manual)",
                            value="1.20.1",
                            key="create_inst_mc_manual",
                            help="e.g. 1.21.1 — use when the dropdown could not load.",
                        ).strip()
                        or "1.20.1"
                    )
            with _cg2:
                loader = st.selectbox(
                    "Loader",
                    _ldr_opts,
                    index=_ldr_idx,
                    format_func=lambda x: str(x).title(),
                    key="create_inst_loader",
                    help="Forge is the default product path; Fabric/Quilt/Vanilla are available when you need them.",
                )
            st.markdown(
                '<div class="forager-create-pack-foot-hint">'
                'Stale list? <a target="_self" href="?forager_nav=settings">Settings → refresh Minecraft versions</a>.'
                "</div>",
                unsafe_allow_html=True,
            )

            st.markdown('<div class="forager-create-pack-section">JVM heap (MB)</div>', unsafe_allow_html=True)
            _mh1, _mh2 = st.columns(2, gap="small")
            with _mh1:
                memory_max = int(
                    st.number_input(
                        "Max (−Xmx)",
                        min_value=1024,
                        max_value=24576,
                        value=int(launcher.config.get("default_memory", 4096) or 4096),
                        step=256,
                        key="create_inst_mem_max",
                        help="Upper heap cap the JVM may grow to (megabytes).",
                    )
                )
            with _mh2:
                memory_min = int(
                    st.number_input(
                        "Min (−Xms)",
                        min_value=512,
                        max_value=24576,
                        value=min(2048, int(launcher.config.get("default_memory", 4096) or 4096)),
                        step=256,
                        key="create_inst_mem_min",
                        help="Initial committed heap (megabytes). Typically half of max for modded packs.",
                    )
                )
            st.caption("If min exceeds max on submit, values are swapped automatically.")

            st.markdown('<div class="forager-create-pack-section">Organize</div>', unsafe_allow_html=True)
            tags_input = st.text_input(
                "Tags",
                placeholder="tech, magic, kitchen-sink",
                key="create_inst_tags",
                help="Comma-separated labels for filtering and quick scanning in My Packs.",
            )
            tags = [tag.strip() for tag in tags_input.split(",") if tag.strip()] if tags_input else []

            submitted = st.form_submit_button(
                "Create instance",
                type="primary",
                use_container_width=True,
                help="Scaffold the pack folder and register it in your library.",
            )

            if submitted:
                if name:
                    _mx = max(512, int(memory_max))
                    _mn = max(256, int(memory_min))
                    if _mn > _mx:
                        _mn, _mx = _mx, _mn
                    try:
                        launcher.create_instance(
                            name=name,
                            minecraft_version=selected_mc,
                            loader=loader,
                            description=description,
                            tags=tags,
                        )
                        launcher.instance_manager.update_instance(
                            name,
                            memory_min=_mn,
                            memory_max=_mx,
                        )
                        st.success(f"Created instance **{name}** with **{_mn}–{_mx} MB** heap.")
                        st.session_state["forager_nav"] = "instances"
                        st.rerun()
                    except Exception as e:
                        st.error(f"Failed to create instance: {e}")
                else:
                    st.error("Please enter a pack / instance name.")


def _loader_badge_text(loader: str) -> str:
    lf = str(loader or "").strip().lower()
    return {
        "forge": "Forge",
        "neoforge": "Neo",
        "fabric": "Fabric",
        "quilt": "Quilt",
        "vanilla": "Vanilla",
    }.get(lf, (str(loader or "?").title() or "?")[:10])


def _strip_cf_html_to_text(raw: str) -> str:
    """Turn CurseForge's long description HTML into plain text for in-app display."""
    if not raw:
        return ""
    t = html.unescape(re.sub(r"(?is)<br\s*/?>", "\n", raw))
    t = re.sub(r"(?is)<[^>]+>", "", t)
    return re.sub(r"\n{3,}", "\n\n", t).strip()


def _st_brief_ok(message: str) -> None:
    """Always show inline success; toast is optional (easy to miss in some themes)."""
    toast = getattr(st, "toast", None)
    if callable(toast):
        try:
            toast(message)
        except Exception:
            pass
    st.success(message)


def _st_brief_warn(message: str) -> None:
    toast = getattr(st, "toast", None)
    if callable(toast):
        try:
            toast(message)
        except Exception:
            pass
    st.warning(message)


def _mods_dispatch_clipboard_copy(text: str) -> None:
    """Best-effort copy into the host browser clipboard from an embedded components iframe."""
    t = str(text or "").strip()
    if not t:
        return
    payload = json.dumps(t)
    components.html(
        "<script>(function(){var t="
        + payload
        + ";var w=(window.parent&&window.parent.navigator)?window.parent:window;"
        "try{if(w.navigator.clipboard&&w.navigator.clipboard.writeText)"
        "w.navigator.clipboard.writeText(t);}catch(e){}})();</script>",
        height=0,
        width=0,
    )


def _mods_format_install_target_one_liner(
    *,
    install_target: str,
    sel_inst: Any,
    sel_external: Any,
    pack_for_mods: Optional[str],
    mc_hint: str,
    loader_hint: str,
    catalog_kind: str,
) -> str:
    """Compact HTML line for the Browse Modpacks catalog strip (install context)."""
    ck = html.escape(str(catalog_kind or "mods"))
    parts: List[str] = []
    if str(install_target or "").startswith("Pack"):
        if pack_for_mods:
            parts.append(
                '<span class="forager-mod-install-strip-target">Pack</span> '
                f'<span class="forager-mod-install-strip-code">{html.escape(str(pack_for_mods))}</span>'
            )
        else:
            parts.append('<span class="forager-mod-install-strip-warn">No pack folder (Browse uses instances only)</span>')
    elif sel_inst is not None:
        nm = html.escape(str(getattr(sel_inst, "name", "") or "instance"))
        parts.append(
            f'<span class="forager-mod-install-strip-target">Instance</span> <strong>{nm}</strong>'
        )
    elif sel_external is not None:
        nm = html.escape(str(getattr(sel_external, "display_name", "") or "external"))
        parts.append(
            f'<span class="forager-mod-install-strip-target">External</span> <strong>{nm}</strong>'
        )
    else:
        parts.append(
            '<span class="forager-mod-install-strip-warn">No launcher instance — add one under My Packs</span>'
        )
    mc = str(mc_hint or "").strip()
    ld = str(loader_hint or "").strip().lower()
    bits: List[str] = []
    if mc:
        bits.append(f'MC <span class="forager-mod-install-strip-code">{html.escape(mc)}</span>')
    if ld and ld != "vanilla":
        bits.append(f'loader <span class="forager-mod-install-strip-code">{html.escape(ld)}</span>')
    if bits:
        parts.append(" · " + " · ".join(bits))
    parts.append(f' · <span class="forager-mod-install-strip-ck">{ck}</span>')
    return "".join(parts)


def _mods_build_instance_options(launcher: LauncherCore) -> Tuple[List[str], List[Tuple[str, Any]]]:
    """Labels + (kind, obj) for Mods tab install target. kind = none | forager | external."""
    labels: List[str] = []
    meta: List[Tuple[str, Any]] = []
    labels.append("— Select instance —")
    meta.append(("none", None))
    instances = _forager_instance_list(launcher)
    for inst in sorted(instances, key=lambda x: x.name.lower()):
        labels.append(f"Forager · {inst.name}")
        meta.append(("forager", inst))
    claimed = {
        launcher.instance_manager._norm_game_path(i.instance_path)
        for i in instances
    }
    for ext in _external_instances_list(launcher):
        if launcher.instance_manager._norm_game_path(ext.game_root) in claimed:
            continue
        src_label = "CurseForge" if ext.source == "curseforge" else "Modrinth"
        labels.append(f"{src_label} · {ext.display_name}")
        meta.append(("external", ext))
    return labels, meta


def _mods_auto_resolve_browse_install_target(
    launcher: LauncherCore,
) -> Tuple[str, Optional[MinecraftInstance], Optional[ExternalInstanceInfo], Optional[str]]:
    """Browse Modpacks: modpack installs always target a launcher profile folder (no manual picker).

    Prefer the first **Forager** instance (sorted name order), else the first **linked** external profile.
    """
    labels, meta = _mods_build_instance_options(launcher)
    install_target = "Minecraft instance"
    pack_for_mods: Optional[str] = None
    sel_inst: Optional[MinecraftInstance] = None
    sel_external: Optional[ExternalInstanceInfo] = None
    pick_label = labels[0] if labels else "— Select instance —"
    for idx in range(1, len(labels)):
        kind, obj = meta[idx]
        if kind == "forager" and obj is not None:
            pick_label = labels[idx]
            sel_inst = obj
            break
    if sel_inst is None:
        for idx in range(1, len(labels)):
            kind, obj = meta[idx]
            if kind == "external" and obj is not None:
                pick_label = labels[idx]
                sel_external = obj
                break
    st.session_state["mods_install_target"] = install_target
    st.session_state["mods_target_instance"] = pick_label
    return install_target, sel_inst, sel_external, pack_for_mods


def _forager_apply_deferred_mods_catalog_search(launcher: LauncherCore, *, show_wait_skin: bool) -> None:
    """Single site for deferred Modrinth/CurseForge catalog fetch (queued via ``_mods_deferred_catalog_kw``)."""
    kw = st.session_state.pop("_mods_deferred_catalog_kw", None)
    if not isinstance(kw, dict):
        return
    if bool(launcher.config.get("catalog_offline_mode")):
        return
    if show_wait_skin:
        st.markdown(
            '<div class="forager-mod-alert forager-mod-alert-safe"><strong>Catalog search</strong> — loading remote rows…</div>',
            unsafe_allow_html=True,
        )
        st.markdown(
            '<div style="max-width:560px;margin:0.35rem 0 0.75rem 0;">'
            '<div class="forager-skel-bar" style="width:96%"></div>'
            '<div class="forager-skel-bar" style="width:78%"></div>'
            '<div class="forager-skel-bar" style="width:88%"></div>'
            "</div>",
            unsafe_allow_html=True,
        )
    try:
        with st.spinner("Searching Modrinth / CurseForge…"):
            st.session_state["mod_search_results"] = launcher.search_mods(**kw)
        st.session_state["_mods_last_search_kw"] = kw
        _forager_activity_push("Browse Modpacks: catalog search completed (deferred pass)")
    except Exception as exc:
        st.warning(f"Catalog search failed: `{exc}`")


_MODS_SOURCE_SLUG_BY_LABEL: Dict[str, str] = {"Modrinth": "modrinth", "CurseForge": "curseforge"}


def _mods_api_sources_for_search(launcher: LauncherCore) -> List[str]:
    """Catalog API source labels: Modrinth always; CurseForge when downloader key is ready."""
    labels = ["Modrinth"]
    if _curseforge_downloader_ready(launcher.mod_downloader):
        labels.append("CurseForge")
    return labels


def _mods_api_source_slugs_for_search(launcher: LauncherCore) -> List[str]:
    return [_MODS_SOURCE_SLUG_BY_LABEL[s] for s in _mods_api_sources_for_search(launcher)]


def _mods_queue_catalog_search_from_session(launcher: LauncherCore, *, catalog_kind: str = "modpack") -> bool:
    """Queue the same catalog ``kw`` as Browse Modpacks **Search / refresh listing** (``browse_popular=True``). Returns False if not queued."""
    if bool(launcher.config.get("catalog_offline_mode")):
        return False
    st.session_state.setdefault("mods_query", "")
    st.session_state.setdefault("mods_mc_ver", "1.20.1")
    st.session_state.setdefault("mods_loader", "forge")
    st.session_state.setdefault("mods_mr_sort", "downloads")
    st.session_state.setdefault("mods_cf_sort", "Total downloads")
    st.session_state.setdefault("mods_limit", 200)
    st.session_state.setdefault("mods_page", 1)
    st.session_state.setdefault("mods_catalog_kind", catalog_kind)
    src_list = _mods_api_source_slugs_for_search(launcher)
    if not src_list:
        return False
    browse_popular = True
    query = str(st.session_state.get("mods_query") or "")
    if not browse_popular and not query.strip():
        return False
    gv_raw = str(st.session_state.get("mods_mc_ver") or "").strip()
    gv_search = gv_raw or None
    loader_filter = str(st.session_state.get("mods_loader") or "forge")
    lparam_search = None if loader_filter == "vanilla" else loader_filter
    try:
        search_limit = max(12, int(st.session_state.get("mods_limit", 200)))
    except (TypeError, ValueError):
        search_limit = 200
    try:
        result_page = max(1, int(st.session_state.get("mods_page", 1)))
    except (TypeError, ValueError):
        result_page = 1
    cf_sort_map = {"Total downloads": 6, "Last updated": 3, "Popularity": 2}
    cf_label = str(st.session_state.get("mods_cf_sort") or "Total downloads")
    cf_sort_field = int(cf_sort_map.get(cf_label, 6))
    modrinth_sort = str(st.session_state.get("mods_mr_sort") or "downloads")
    ck = str(st.session_state.get("mods_catalog_kind") or catalog_kind or "modpack")
    qtext = query.strip() if not browse_popular else query.strip()
    kw_rs: Dict[str, Any] = {
        "query": qtext,
        "minecraft_version": gv_search,
        "loader": lparam_search,
        "limit": search_limit,
        "sources": src_list,
        "curseforge_sort_field": cf_sort_field,
        "page": int(result_page),
        "modrinth_index": modrinth_sort,
        "catalog_kind": ck,
    }
    st.session_state["_mods_deferred_catalog_kw"] = dict(kw_rs)
    st.rerun()


