def _render_home_dashboard_pins(launcher: LauncherCore) -> None:
    raw = launcher.config.get("home_pinned_widgets")
    if not isinstance(raw, list):
        return
    known = set(FORAGER_HOME_PIN_LABELS.keys())
    order: List[str] = []
    seen: set[str] = set()
    for pid in raw:
        if not isinstance(pid, str) or not pid.strip():
            continue
        pid = pid.strip()
        if pid not in known or pid in seen:
            continue
        seen.add(pid)
        order.append(pid)
    if not order:
        return
    st.markdown('<div class="forager-kicker">Pinned on Home</div>', unsafe_allow_html=True)
    for pin in order:
        label = FORAGER_HOME_PIN_LABELS.get(pin, pin)
        with st.expander(label, expanded=False):
            if pin == "browse_modpacks_catalog":
                if bool(launcher.config.get("catalog_offline_mode")):
                    st.info(
                        "**Catalog offline mode** is enabled under **Settings → Mod library** — Modrinth/CurseForge API listing "
                        "and search are skipped until you turn it off."
                    )
                    continue
                _mods_session_defaults_for_home_catalog_strip()
                _, sel_inst, sel_external, _pfm = _mods_auto_resolve_browse_install_target(launcher)
                if sel_inst:
                    st.caption(
                        f"**Install target (automatic):** Forager **`{html.escape(sel_inst.name)}`** · MC {html.escape(str(sel_inst.minecraft_version))} · "
                        f"{html.escape(str(sel_inst.loader))} · `{html.escape(str(sel_inst.instance_path))}`"
                    )
                elif sel_external:
                    st.caption(
                        f"**Install target (automatic):** {html.escape(str(sel_external.source))} **`{html.escape(sel_external.display_name)}`** · "
                        f"MC {html.escape(str(sel_external.minecraft_version))} · `{html.escape(str(sel_external.game_root))}`"
                    )
                    if (
                        str(sel_external.minecraft_version).lower() == "unknown"
                        or str(sel_external.loader).lower() == "unknown"
                    ):
                        st.caption(
                            "Version/loader metadata missing on disk — set **Minecraft version** and **Loader** below "
                            "so pack file resolution matches this profile."
                        )
                else:
                    st.warning(
                        "No Forager instances or linked profiles yet — create one under **My Packs** to enable installs from this catalog."
                    )
                hq1, hq2 = st.columns([2.8, 1.1])
                with hq1:
                    st.text_input(
                        "Search",
                        placeholder="Search modpacks, or leave blank for popular pack listings",
                        key="mods_query",
                    )
                with hq2:
                    st.text_input("MC", placeholder="1.20.1", key="mods_mc_ver")
                hlc1, hlc2, hlc3, hlc4 = st.columns(4)
                with hlc1:
                    st.selectbox(
                        "Loader",
                        ["forge", "fabric", "quilt", "neoforge", "vanilla"],
                        key="mods_loader",
                    )
                with hlc2:
                    st.selectbox(
                        "Modrinth sort",
                        ["relevance", "downloads", "newest", "updated", "follows"],
                        key="mods_mr_sort",
                    )
                with hlc3:
                    st.selectbox(
                        "CurseForge sort",
                        ["Total downloads", "Last updated", "Popularity"],
                        key="mods_cf_sort",
                    )
                with hlc4:
                    st.number_input("API page", min_value=1, max_value=9999, key="mods_page")
                _lim_home = [24, 48, 72, 96, 120, 200, 300, 400, 600, 800, 1200, 1600, 2000]
                _mlhr = st.session_state.get("mods_limit", 200)
                try:
                    _mlhi = int(_mlhr)
                except (TypeError, ValueError):
                    _mlhi = 200
                if _mlhi not in _lim_home:
                    st.session_state["mods_limit"] = min(_lim_home, key=lambda x: abs(x - _mlhi))
                st.selectbox(
                    "Rows / refresh",
                    _lim_home,
                    key="mods_limit",
                    format_func=lambda n: f"{n} merged rows",
                )
                if st.button("Search / refresh listing", type="primary", key="home_pin_mods_search"):
                    if not _mods_queue_catalog_search_from_session(launcher):
                        if bool(launcher.config.get("catalog_offline_mode")):
                            st.warning("Turn off **Catalog offline mode** in Settings to run catalog searches.")
                        else:
                            st.warning("Catalog search could not be queued.")
                prev_rows = list(st.session_state.get("mod_search_results") or [])[:12]
                if prev_rows:
                    st.caption("Latest loaded catalog (first 12 rows)")
                    for m in prev_rows:
                        st.write(f"**{m.name}** · {m.source}")
                if st.button("Open full Browse Modpacks", use_container_width=True, key="home_pin_open_mods"):
                    st.session_state["forager_nav"] = "mods"
                    st.rerun()
                continue
            nav_key = FORAGER_HOME_PIN_NAV.get(pin)
            if pin == "my_packs_library":
                st.caption("Grid of Forager instances and linked CurseForge/Modrinth profiles — sync, launch, and open folders.")
                if st.button("Open My Packs", type="primary", use_container_width=True, key=f"home_pin_go_{pin}"):
                    st.session_state["forager_nav"] = nav_key or "instances"
                    st.rerun()
            elif pin == "pack_health":
                st.caption("Conflict scan, manifest health, and pack diagnostics — open Pack Health from the launcher loop.")
                if st.button("Open Pack Health", type="primary", use_container_width=True, key=f"home_pin_go_{pin}"):
                    st.session_state["forager_nav"] = nav_key or "conflicts"
                    st.rerun()
            elif pin == "power_center":
                st.caption("JVM tuning, install preflight, and power-user controls for your launcher workspace.")
                if st.button("Open Power Center", type="primary", use_container_width=True, key=f"home_pin_go_{pin}"):
                    st.session_state["forager_nav"] = nav_key or "power_center"
                    st.rerun()
            elif pin == "forager_hub":
                st.caption("AI chat tied to your packs and library — ask questions with your real context loaded.")
                if st.button("Open Forager", type="primary", use_container_width=True, key=f"home_pin_go_{pin}"):
                    st.session_state["forager_nav"] = nav_key or "forager_hub"
                    st.rerun()
            elif pin == "ai_architect":
                st.caption("Plans, compat factory, configs, and the full Architect workspace for serious pack work.")
                if st.button("Open AI · Architect", type="primary", use_container_width=True, key=f"home_pin_go_{pin}"):
                    st.session_state["forager_nav"] = nav_key or "ai_architect"
                    st.rerun()


def _mods_game_root_for_compare_label(launcher: LauncherCore, label: str) -> Optional[str]:
    """Resolve game root path from the same labels used in Browse Modpacks install target."""
    labels, meta = _mods_build_instance_options(launcher)
    if not label or label not in labels:
        return None
    idx = labels.index(label)
    kind, obj = meta[idx]
    if kind == "none" or obj is None:
        return None
    if kind == "forager":
        return str(getattr(obj, "instance_path", "") or "").strip() or None
    if kind == "external":
        return str(getattr(obj, "game_root", "") or "").strip() or None
    return None


def _mods_catalog_target_key(
    install_target: str,
    *,
    sel_inst: Optional[MinecraftInstance],
    sel_external: Optional[ExternalInstanceInfo],
    pack_for_mods: Optional[str],
) -> str:
    if install_target.startswith("Minecraft"):
        if sel_inst:
            return f"inst:{sel_inst.name}"
        if sel_external:
            return f"ext:{sel_external.source}:{sel_external.stable_id}"
    if install_target.startswith("Pack") and pack_for_mods:
        return f"pack:{pack_for_mods}"
    return "none"


