def _mods_theme_overrides_from_config(launcher: LauncherCore) -> Dict[str, Dict[str, Any]]:
    raw = launcher.config.get("mods_theme_overrides")
    out: Dict[str, Dict[str, Any]] = {}
    if not isinstance(raw, dict):
        return out
    for target_key, row in raw.items():
        if not isinstance(target_key, str) or not isinstance(row, dict):
            continue
        enabled = row.get("enabled")
        auto = row.get("auto_detect", True)
        out[target_key] = {
            "enabled": [str(x) for x in (enabled if isinstance(enabled, list) else []) if str(x) in _MODS_THEME_RULES],
            "auto_detect": bool(auto),
        }
    return out


def _mods_theme_detect_for_target(
    *,
    sel_inst: Optional[MinecraftInstance],
    sel_external: Optional[ExternalInstanceInfo],
    pack_for_mods: Optional[str],
    local_jar_profiles: Sequence[Dict[str, Any]],
) -> List[str]:
    chunks: List[str] = []
    chunks.append(str(getattr(sel_inst, "name", "") or ""))
    chunks.append(str(getattr(sel_inst, "description", "") or ""))
    chunks.extend([str(t) for t in (getattr(sel_inst, "tags", None) or [])])
    chunks.append(str(getattr(sel_external, "display_name", "") or ""))
    chunks.append(str(getattr(sel_external, "minecraft_version", "") or ""))
    chunks.append(str(getattr(sel_external, "loader", "") or ""))
    if pack_for_mods:
        chunks.append(str(pack_for_mods))
        pack_root = os.path.join(PACKS_DIR, pack_for_mods)
        try:
            init_pack_manifest(pack_root)
            man = load_pack_manifest(pack_root)
            if isinstance(man, dict):
                for key in ("description", "summary", "theme", "style"):
                    chunks.append(str(man.get(key) or ""))
                tags = man.get("tags") if isinstance(man.get("tags"), list) else []
                chunks.extend(str(t) for t in tags)
        except (FileNotFoundError, OSError, KeyError, TypeError, ValueError):
            pass
    for p in list(local_jar_profiles)[:220]:
        chunks.append(str(p.get("mod_id") or ""))
        chunks.append(str(p.get("display_name") or ""))
        chunks.append(str(p.get("stem_soft") or ""))
    blob = " ".join(chunks).lower()
    out: List[str] = []
    for theme_name, rule in _MODS_THEME_RULES.items():
        hits = sum(1 for token in (rule.get("detect") or []) if token in blob)
        if hits >= 1:
            out.append(theme_name)
    return out


def _mods_row_blob_for_theme(mod: ModInfo) -> str:
    return " ".join(
        [
            str(mod.name or ""),
            str(mod.description or ""),
            str(mod.author or ""),
            str(mod.project_id or ""),
            " ".join(str(c or "") for c in (mod.categories or [])),
            " ".join(str(x or "") for x in (mod.loaders or [])),
        ]
    ).lower()


def _mods_filter_preset_snapshot() -> Dict[str, Any]:
    snap: Dict[str, Any] = {}
    for key in _MODS_FILTER_PRESET_KEYS:
        if key in st.session_state:
            val = st.session_state.get(key)
            if isinstance(val, (list, dict)):
                snap[key] = json.loads(json.dumps(val, ensure_ascii=True))
            else:
                snap[key] = val
    return snap


def _mods_apply_filter_preset_state(state: Dict[str, Any]) -> None:
    for key in _MODS_FILTER_PRESET_KEYS:
        if key not in state:
            continue
        val = state.get(key)
        if isinstance(val, (list, dict)):
            st.session_state[key] = json.loads(json.dumps(val, ensure_ascii=True))
        else:
            st.session_state[key] = val
    st.session_state["_mods_catalog_refetch_paging"] = True


def _mods_filter_presets_from_config(launcher: LauncherCore) -> Dict[str, Dict[str, Dict[str, Any]]]:
    raw = launcher.config.get("mods_filter_presets")
    out: Dict[str, Dict[str, Dict[str, Any]]] = {}
    if not isinstance(raw, dict):
        return out
    for tkey, presets in raw.items():
        if not isinstance(tkey, str) or not isinstance(presets, dict):
            continue
        clean_bucket: Dict[str, Dict[str, Any]] = {}
        for name, state in presets.items():
            if not isinstance(name, str) or not isinstance(state, dict):
                continue
            clean_bucket[name] = {k: v for k, v in state.items() if k in _MODS_FILTER_PRESET_KEYS}
        if clean_bucket:
            out[tkey] = clean_bucket
    return out


def _mods_filter_auto_map_from_config(launcher: LauncherCore) -> Dict[str, str]:
    raw = launcher.config.get("mods_filter_preset_auto")
    out: Dict[str, str] = {}
    if not isinstance(raw, dict):
        return out
    for tkey, name in raw.items():
        if isinstance(tkey, str) and isinstance(name, str) and name.strip():
            out[tkey] = name.strip()
    return out


def _mods_catalog_pin_version_id(
    launcher: LauncherCore, target_key: str, source: str, project_id: str
) -> Optional[str]:
    for p in launcher.config.get("catalog_pins") or []:
        if not isinstance(p, dict):
            continue
        if str(p.get("target_key")) != target_key:
            continue
        if str(p.get("source", "")).lower() != str(source).lower():
            continue
        if str(p.get("project_id", "")).strip() != str(project_id).strip():
            continue
        vid = str(p.get("version_id") or "").strip()
        return vid or None
    return None


