def _mods_git_merge_tree_preview_snippet(ref_a: str, ref_b: str, *, max_bytes: int = 120_000) -> str:
    """Read-only `git merge-tree` preview (needs git 2.34+ merge-tree CLI)."""
    repo = os.path.dirname(PACKS_DIR)
    if not os.path.isdir(os.path.join(repo, ".git")):
        return "(No `.git` at repository root.)"
    ra = (ref_a or "").strip()
    rb = (ref_b or "").strip()
    if not ra or not rb:
        return "Enter **Ref A** and **Ref B** (branch names, tags, or commit SHAs)."
    try:
        va = subprocess.run(
            ["git", "rev-parse", "--verify", ra],
            cwd=repo,
            capture_output=True,
            text=True,
            timeout=12,
            encoding="utf-8",
            errors="replace",
        )
        if va.returncode != 0:
            return f"Could not resolve ref A `{ra}`: {(va.stderr or va.stdout or '').strip()}"

        vb = subprocess.run(
            ["git", "rev-parse", "--verify", rb],
            cwd=repo,
            capture_output=True,
            text=True,
            timeout=12,
            encoding="utf-8",
            errors="replace",
        )
        if vb.returncode != 0:
            return f"Could not resolve ref B `{rb}`: {(vb.stderr or vb.stdout or '').strip()}"

        mb = subprocess.run(
            ["git", "merge-base", ra, rb],
            cwd=repo,
            capture_output=True,
            text=True,
            timeout=20,
            encoding="utf-8",
            errors="replace",
        )
        if mb.returncode != 0:
            return f"merge-base failed: {(mb.stderr or mb.stdout or '').strip()}"
        base = ((mb.stdout or "").strip().splitlines() or [""])[0]
        if not base:
            return "merge-base returned empty output."

        mt = subprocess.run(
            ["git", "merge-tree", base, ra, rb],
            cwd=repo,
            capture_output=True,
            text=True,
            timeout=90,
            encoding="utf-8",
            errors="replace",
        )
        raw = ((mt.stdout or "").strip() + (f"\n{(mt.stderr or '').strip()}" if mt.stderr else "")).strip()
        b = raw.encode("utf-8", errors="replace")
        if len(b) > max_bytes:
            return b[:max_bytes].decode("utf-8", errors="replace") + "\n… (truncated — open a terminal for full merge-tree output)"
        if not raw and mt.returncode != 0:
            return "`git merge-tree` failed — your git may use a newer merge-tree CLI; try `git merge-tree -h` locally."
        return raw or "(merge-tree produced no output — branches may match)"
    except (OSError, subprocess.TimeoutExpired) as exc:
        return f"(git command failed: `{exc}`)"


def _forager_plan_apply_fingerprint(plan: Dict[str, Any]) -> str:
    raw = json.dumps(plan, sort_keys=True, default=str, ensure_ascii=True).encode("utf-8")
    return hashlib.sha256(raw).hexdigest()[:20]


def _forager_plan_unlock_session_key(plan: Dict[str, Any]) -> str:
    """One unlock per plan fingerprint so Approvals Inbox and source routes share the same gate."""
    return f"forager_plan_unlock_{_forager_plan_apply_fingerprint(plan)}"


def _forager_feature_plan_apply_allowed(
    launcher: LauncherCore, *, key_prefix: str, plan: Dict[str, Any]
) -> Tuple[bool, str]:
    del key_prefix  # retained for call-site compatibility; unlock is fingerprint-global
    if bool(launcher.config.get("ai_apply_blocked")):
        return False, "AI plan apply is disabled in **Settings** (Block AI plan applies)."
    if bool(launcher.config.get("ai_writes_require_preview")):
        sk = _forager_plan_unlock_session_key(plan)
        if not st.session_state.get(sk):
            return (
                False,
                "Click **Mark diffs reviewed** for this plan, or disable **Require diff review before Apply** in Settings.",
            )
        return True, ""
    return True, ""


def _forager_approvals_extract_plan(payload: Any) -> Optional[Dict[str, Any]]:
    if not isinstance(payload, dict) or not payload:
        return None
    inner = payload.get("feature_plan")
    if isinstance(inner, dict) and inner:
        return inner
    if isinstance(payload.get("actions"), list):
        return payload
    return None


def _forager_approvals_enqueue_from_plan(
    plan: Optional[Dict[str, Any]],
    *,
    pack_root: str,
    source_nav: str,
    title_fallback: str,
) -> None:
    if not isinstance(plan, dict) or not plan:
        return
    root = os.path.normpath(os.path.expanduser(str(pack_root or "").strip()))
    if not root or not os.path.isdir(root):
        return
    try:
        from forager_ai.approvals.inbox_store import upsert_pending

        fp = _forager_plan_apply_fingerprint(plan)
        title = str(plan.get("feature_name") or plan.get("title") or title_fallback)[:500]
        upsert_pending(plan, pack_root=root, source_nav=source_nav, title=title, plan_fp=fp)
    except Exception:
        pass


def _forager_approvals_enqueue_from_payload(
    payload: Any,
    *,
    pack_root: str,
    source_nav: str,
    title_fallback: str,
) -> None:
    plan = _forager_approvals_extract_plan(payload)
    _forager_approvals_enqueue_from_plan(
        plan, pack_root=pack_root, source_nav=source_nav, title_fallback=title_fallback
    )


def _instance_target_label(instance: MinecraftInstance) -> str:
    return f"Forager · {instance.name}"


def _open_instance_in_mod_browser(
    instance: MinecraftInstance,
    catalog_kind: str,
    *,
    catalog_seek_query: Optional[str] = None,
    catalog_seek_autorun: bool = False,
) -> None:
    """Deep-link Configure workspace actions into the existing catalog installer."""
    st.session_state["mods_install_target"] = "Minecraft instance"
    st.session_state["mods_target_instance"] = _instance_target_label(instance)
    st.session_state["mods_catalog_kind"] = "modpack"
    st.session_state["_mods_catalog_kind_prev"] = "modpack"
    st.session_state["mods_mc_ver"] = instance.minecraft_version or "1.20.1"
    loader = (instance.loader or "forge").lower()
    st.session_state["mods_loader"] = loader if loader in {"forge", "fabric", "quilt", "neoforge", "vanilla"} else "forge"
    qs = str(catalog_seek_query or "").strip()
    if qs:
        st.session_state["_mods_seek_query"] = qs
        st.session_state["_mods_seek_autorun"] = bool(catalog_seek_autorun)
    elif catalog_seek_autorun:
        st.session_state["_mods_seek_autorun"] = True
    st.session_state["forager_nav"] = "mods"
    st.rerun()


def _selected_config_instance(launcher: LauncherCore) -> Optional[MinecraftInstance]:
    name = st.session_state.get("forager_config_instance")
    if not name:
        return None
    return launcher.instance_manager.get_instance(str(name))


def _can_try_native_instance_launch(instance: MinecraftInstance) -> Tuple[bool, str]:
    """The current native launcher needs a local libraries folder and minecraft.jar."""
    root = instance.instance_path
    if not root or not os.path.isdir(root):
        return False, "The instance folder is missing."
    if not os.path.isdir(os.path.join(root, "libraries")):
        return False, "No `libraries/` folder was found, so this linked profile likely depends on its original launcher."
    if not os.path.exists(os.path.join(root, "minecraft.jar")):
        return False, "No `minecraft.jar` was found for Forager's current native launch path."
    return True, "Native launch files were found."


def _try_launch_instance(launcher: LauncherCore, instance: MinecraftInstance) -> None:
    linked = bool(getattr(instance, "linked_source", None))
    can_try, reason = _can_try_native_instance_launch(instance)
    if linked and not can_try:
        st.session_state["forager_launch_fallback"] = {
            "name": instance.name,
            "path": instance.instance_path,
            "reason": reason,
            "source": getattr(instance, "linked_source", "external"),
        }
        _st_brief_warn(f"{instance.name} needs its original launcher. {reason}")
        return
    with st.spinner(f"Launching {instance.name}..."):
        ok = launcher.launch_instance(instance.name)
    if ok:
        _st_brief_ok(f"Launched {instance.name}.")
        st.rerun()
    else:
        st.session_state["forager_launch_fallback"] = {
            "name": instance.name,
            "path": instance.instance_path,
            "reason": "Native launch failed. Use the original launcher or inspect the folder.",
            "source": getattr(instance, "linked_source", "forager") or "forager",
        }
        _st_brief_warn("Native launch failed; fallback guidance is shown below.")


def _list_workspace_files(root: str, subdir: str, extensions: Tuple[str, ...], limit: int = 160) -> List[Dict[str, Any]]:
    folder = os.path.join(root, subdir)
    rows: List[Dict[str, Any]] = []
    if not os.path.isdir(folder):
        return rows
    for base, _, files in os.walk(folder):
        for filename in sorted(files):
            if not filename.lower().endswith(extensions):
                continue
            full = os.path.join(base, filename)
            rel = os.path.relpath(full, root).replace("\\", "/")
            try:
                rows.append(
                    {
                        "name": filename,
                        "rel": rel,
                        "size_mb": round(os.path.getsize(full) / (1024 * 1024), 2),
                        "modified": datetime.fromtimestamp(os.path.getmtime(full)).strftime("%Y-%m-%d"),
                    }
                )
            except OSError:
                rows.append({"name": filename, "rel": rel, "size_mb": 0, "modified": "unknown"})
            if len(rows) >= limit:
                return rows
    return rows


def _subdir_norm_name(subdir: str) -> str:
    return Path(str(subdir).replace("\\", "/")).name.lower()


def _list_workspace_jar_mods(game_root: str, subdir: str = "mods", *, limit: int = 620) -> List[Dict[str, Any]]:
    """
    Forge/CurseForge-style mod entries: *.jar enabled and *.jar.disabled (toggle target).
    Check ``.jar.disabled`` before``.jar`` — ``x.jar.disabled`` wrongly matches ``endswith(\".jar\")``.
    """
    folder = os.path.join(game_root, subdir)
    rows: List[Dict[str, Any]] = []
    if not os.path.isdir(folder):
        return rows
    for base, _, files in os.walk(folder):
        for filename in sorted(files):
            low = filename.lower()
            disabled = False
            if low.endswith(".jar.disabled"):
                disabled = True
            elif low.endswith(".jar"):
                disabled = False
            else:
                continue
            full = os.path.join(base, filename)
            rel = os.path.relpath(full, game_root).replace("\\", "/")
            try:
                rows.append(
                    {
                        "name": filename,
                        "rel": rel,
                        "disabled": disabled,
                        "path": full,
                        "size_mb": round(os.path.getsize(full) / (1024 * 1024), 2),
                        "modified": datetime.fromtimestamp(os.path.getmtime(full)).strftime("%Y-%m-%d"),
                    }
                )
            except OSError:
                rows.append(
                    {
                        "name": filename,
                        "rel": rel,
                        "disabled": disabled,
                        "path": full,
                        "size_mb": 0,
                        "modified": "unknown",
                    }
                )
            if len(rows) >= limit:
                return sorted(rows, key=lambda r: (not r["disabled"], str(r["name"]).lower()))
    return sorted(rows, key=lambda r: (not r["disabled"], str(r["name"]).lower()))


def _mods_workspace_jar_logical_name(storage_name: str) -> str:
    """Sort/search key ignoring disabled suffix."""
    sn = storage_name.lower()
    if sn.endswith(".jar.disabled"):
        return storage_name[: -len(".disabled")]
    return storage_name


def _mods_workspace_toggle_jar_disabled(row: Dict[str, Any]) -> Tuple[bool, str]:
    p = Path(str(row.get("path") or ""))
    if not p.is_file():
        return False, "File not found."
    s = str(p)
    low = s.lower()
    try:
        if row.get("disabled"):
            if not low.endswith(".jar.disabled"):
                return False, "Not a disabled mod file."
            dst = Path(s[: -len(".disabled")])
        else:
            if not low.endswith(".jar"):
                return False, "Expected a `.jar` file."
            dst = Path(s + ".disabled")
        if dst.exists():
            return False, f"Blocked: `{dst.name}` already exists."
        os.replace(str(p), str(dst))
        return True, "Updated."
    except OSError as exc:
        return False, str(exc)


def _mods_workspace_delete_jar(row: Dict[str, Any]) -> Tuple[bool, str]:
    p = Path(str(row.get("path") or ""))
    if not p.is_file():
        return False, "File not found."
    low = p.name.lower()
    if not (low.endswith(".jar") or low.endswith(".jar.disabled")):
        return False, "Wrong file type."
    try:
        p.unlink()
        return True, "Removed."
    except OSError as exc:
        return False, str(exc)


def _mods_workspace_mod_toggle_callback(toggle_key: str, row_snap: Dict[str, Any]) -> None:
    want_on = bool(st.session_state.get(toggle_key))
    is_on = not bool(row_snap.get("disabled"))
    if want_on == is_on:
        return
    ok_t, msg_t = _mods_workspace_toggle_jar_disabled(row_snap)
    if not ok_t:
        st.session_state[toggle_key] = is_on
        _st_brief_warn(msg_t)
        return
    _st_brief_ok("Mod enabled (renamed back to `.jar`)." if want_on else "Mod disabled (`.jar.disabled`).")
    st.rerun()


def _mods_sanitize_jar_version_for_display(raw: str, logical_fn: str) -> str:
    """Strip Gradle/TOML placeholders like ${{file.jarVersion}}; fall back to semver-like tokens from the jar name."""
    v = (raw or "").strip()
    low = v.lower()
    bogus = "${" in v or "{{" in v or "file.jarver" in low
    stem = Path(_mods_workspace_jar_logical_name(logical_fn)).stem
    fallback = ""
    cand = re.findall(r"\d+\.\d+(?:\.\d+)?(?:[-+a-zA-Z0-9.]+)?", stem)
    if cand:
        fallback = cand[-1][:26]
    if v and not bogus and len(v) < 52:
        return v[:26]
    if bogus or not v:
        return fallback
    return v[:26]


def _mods_resolve_mc_loader_for_install(
    sel_inst: Optional[MinecraftInstance],
    sel_external: Optional[ExternalInstanceInfo],
    game_version_filter: str,
    loader_filter: str,
) -> Tuple[Optional[str], Optional[str]]:
    """Minecraft version + loader for resolving catalog files (Modrinth / CurseForge)."""
    if sel_inst:
        lf = sel_inst.loader
        loader_out: Optional[str] = None if lf == "vanilla" else lf
        return sel_inst.minecraft_version, loader_out
    if sel_external:
        gv = (sel_external.minecraft_version or "").strip()
        if not gv or gv.lower() == "unknown":
            gv = (game_version_filter or "").strip()
        lf_raw = (sel_external.loader or "").strip().lower()
        if lf_raw in ("", "unknown"):
            loader_out = None if loader_filter == "vanilla" else loader_filter
        elif lf_raw == "vanilla":
            loader_out = None
        else:
            loader_out = sel_external.loader
        return (gv or None), loader_out
    return None, None


_JAR_PROFILE_SCAN_LIMIT = 520


def _mods_normalized_game_root(game_root: str) -> str:
    """Absolute normalized path string for catalog ↔ modlist caches."""
    try:
        return os.path.normpath(str(Path(game_root).expanduser().resolve()))
    except OSError:
        return os.path.normpath(os.path.expanduser(str(game_root)))


def _mods_catalog_soft_key(label: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", (label or "").lower())


def _split_mod_stem_camel_words(s: str) -> str:
    if not s:
        return s
    t = re.sub(r"([a-z0-9])([A-Z][a-z]+)", r"\1 \2", s)
    return re.sub(r"([A-Z]+)([A-Z][a-z])", r"\1 \2", t)


def _mods_stem_take_mod_name_prefix(stem: str) -> str:
    """Drop loader channel suffix (-forge-, _FORGE_) so we humanize only the project side."""
    if not stem.strip():
        return stem
    s = stem.strip()
    low = s.lower()
    markers = (
        "-forge-",
        "-fabric-",
        "-neoforge-",
        "-quilt-",
        "_forge_",
        "__forge_",
        "-forge_",
        "_fabric_",
        "__fabric_",
        "-fabric_",
        "_fabric-",
        "-neoforge_",
        "-quilt_",
    )
    cut_at = len(s)
    for m in markers:
        idx = low.find(m)
        if idx >= 6 and idx < cut_at:
            cut_at = idx
    trimmed = (s[:cut_at] if cut_at < len(s) else s).rstrip("-_ .+")
    return trimmed or stem


def _stem_strip_loaders_and_versions(stem: str) -> str:
    """Remove common Forge/Fabric + Minecraft version tails from jar file stems."""
    s = stem.strip()
    if not s:
        return s
    s = re.sub(r"^[\[\(][^\]\)]*[\]\)]\s*", "", s)
    s = re.sub(r"(?i)(^|[\-_])(?:forge|fabric|neoforge|quilt)(?:$|[\-_]+)", r"\1", s)
    s = re.sub(r"(?i)_FORGE_", "_", s).replace("__", "_")
    s = re.sub(r"(?i)_FABRIC_", "_", s).replace("__", "_")
    s = re.sub(r"(?i)-(?:forge|fabric|neoforge|quilt)(?:-|_|$|$)", "-", s)
    for pat in (
        r"[._-]?(?:mc|MC)[._-]?1\.\d(?:\.\d)?.+$",
        r"(?:\-|_|\.|\+)(?:1\.\d{1,2}(?:\.\d+)?)(?:[._\-+].*)?$",
        r"(?:^|[._-])v\d+(?:[._-]\d+)+$",
    ):
        ns = re.sub(pat, "", s, flags=re.I)
        if ns != s:
            s = ns
    s = re.sub(r"[._\-+]{2,}", "-", s)
    return s.strip(" -_+.") or stem


def _title_case_readable_mod_words(text: str) -> str:
    tiny = {"of", "the", "for", "and", "to", "from", "a", "an", "in", "on", "at", "vs", "x", "or"}
    parts: List[str] = []
    for i, raw in enumerate(text.split()):
        w = raw.strip()
        if not w:
            continue
        lw = w.lower()
        if lw in tiny and i > 0:
            parts.append(lw)
            continue
        if w.isascii() and re.fullmatch(r"[A-Z]{2,4}", w):
            parts.append(w)
            continue
        if not w.isascii() or lw.isdigit() or lw.startswith("§"):
            parts.append(raw)
            continue
        parts.append(w[:1].upper() + lw[1:])
    return " ".join(parts) if parts else text


def _humanize_mod_jar_stem(stem: str) -> str:
    """Best-effort CurseForge-style title when manifest displayName is missing or slug-only."""
    if not stem.strip():
        return stem
    root = stem.split("+")[0].split("__")[0].strip()
    root = _mods_stem_take_mod_name_prefix(root)
    root = _stem_strip_loaders_and_versions(root)
    if len(root.strip()) < 2:
        root = stem.split("+")[0].split("__")[0].strip()
    compact = re.sub(r"[\.\-_\+]+", "", root).strip()
    if len(compact) < 2:
        compact = re.sub(r"\s+", "", root)
    spaced = _split_mod_stem_camel_words(compact)
    spaced = re.sub(r"(\d)([A-Za-z])", r"\1 \2", spaced)
    spaced = re.sub(r"\s+", " ", spaced).strip()
    if len(spaced) < 2:
        spaced = re.sub(r"[\-_]+", " ", root).strip()
    return _title_case_readable_mod_words(spaced) if spaced else stem


def _pil_from_jar_logo_data_uri(data_uri: str) -> Optional[Image.Image]:
    if not isinstance(data_uri, str) or not data_uri.startswith("data:"):
        return None
    if len(data_uri) > 62_500:
        return None
    try:
        comma = data_uri.find(",")
        if comma < 0:
            return None
        blob = base64.b64decode(data_uri[comma + 1 :].strip())
        im = Image.open(io.BytesIO(blob))
        im.load()
        _rs = getattr(getattr(Image, "Resampling", Image), "LANCZOS", getattr(Image, "LANCZOS", Image.BICUBIC))
        im.thumbnail((96, 96), _rs)
        return im
    except Exception:
        return None


def _mod_catalog_snip_dedupe(jar_note: str, catalog_snip: str) -> str:
    a = re.sub(r"\s+", " ", (jar_note or "").strip().lower())
    b = re.sub(r"\s+", " ", (catalog_snip or "").strip().lower())
    if not b:
        return ""
    if not a:
        return (catalog_snip or "").strip()
    if a == b:
        return ""
    n = 36
    if len(a) >= n and len(b) >= n and (a[:n] == b[:n] or a in b or b in a):
        return ""
    return (catalog_snip or "").strip()


def _mod_card_letter_tile(label: str, size: int = 56) -> Image.Image:
    raw = (label or "").strip()
    ch = (raw[:1] or "?").upper()
    palettes = [
        (30, 58, 138),
        (21, 94, 117),
        (88, 28, 135),
        (120, 53, 15),
        (30, 41, 59),
        (22, 101, 52),
    ]
    idx = abs(hash(raw)) % len(palettes)
    im = Image.new("RGB", (size, size), palettes[idx])
    draw = ImageDraw.Draw(im)
    font: Any = None
    if os.name == "nt":
        windir = os.environ.get("WINDIR", r"C:\Windows")
        for rel in ("Fonts\\segoeuib.ttf", "Fonts\\segoeui.ttf", "Fonts\\arial.ttf"):
            fp = os.path.join(windir, rel)
            if os.path.isfile(fp):
                try:
                    font = ImageFont.truetype(fp, max(18, size // 2))
                    break
                except OSError:
                    pass
    if font is None:
        for p in (
            "/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
            "/System/Library/Fonts/Supplemental/Arial Bold.ttf",
        ):
            if os.path.isfile(p):
                try:
                    font = ImageFont.truetype(p, max(18, size // 2))
                    break
                except OSError:
                    pass
    if font is None:
        font = ImageFont.load_default()
    fill = (226, 232, 240)
    bbox = draw.textbbox((0, 0), ch, font=font)
    tw, th = bbox[2] - bbox[0], bbox[3] - bbox[1]
    ox, oy = (size - tw) // 2 - bbox[0], (size - th) // 2 - bbox[1]
    draw.text((ox, oy), ch, font=font, fill=fill)
    return im


def _curseforge_like_mod_primary_title(display_name: str, mod_id: str, fname: str) -> str:
    stem = Path(fname).stem
    dn = (display_name or "").strip()
    mid = (mod_id or "").strip()
    fallback = _humanize_mod_jar_stem(stem)

    mid_tail = mid.split(":")[-1].strip()
    dn_soft = _mods_catalog_soft_key(dn)
    mid_soft = _mods_catalog_soft_key(mid_tail)
    stem_soft = _mods_catalog_soft_key(stem)

    if not dn or dn.lower() == mid_tail.lower():
        return fallback or stem

    # Slugs that equal the cleaned filename token read better as humanized stems.
    if dn_soft == stem_soft and " " not in dn and "'" not in dn:
        return fallback or dn

    if mid_soft and dn_soft == mid_soft and " " not in dn:
        return fallback or dn

    return dn


def _looks_like_opaque_project_id(pid: str) -> bool:
    """True for UUID-shaped Modrinth project ids where slug-based matching matters."""
    p = (pid or "").strip().lower()
    if len(p) != 36 or p.count("-") != 4:
        return False
    return bool(re.fullmatch(r"[0-9a-f\-]+", p))


def _modrinth_slug_from_catalog_url(url: Optional[str]) -> str:
    if not url or not isinstance(url, str):
        return ""
    m = re.search(
        r"modrinth\.com/(?:mod|modpack|shader|resourcepack|datapack)/([^/?#]+)",
        url,
        re.I,
    )
    if not m:
        return ""
    return unquote(m.group(1).strip()).lower()


def _mods_local_jars_mtime_signature(game_root_abs: str) -> str:
    """Invalidates jar profile cache when mods/ contents change."""
    root = Path(game_root_abs) / "mods"
    if not root.is_dir():
        return "missing"
    max_ns = 0
    n = 0
    for base, _, names in os.walk(root):
        for fn in names:
            fl = fn.lower()
            if fl.endswith(".jar.disabled"):
                pass
            elif not fl.endswith(".jar"):
                continue
            fp = Path(base) / fn
            try:
                max_ns = max(max_ns, fp.stat().st_mtime_ns)
            except OSError:
                pass
            n += 1
            if n >= _JAR_PROFILE_SCAN_LIMIT:
                return f"n{n}|mt{max_ns}|cap"
    return f"n{n}|mt{max_ns}"


@st.cache_data(ttl=90, max_entries=256, show_spinner=False)
def _mods_cached_local_jar_profiles(norm_root: str, sig: str) -> List[Dict[str, Any]]:
    """Forge/Fabric mods.toml-derived ids + stems for aligning Modlist jars with Browse Modpacks."""
    out: List[Dict[str, Any]] = []
    root = Path(norm_root)
    mods_dir = root / "mods"
    if not mods_dir.is_dir():
        return out
    n = 0
    for base, _, names in os.walk(str(mods_dir)):
        for fn in sorted(names):
            fl = fn.lower()
            if fl.endswith(".jar.disabled"):
                pass
            elif not fl.endswith(".jar"):
                continue
            fp = Path(base) / fn
            try:
                rel = os.path.relpath(str(fp), str(root)).replace("\\", "/")
            except ValueError:
                rel = fn
            logical_fn = _mods_workspace_jar_logical_name(fn)
            stem = Path(logical_fn).stem
            meta = read_jar_mod_metadata(str(fp))
            raw_mid = str(meta.get("mod_id") or "").strip().lower()
            if ":" in raw_mid:
                raw_mid = raw_mid.split(":", 1)[-1].strip()
            disp = str(meta.get("display_name") or "").strip()
            snippet = str(meta.get("description") or "").replace("\n", " ").strip()
            if len(snippet) > 320:
                snippet = snippet[:317] + "..."
            logo_uri = ""
            raw_logo = meta.get("logo_data_uri")
            if isinstance(raw_logo, str) and raw_logo.startswith("data:") and len(raw_logo) < 62_000:
                logo_uri = raw_logo
            auth_list = meta.get("authors") if isinstance(meta.get("authors"), list) else []
            authors_text = ", ".join(str(x).strip() for x in auth_list[:5] if str(x).strip())
            jar_ver = _mods_sanitize_jar_version_for_display(str(meta.get("version") or "").strip(), logical_fn)
            try:
                zmt = fp.stat().st_mtime
                zsz = fp.stat().st_size
            except OSError:
                zmt = 0.0
                zsz = 0
            out.append(
                {
                    "name": fn,
                    "rel": rel,
                    "stem": stem,
                    "stem_soft": _mods_catalog_soft_key(stem),
                    "mod_id": raw_mid,
                    "display_name": disp,
                    "display_soft": _mods_catalog_soft_key(disp or stem),
                    "curseforge_like_title": _curseforge_like_mod_primary_title(disp, raw_mid, logical_fn),
                    "jar_snippet": snippet,
                    "logo_data_uri": logo_uri,
                    "authors_text": authors_text,
                    "jar_version": jar_ver,
                    "mtime": zmt,
                    "size_bytes": zsz,
                    "path": str(fp),
                }
            )
            n += 1
            if n >= _JAR_PROFILE_SCAN_LIMIT:
                break
        if n >= _JAR_PROFILE_SCAN_LIMIT:
            break
    out.sort(key=lambda r: str(r["name"]).lower())
    return out


def list_local_mod_profiles_for_game_root(game_root: str) -> List[Dict[str, Any]]:
    if not game_root or not os.path.isdir(game_root):
        return []
    key = _mods_normalized_game_root(game_root)
    # Bump schema when jar title/heuristic logic changes so Streamlit drops stale profiles.
    sig = "titles_v5|" + _mods_local_jars_mtime_signature(key)
    return list(_mods_cached_local_jar_profiles(key, sig))


def _mods_game_root_for_installed_bridge(
    install_target: str,
    *,
    sel_inst: Optional[MinecraftInstance],
    sel_external: Optional[ExternalInstanceInfo],
    pack_for_mods: Optional[str],
) -> Optional[str]:
    if install_target.startswith("Minecraft"):
        if sel_inst:
            return sel_inst.instance_path
        if sel_external:
            return sel_external.game_root
        return None
    if install_target.startswith("Pack") and pack_for_mods:
        return os.path.join(PACKS_DIR, pack_for_mods)
    return None


def catalog_mod_matches_installed_jar(mod: ModInfo, profiles: Sequence[Dict[str, Any]]) -> Optional[str]:
    """Return matching local jar filename if this catalog row is already installed in the target mods/ folder."""
    if not profiles:
        return None
    slug_mr = ""
    pid_low = str(mod.project_id or "").strip().lower()
    if mod.source == "modrinth":
        slug_mr = _modrinth_slug_from_catalog_url(mod.project_url)
        if not slug_mr and mod.project_url and pid_low:
            slug_mr = pid_low if not _looks_like_opaque_project_id(pid_low) else ""
    catalog_name_soft = _mods_catalog_soft_key(mod.name or "")

    for prof in profiles:
        mid = str(prof.get("mod_id") or "").strip().lower()
        stem_soft = str(prof.get("stem_soft") or "")
        display_soft = str(prof.get("display_soft") or "")
        fname = str(prof.get("name") or "")

        if mod.source == "modrinth":
            if slug_mr and mid == slug_mr:
                return fname
            if slug_mr and display_soft == slug_mr and len(slug_mr) >= 4:
                return fname
            if pid_low and not _looks_like_opaque_project_id(pid_low) and mid == pid_low:
                return fname

        # CurseForge (and fuzzy Modrinth fallbacks): compare normalized titles / stems.
        if catalog_name_soft and len(catalog_name_soft) >= 4:
            if display_soft == catalog_name_soft:
                return fname
            if len(stem_soft) >= 5 and stem_soft in catalog_name_soft:
                return fname
            if len(stem_soft) >= 6 and catalog_name_soft in stem_soft:
                return fname

    return None


def _mods_excerpt_graph_manifest_from_profiles(
    profiles: List[Dict[str, Any]],
    *,
    max_nodes: int = 100,
) -> Dict[str, Any]:
    """Build a minimal manifest dict for ``build_graph`` from scanned ``mods/`` jar profiles."""
    mods: List[Dict[str, Any]] = []
    seen: set[str] = set()
    cap = max(1, int(max_nodes))
    for p in profiles[:cap]:
        mid = str(p.get("mod_id") or "").strip().lower()
        if not mid:
            mid = str(p.get("display_soft") or p.get("stem_soft") or "").strip().lower()
        if not mid or mid in seen:
            continue
        seen.add(mid)
        mods.append({"mod_id": mid, "dependencies": []})
    return {"mods": mods, "compats": []}


def _mods_parse_iso_timestamp(value: Optional[str]) -> Optional[datetime]:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return datetime.fromisoformat(raw.replace("Z", "+00:00"))
    except ValueError:
        return None


def _mods_row_category_tags(mod: ModInfo) -> List[str]:
    """Category + loader tags attached to a catalog row (for client filters)."""
    tags: List[str] = []
    seen: set[str] = set()
    for raw in list(mod.categories or []) + list(mod.loaders or []):
        t = str(raw or "").strip()
        if not t:
            continue
        key = t.lower()
        if key in seen:
            continue
        seen.add(key)
        tags.append(t)
    return tags


def _mods_row_category_tag_set(mod: ModInfo) -> set[str]:
    return {t.lower() for t in _mods_row_category_tags(mod)}


def _mods_sync_category_option_pool(mods: Sequence[ModInfo]) -> List[str]:
    pool = [str(x).strip() for x in (st.session_state.get("mods_cli_category_pool") or []) if str(x).strip()]
    seen = {x.lower() for x in pool}
    for m in mods:
        for t in _mods_row_category_tags(m):
            kl = t.lower()
            if kl in seen:
                continue
            seen.add(kl)
            pool.append(t)
    pool = sorted(pool, key=lambda s: s.lower())[:160]
    st.session_state["mods_cli_category_pool"] = pool
    return pool


def _mods_category_options_for_ui(mods: Sequence[ModInfo]) -> List[str]:
    return _mods_sync_category_option_pool(mods)


def _mods_prune_category_widget_state(options: Sequence[str]) -> None:
    allow = {str(x) for x in options}
    for key in ("mods_cli_categories", "mods_cli_exclude_categories"):
        cur = st.session_state.get(key) or []
        if not isinstance(cur, list):
            continue
        pruned = [x for x in cur if x in allow]
        if pruned != cur:
            st.session_state[key] = pruned


def _mods_prune_theme_widget_state() -> None:
    allow = set(_MODS_THEME_RULES.keys())
    cur = st.session_state.get("mods_active_themes") or []
    if not isinstance(cur, list):
        st.session_state["mods_active_themes"] = []
        return
    pruned = [str(x) for x in cur if str(x) in allow]
    if pruned != cur:
        st.session_state["mods_active_themes"] = pruned


def _mods_apply_catalog_client_filters(mods: List[ModInfo]) -> List[ModInfo]:
    """Narrow catalog rows client-side with pack-aware dynamic filters."""
    out = list(mods)
    active_themes = [str(x) for x in (st.session_state.get("mods_active_themes") or []) if str(x) in _MODS_THEME_RULES]
    if active_themes:
        theme_tokens: List[str] = []
        for t in active_themes:
            theme_tokens.extend([str(x).strip().lower() for x in (_MODS_THEME_RULES.get(t, {}).get("include") or []) if str(x).strip()])
        token_set = sorted(set(theme_tokens))
        if token_set:
            out = [m for m in out if any(tok in _mods_row_blob_for_theme(m) for tok in token_set)]
    cats = st.session_state.get("mods_cli_categories") or []
    if cats:
        cat_l = {str(c).strip().lower() for c in cats if str(c).strip()}
        cat_mode = str(st.session_state.get("mods_cli_category_mode") or "Any selected").strip()
        if cat_mode == "All selected":
            out = [m for m in out if cat_l.issubset(_mods_row_category_tag_set(m))]
        else:
            out = [m for m in out if _mods_row_category_tag_set(m) & cat_l]
    srcs = st.session_state.get("mods_cli_sources")
    if srcs is None:
        srcs = ["modrinth", "curseforge"]
    if isinstance(srcs, list) and len(srcs) == 0:
        srcs = ["modrinth", "curseforge"]
    if isinstance(srcs, list) and len(srcs) > 0:
        allow = {str(s).strip().lower() for s in srcs}
        out = [m for m in out if str(m.source or "").strip().lower() in allow]
    sort_mode = str(st.session_state.get("mods_cli_sort") or "API order")
    if sort_mode == "Downloads (high first)":
        out.sort(key=lambda m: int(m.download_total or 0), reverse=True)
    elif sort_mode == "Downloads (low first)":
        out.sort(key=lambda m: int(m.download_total or 0))
    elif sort_mode == "Name A-Z":
        out.sort(key=lambda m: (m.name or "").lower())
    elif sort_mode == "Name Z-A":
        out.sort(key=lambda m: (m.name or "").lower(), reverse=True)
    elif sort_mode == "Author A-Z":
        out.sort(key=lambda m: (m.author or "").lower())
    elif sort_mode == "Author Z-A":
        out.sort(key=lambda m: (m.author or "").lower(), reverse=True)
    elif sort_mode == "Updated (newest first)":

        def _upd_key(m: ModInfo) -> float:
            dt = _mods_parse_iso_timestamp(m.updated_at)
            return dt.timestamp() if dt is not None else float("-inf")

        out.sort(key=_upd_key, reverse=True)
    elif sort_mode == "Updated (oldest first)":

        def _upd_key_old(m: ModInfo) -> float:
            dt = _mods_parse_iso_timestamp(m.updated_at)
            return dt.timestamp() if dt is not None else float("inf")

        out.sort(key=_upd_key_old)
    return out


def _install_modinfo_from_panel(
    launcher: LauncherCore,
    chosen: ModInfo,
    *,
    catalog_kind: str,
    install_target_is_instance: bool,
    sel_inst: Optional[MinecraftInstance],
    pack_for_mods: Optional[str],
    install_dependencies: bool,
    external_game_root: Optional[str] = None,
) -> None:
    """Run install for ModInfo from project panel (instance, external launcher profile, or pack)."""
    ck = (catalog_kind or "mods").strip().lower()
    deps = install_dependencies and ck == "mods"
    sub = launcher._catalog_subdir_for_kind(ck)
    if ck == "mods" and not external_game_root:
        if install_target_is_instance and sel_inst:
            preflight = launcher.preflight_instance_install(sel_inst.name, chosen)
            target_label = f"instance:{sel_inst.name}"
        elif pack_for_mods:
            root = os.path.join(PACKS_DIR, pack_for_mods)
            preflight = launcher.preflight_catalog_install(root, chosen, pack_name=pack_for_mods)
            target_label = f"pack:{pack_for_mods}"
        else:
            preflight = None
            target_label = "unknown"

        if preflight:
            st.session_state["forager_last_install_preflight"] = preflight
            decision = str(preflight.get("decision", "allow"))
            confirm_key = f"forager_preflight_confirm_{target_label}_{chosen.id}"
            if decision in {"warn", "block"} and not st.session_state.get(confirm_key):
                render_preflight_card(preflight)
                st.session_state[confirm_key] = True
                st.markdown(
                    '<div class="forager-mod-alert forager-mod-alert-tip">'
                    "<strong>Review gate:</strong> Click the install button again to confirm after reviewing this preflight report."
                    "</div>",
                    unsafe_allow_html=True,
                )
                return
            if decision in {"warn", "block"}:
                st.session_state.pop(confirm_key, None)

    if external_game_root:
        ok = launcher.install_catalog_into_pack(
            external_game_root,
            chosen,
            catalog_kind=ck,
            install_dependencies=deps,
        )
        fn = chosen.file_name or chosen.name
        if ok:
            st.success(f"Installed `{fn}` into external profile → `{sub}/` under game folder.")
        else:
            st.error("Install failed.")
    elif install_target_is_instance and sel_inst:
        ok = launcher.install_catalog_item(
            sel_inst.name,
            chosen,
            catalog_kind=ck,
            install_dependencies=deps,
        )
        fn = chosen.file_name or chosen.name
        if ok:
            st.success(f"Installed `{fn}` into instance `{sel_inst.name}` → `{sub}/`.")
        else:
            st.error("Install failed.")
    elif pack_for_mods:
        root = os.path.join(PACKS_DIR, pack_for_mods)
        ok = launcher.install_catalog_into_pack(
            root,
            chosen,
            catalog_kind=ck,
            install_dependencies=deps,
        )
        fn = chosen.file_name or chosen.name
        if ok:
            st.success(f"Installed `{fn}` into `packs/{pack_for_mods}/{sub}/`.")
        else:
            st.error("Install failed.")
    else:
        st.error("No download target.")


def _mods_row_anchor_id(mod: ModInfo) -> str:
    src = re.sub(r"[^a-z0-9]", "", str(mod.source or "x").lower())[:12]
    pid = re.sub(r"[^a-zA-Z0-9_-]", "_", str(mod.project_id or "proj"))[:56]
    return f"forager-mod-{src}-{pid}"


def _mods_detail_dialog_on_dismiss() -> None:
    a = st.session_state.pop("_mods_active_row_anchor", None)
    if isinstance(a, str) and a.strip():
        st.session_state["_mods_scroll_to_anchor"] = a.strip()
    st.session_state["mods_project_detail"] = None
    st.session_state.pop("_mods_open_detail_dialog", None)


def _mods_apply_mod_catalog_scroll_restore() -> None:
    anchor = st.session_state.pop("_mods_scroll_to_anchor", None)
    if not isinstance(anchor, str) or not anchor.strip():
        return
    a = anchor.strip()
    if not re.match(r"^[a-zA-Z0-9_-]+$", a):
        return
    js = json.dumps(a)
    components.html(
        "<script>(function(){const k="
        + js
        + ";function go(){try{var r=window.parent&&window.parent.document;if(!r)return;var e=r.getElementById(k);"
        "if(e)e.scrollIntoView({block:'nearest',inline:'nearest'});}catch(x){}}"
        ";(window.requestAnimationFrame||function(f){setTimeout(f,0);})(go);})();</script>",
        height=0,
        width=0,
    )


def _mods_close_project_detail_panel() -> None:
    _mods_detail_dialog_on_dismiss()
    st.rerun()


def _render_mod_project_detail_panel(
    launcher: LauncherCore,
    detail_sel: Optional[Dict[str, Any]],
    *,
    catalog_kind: str,
    mc_for_file: Optional[str],
    loader_for_file: Optional[str],
    can_install: bool,
    install_target_is_instance: bool,
    sel_inst: Optional[MinecraftInstance],
    pack_for_mods: Optional[str],
    external_game_root: Optional[str] = None,
) -> None:
    """Storefront-style project view: about, gallery, version file picker."""
    st.markdown('<div class="forager-mod-detail-shell">', unsafe_allow_html=True)
    try:
        if not detail_sel:
            st.markdown("### Project page")
            st.caption(
                "Pick **Project** next to a mod to open this panel — same idea as a Modrinth / CurseForge "
                "project page: long description, screenshots, and an explicit file version before **Install**."
            )
            return

        src = detail_sel.get("source")
        pid = str(detail_sel.get("project_id") or "").strip()
        if not pid or src not in ("modrinth", "curseforge"):
            st.warning("Invalid project selection.")
            return

        md = launcher.mod_downloader
        close_col, _ = st.columns([1, 3])
        with close_col:
            if st.button("Close", key="mods_detail_panel_close"):
                _mods_close_project_detail_panel()

        ck = (catalog_kind or "mods").strip().lower()
        mr_loader = ck in ("mods", "modpack")
        cf_loader = ck in ("mods", "modpack")

        if src == "modrinth":
            d = md.get_modrinth_project_detail(pid)
            if not d:
                st.error("Could not load this Modrinth project.")
                return
            title = d.get("title") or detail_sel.get("title") or "Project"
            ic = d.get("icon_url")
            h1, h2 = st.columns([1, 5])
            with h1:
                if ic:
                    st.image(ic, width=92)
            with h2:
                st.markdown(f"### {title}")
                st.caption(f"Modrinth — `{pid}`")
            cats = d.get("categories") or []
            if cats:
                st.caption(" · ".join(str(c) for c in cats[:10]))

            mcols = st.columns(3)
            dl = d.get("downloads")
            fl = d.get("follows")
            with mcols[0]:
                st.metric("Downloads", _fmt_downloads(int(dl)) if isinstance(dl, int) else (str(dl) if dl else "—"))
            with mcols[1]:
                st.metric("Follows", _fmt_downloads(int(fl)) if isinstance(fl, int) else (str(fl) if fl else "—"))
            with mcols[2]:
                st.metric("Gallery", len(d.get("gallery_urls") or []))

            link_bits: List[str] = []
            if d.get("project_url"):
                link_bits.append(f"[Modrinth]({d['project_url']})")
            if d.get("source_url"):
                link_bits.append(f"[Source]({d['source_url']})")
            if d.get("issues_url"):
                link_bits.append(f"[Issues]({d['issues_url']})")
            if d.get("wiki_url"):
                link_bits.append(f"[Wiki]({d['wiki_url']})")
            if d.get("discord_url"):
                link_bits.append(f"[Discord]({d['discord_url']})")
            if link_bits:
                st.markdown(" · ".join(link_bits))

            tab_about, tab_ver, tab_gal = st.tabs(["About", "Versions", "Gallery"])
            with tab_about:
                body = (d.get("body_markdown") or "").strip()
                if body:
                    cap = 24000
                    st.markdown(body[:cap] + ("…" if len(body) > cap else ""))
                else:
                    st.write((d.get("description") or "").strip() or "—")

            with tab_gal:
                urls = d.get("gallery_urls") or []
                if not urls:
                    st.caption("No gallery images for this project.")
                else:
                    for i in range(0, len(urls), 2):
                        g1, g2 = st.columns(2)
                        with g1:
                            st.image(urls[i], use_container_width=True)
                        if i + 1 < len(urls):
                            with g2:
                                st.image(urls[i + 1], use_container_width=True)

            with tab_ver:
                vers = md.get_modrinth_versions(
                    pid,
                    minecraft_version=mc_for_file,
                    loader=loader_for_file,
                    filter_loader=mr_loader,
                    catalog_kind=ck,
                )
                if not vers:
                    vers = md.get_modrinth_versions(
                        pid, None, None, filter_loader=False, catalog_kind=ck
                    )[:50]
                if not vers:
                    st.info("No files returned — try another Minecraft version or loader, or open the project on Modrinth.")
                else:
                    labels = [
                        f"{v.file_name or '?'} — {', '.join(v.minecraft_versions[:8])}"
                        + ("…" if len(v.minecraft_versions) > 8 else "")
                        for v in vers
                    ]
                    pick_i = st.selectbox(
                        "Version file",
                        list(range(len(vers))),
                        format_func=lambda i, lbls=labels: lbls[i],
                        key=f"mods_det_mr_pick_{pid}",
                    )
                    chosen = vers[pick_i]
                    st.caption(
                        f"Loaders: {', '.join(chosen.loaders or []) or '—'} · "
                        f"SHA1: `{chosen.sha1_hash or '—'}`"
                    )
                    if can_install and st.button(
                        "Install this file",
                        type="primary",
                        key=f"mods_det_mr_inst_{pid}",
                    ):
                        _install_modinfo_from_panel(
                            launcher,
                            chosen,
                            catalog_kind=ck,
                            install_target_is_instance=install_target_is_instance,
                            sel_inst=sel_inst,
                            pack_for_mods=pack_for_mods,
                            install_dependencies=(ck == "mods"),
                            external_game_root=external_game_root,
                        )

        else:
            if not _curseforge_downloader_ready(md):
                st.warning("Add a **CurseForge API key** under **Settings → Mod library** to load project details and file lists here.")
                return
            d = md.get_curseforge_mod_detail(pid)
            if not d:
                st.error("Could not load this CurseForge project.")
                return
            title = d.get("title") or detail_sel.get("title") or "Project"
            ic = d.get("icon_url")
            h1, h2 = st.columns([1, 5])
            with h1:
                if ic:
                    st.image(ic, width=92)
            with h2:
                st.markdown(f"### {title}")
                st.caption(f"CurseForge — `{pid}` · by {d.get('author') or '—'}")
            cats = d.get("categories") or []
            if cats:
                st.caption(" · ".join(str(c) for c in cats[:12]))

            dc = d.get("download_count")
            mcols = st.columns(2)
            with mcols[0]:
                st.metric("Downloads", _fmt_downloads(int(dc)) if isinstance(dc, int) else "—")
            with mcols[1]:
                st.metric("Screenshots", len(d.get("gallery_urls") or []))

            link_bits = []
            if d.get("project_url"):
                link_bits.append(f"[CurseForge]({d['project_url']})")
            if d.get("website_url"):
                link_bits.append(f"[Website]({d['website_url']})")
            if d.get("source_code_url"):
                link_bits.append(f"[Source]({d['source_code_url']})")
            if d.get("issues_url"):
                link_bits.append(f"[Issues]({d['issues_url']})")
            if d.get("wiki_url"):
                link_bits.append(f"[Wiki]({d['wiki_url']})")
            if link_bits:
                st.markdown(" · ".join(link_bits))

            tab_about, tab_ver, tab_gal = st.tabs(["About", "Versions", "Gallery"])
            with tab_about:
                plain = _strip_cf_html_to_text(str(d.get("description_html") or ""))
                if plain:
                    st.markdown(plain[:24000] + ("…" if len(plain) > 24000 else ""))
                else:
                    st.write(d.get("summary") or "—")

            with tab_gal:
                urls = d.get("gallery_urls") or []
                if not urls:
                    st.caption("No screenshots on the API response for this mod.")
                else:
                    for i in range(0, len(urls), 2):
                        g1, g2 = st.columns(2)
                        with g1:
                            st.image(urls[i], use_container_width=True)
                        if i + 1 < len(urls):
                            with g2:
                                st.image(urls[i + 1], use_container_width=True)

            with tab_ver:
                files = md.list_curseforge_mod_files(
                    pid,
                    minecraft_version=mc_for_file,
                    loader=loader_for_file,
                    use_loader=cf_loader,
                )
                if not files:
                    files = md.list_curseforge_mod_files(
                        pid, None, None, limit=50, use_loader=False
                    )
                if not files:
                    st.info("No files returned — check your filters or try on the CurseForge website.")
                else:
                    labels = []
                    for frec in files:
                        gvs = frec.get("gameVersions") or []
                        gv_s = ", ".join(str(x) for x in gvs[:6])
                        if len(gvs) > 6:
                            gv_s += "…"
                        labels.append(f"{frec.get('fileName') or '?'} — {gv_s}")
                    pick_i = st.selectbox(
                        "Mod file",
                        list(range(len(files))),
                        format_func=lambda i, lbls=labels: lbls[i],
                        key=f"mods_det_cf_pick_{pid}",
                    )
                    f_pick = files[pick_i]
                    if can_install and st.button(
                        "Install this file",
                        type="primary",
                        key=f"mods_det_cf_inst_{pid}",
                    ):
                        cand = md.curseforge_file_to_modinfo(pid, f_pick, catalog_kind=ck)
                        if not cand:
                            st.error("Could not resolve download for this file.")
                        else:
                            _install_modinfo_from_panel(
                                launcher,
                                cand,
                                catalog_kind=ck,
                                install_target_is_instance=install_target_is_instance,
                                sel_inst=sel_inst,
                                pack_for_mods=pack_for_mods,
                                install_dependencies=(ck == "mods"),
                                external_game_root=external_game_root,
                            )
    finally:
        st.markdown("</div>", unsafe_allow_html=True)


# Initialize launcher core
@st.cache_resource
def get_launcher(_resource_gen: int = 8):
    """Bump **_resource_gen** after LauncherCore / InstanceManager / ModDownloader API or behavior changes (Streamlit cache)."""
    return LauncherCore()

@st.cache_resource
def get_content_manager():
    launcher_dir = os.path.join(os.path.expanduser("~"), ".forager_ai")
    return ContentManager(os.path.join(launcher_dir, "content"))

@st.cache_resource
def get_conflict_resolver(_api_rev: int = _CONFLICT_RESOLVER_API_REV):
    """Bump **_api_rev** when ``ConflictResolver.analyze_mod_list`` / guardrail API changes."""
    launcher_dir = os.path.join(os.path.expanduser("~"), ".forager_ai")
    return ConflictResolver(os.path.join(launcher_dir, "conflicts"))

launcher = get_launcher(8)
_FORAGER_INST_LIST_CACHE: list = []


def _forager_instance_list(launcher) -> list:
    """Single snapshot per script run (Streamlit reruns the module; list is fresh each run)."""
    if not _FORAGER_INST_LIST_CACHE:
        _FORAGER_INST_LIST_CACHE.extend(launcher.instance_manager.list_instances())
    return _FORAGER_INST_LIST_CACHE


def _invalidate_forager_instance_list_cache() -> None:
    _FORAGER_INST_LIST_CACHE.clear()


def _launcher_config_signature(config: Dict[str, Any]) -> str:
    """Stable cache key for expensive external-instance discovery."""
    roots = {
        "curseforge_instances_root": str(config.get("curseforge_instances_root") or ""),
        "modrinth_profiles_root": str(config.get("modrinth_profiles_root") or ""),
    }
    return json.dumps(roots, sort_keys=True, ensure_ascii=True)


@st.cache_data(ttl=45, show_spinner=False)
def _discover_external_instances_cached(config_sig: str) -> List[Dict[str, Any]]:
    try:
        cfg = json.loads(config_sig)
    except Exception:
        cfg = {}
    roots_cfg = {
        "curseforge_instances_root": str(cfg.get("curseforge_instances_root") or ""),
        "modrinth_profiles_root": str(cfg.get("modrinth_profiles_root") or ""),
    }
    return [asdict(x) for x in discover_external_instances(roots_cfg)]


def _external_instances_list(launcher: LauncherCore) -> List[ExternalInstanceInfo]:
    rows = _discover_external_instances_cached(_launcher_config_signature(launcher.config))
    return [ExternalInstanceInfo(**row) for row in rows]


def _invalidate_external_instances_cache() -> None:
    _discover_external_instances_cached.clear()


try:
    launcher.reload_config_from_disk_if_changed()
except Exception:
    pass
content_manager = get_content_manager()
conflict_resolver = get_conflict_resolver(_CONFLICT_RESOLVER_API_REV)


@st.cache_data(ttl=45, show_spinner=False)
def _forager_hub_cached_preflight(
    pack_root: str,
    label: str,
    mc: str,
    loader: str,
    mods_sig: float,
    compats_sig: float,
    manifest_sig: float,
    lock_sig: float,
    dismissals_sig: float,
    telemetry_enabled: bool,
    telemetry_include_paths: bool,
) -> Dict[str, Any]:
    """Ephemeral scan + health for the Hub snapshot (mtimes bust cache when disk state changes)."""
    return build_launch_target_preflight_report(
        game_root=pack_root,
        label=label,
        minecraft_version=mc,
        loader=loader,
        launcher=launcher,
        conflict_resolver=conflict_resolver,
        telemetry_enabled=telemetry_enabled,
        telemetry_include_paths=telemetry_include_paths,
    )


def _manifest_signature(manifest: Dict[str, Any]) -> str:
    try:
        return json.dumps(manifest, sort_keys=True, ensure_ascii=True)
    except Exception:
        return "{}"


@st.cache_data(ttl=30, show_spinner=False)
def _cached_conflict_scan_report(
    *,
    manifest_sig: str,
    pack_root: str,
    pack_name: str,
    auto_resolve: bool = True,
    dismissals_sig: float = 0.0,
) -> Dict[str, Any]:
    try:
        manifest = json.loads(manifest_sig)
        if not isinstance(manifest, dict):
            manifest = {}
    except Exception:
        manifest = {}
    skip_ids = load_dismissed_conflict_ids(pack_root)
    return build_conflict_scan_report(
        resolver=conflict_resolver,
        manifest=manifest,
        pack_root=pack_root,
        pack_name=pack_name,
        auto_resolve=auto_resolve,
        skip_conflict_ids=skip_ids,
    )


def _pack_health_graph_node_cap(mods_n: int) -> int:
    return pack_health_graph_node_cap(mods_n)


def _humanize_conflict_type(type_str: str) -> str:
    return humanize_conflict_type(type_str)


def _pack_health_conflicts_signature(conflicts: List[Dict[str, Any]]) -> str:
    parts = [
        f"{str(c.get('id') or '')}|{str(c.get('severity') or '')}"
        for c in (conflicts or [])
    ]
    blob = "\n".join(sorted(parts))
    return hashlib.sha256(blob.encode("utf-8")).hexdigest()[:20]


@st.cache_data(ttl=120, show_spinner=False)
def _cached_pack_health_graph(
    *,
    manifest_sig: str,
    scan_mods_sig: str,
    scan_conflicts_sig: str,
    mods_n: int,
    dismissals_sig: float = 0.0,
) -> Dict[str, Any]:
    try:
        manifest = json.loads(manifest_sig)
        if not isinstance(manifest, dict):
            manifest = {}
    except Exception:
        manifest = {}
    try:
        scan_mods = json.loads(scan_mods_sig)
        if not isinstance(scan_mods, list):
            scan_mods = []
    except Exception:
        scan_mods = []
    try:
        scan_conflicts = json.loads(scan_conflicts_sig)
        if not isinstance(scan_conflicts, list):
            scan_conflicts = []
    except Exception:
        scan_conflicts = []
    cap = _pack_health_graph_node_cap(mods_n)
    graph_data = build_graph(
        manifest,
        scan_mods=scan_mods,
        scan_conflicts=scan_conflicts,
        max_render_nodes=cap,
    )
    dot = to_graphviz_dot(graph_data)
    mode = "conflict_focus" if int(mods_n) >= 150 else "full"
    return {
        "dot": dot,
        "nodes": str(len(graph_data.get("nodes") or [])),
        "edges": str(len(graph_data.get("edges") or [])),
        "mode": mode,
        "cap": str(cap),
        "findings_json": json.dumps(graph_data.get("findings") or [], ensure_ascii=True),
    }


def _compact_council_pack_overlay(ctx: Dict[str, Any]) -> Dict[str, Any]:
    """Trim pack brain fields for Council JSON payloads."""
    return {
        "pack_name": ctx.get("pack_name"),
        "health_score": (ctx.get("health_score") or {}).get("score"),
        "health_verdict": (ctx.get("health_score") or {}).get("verdict"),
        "health_narrative": str(ctx.get("health_narrative") or "")[:2200],
        "confirmed_facts_context": str(ctx.get("confirmed_facts_context") or "")[:1400],
        "context_cards_bundle": str(ctx.get("context_cards_bundle") or "")[:4500],
        "known_issue_hints": str(ctx.get("known_issue_hints") or "")[:2000],
    }


def _run_quality_council_review(
    *,
    pack_root: str,
    pack_name: str,
    title: str,
    payload: Dict[str, Any],
    artifact_type: str,
    subject: str,
) -> Dict[str, Any]:
    """Persist a Council artifact and run review when an API key is configured."""
    artifact = make_ai_artifact(
        artifact_type=artifact_type,
        pack_name=pack_name,
        title=title,
        summary="Automatic Council review for clarity, performance, compatibility, safety, stability, and professional quality.",
        source="forager_auto_quality_council",
        payload={
            **payload,
            "council_instructions": [
                "Review clarity: the output should be understandable and easy for the user to test.",
                "Review performance: flag tick loops, noisy assets, oversized files, long audio, and runtime risk.",
                "Review compatibility: check Minecraft 1.20.1 Forge expectations, optional mod fallbacks, namespaces, and resource paths.",
                "Review mod-delivery quality when applicable: plans should be buildable/testable (ids, dependencies, client/server split, asset paths, legal notes).",
                "Review quality: texture/model/audio/animation outputs should be coherent, polished, and suitable for pack testing.",
                "Block unsafe or unreviewable output.",
            ],
        },
    )
    artifact_path = ""
    try:
        artifact_path = save_ai_artifact(pack_root, artifact, folder=".forager/council_reviews/artifacts")
    except Exception:
        pass
    api_key = launcher.config.get("openrouter_api_key", "")
    report: Dict[str, Any]
    if not api_key.strip():
        report = {
            "chair": {
                "final_verdict": "skipped",
                "issues": [],
                "recommended_actions": ["Set an OpenRouter API key to enable automatic Council review."],
            },
            "artifact": artifact,
            "artifact_path": artifact_path,
        }
    else:
        try:
            pack_overlay = None
            try:
                _ov_ctx = build_pack_ai_context(
                    pack_root=pack_root,
                    pack_name=pack_name,
                    resolver=conflict_resolver,
                    include_performance=True,
                    council_lesson_chars=2000,
                    cache_dir=str(launcher.mod_downloader.cache_dir),
                    launcher=launcher,
                    game_root=pack_root,
                )
                pack_overlay = _compact_council_pack_overlay(_ov_ctx)
            except Exception:
                pack_overlay = None
            report = run_council_review(
                api_key=api_key,
                subject=subject,
                artifact=artifact,
                model=resolve_council_model(launcher.config),
                pack_context_overlay=pack_overlay,
            )
            report["artifact_path"] = artifact_path
        except Exception as exc:
            report = {
                "chair": {
                    "final_verdict": "error",
                    "issues": [{"severity": "medium", "detail": f"Council review failed: {exc}", "owner": "chair"}],
                    "recommended_actions": ["Retry review after checking API/network settings."],
                },
                "artifact": artifact,
                "artifact_path": artifact_path,
            }
    try:
        review_dir = Path(pack_root) / ".forager" / "council_reviews" / "reports"
        review_dir.mkdir(parents=True, exist_ok=True)
        stamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
        safe_type = re.sub(r"[^a-zA-Z0-9_-]+", "_", artifact_type)[:80]
        write_text_utf8_nobom(str(review_dir / f"{stamp}_{safe_type}.json"), json.dumps(report, indent=2, ensure_ascii=False))
    except Exception:
        pass
    return report


def _forager_hub_maybe_auto_council_and_render(
    *,
    pack_root: str,
    pack_name: str,
    user_question: str,
    assistant_markdown: str,
    mode_label: str,
) -> Tuple[str, int]:
    """If Settings permit, run multi-reviewer Council on a substantive Hub reply; render summary; return verdict + issue count."""
    cfg = launcher.config
    if not bool(cfg.get("hub_auto_council_validation", False)):
        return "", 0
    body = str(assistant_markdown or "").strip()
    if len(body) < _FORAGER_HUB_AUTO_COUNCIL_MIN_CHARS:
        return "", 0
    try:
        with st.spinner("AI Council validating this reply — safety, accuracy, polish, compat, ship quality + chair (~6 reviewer calls)."):
            rep = _run_quality_council_review(
                pack_root=pack_root,
                pack_name=pack_name or "pack",
                title="Automated Hub reply validation",
                payload={
                    "hub_user_question": user_question[:8000],
                    "hub_assistant_reply": body[:50000],
                    "hub_answer_mode": str(mode_label or "")[:220],
                    "notes": (
                        "This is a conversational hub answer for a Forge/Minecraft install — not necessarily a shipped mod "
                        "or asset. Flag unsafe pack advice (data loss, wrong loader), implausible Minecraft facts, unclear "
                        "steps the user cannot follow, and missing compatibility cues when mods are referenced."
                    ),
                },
                artifact_type="forager_hub_live_council_review",
                subject=f'Hub assistant reply QA — "{(pack_name or "pack")[:80]}"',
            )
        _render_council_review_result(rep, label="Council · Hub reply validation")
        chair = rep.get("chair") if isinstance(rep, dict) else {}
        verdict = str((chair or {}).get("final_verdict") or "").strip()
        issue_n = 0
        if isinstance(chair, dict):
            issues = chair.get("issues")
            issue_n = len(issues) if isinstance(issues, list) else 0
        return verdict, issue_n
    except Exception as exc:
        st.warning(f"Council validation skipped due to error: `{exc}`")
        return "error", 0


def _council_issue_counts(chair: Dict[str, Any]) -> str:
    counts: Dict[str, int] = {}
    for issue in chair.get("issues") or []:
        if isinstance(issue, dict):
            severity = str(issue.get("severity") or "unknown").lower()
        else:
            severity = "unknown"
        counts[severity] = counts.get(severity, 0) + 1
    if not counts:
        return "No issues reported"
    order = ["high", "medium", "low", "unknown"]
    return ", ".join(f"{counts[key]} {key}" for key in order if counts.get(key))


def _render_council_review_result(report: Dict[str, Any], *, label: str = "Council review") -> None:
    chair = report.get("chair") if isinstance(report, dict) else {}
    verdict = str((chair or {}).get("final_verdict") or "unknown")
    if verdict == "pass":
        st.success(f"{label}: pass")
    elif verdict in {"block", "error"}:
        st.error(f"{label}: {verdict}")
    elif verdict == "skipped":
        st.info(f"{label}: skipped until an API key is configured.")
    else:
        st.warning(f"{label}: {verdict}")
    if chair:
        st.caption(f"{_council_issue_counts(chair)} · {len((chair or {}).get('recommended_actions') or [])} recommended action(s).")
    artifact_path = str(report.get("artifact_path") or "")
    if verdict == "skipped" and artifact_path:
        st.caption(f"Council-ready artifact saved: `{artifact_path}`")
    with st.expander(label, expanded=verdict in {"block", "error", "revise"}):
        issues = (chair or {}).get("issues") or []
        if issues:
            st.markdown("**Top issues**")
            for issue in issues[:6]:
                if isinstance(issue, dict):
                    st.write(f"- `{issue.get('severity', 'unknown')}` {issue.get('detail', issue)}")
                else:
                    st.write(f"- {issue}")
        actions = (chair or {}).get("recommended_actions") or []
        if actions:
            st.markdown("**Recommended actions**")
            for action in actions[:6]:
                st.write(f"- {action}")
        st.json(report)


