def _preview_cache_dir() -> str:
    path = os.path.join(os.path.expanduser("~"), ".forager_ai", "preview_cache")
    os.makedirs(path, exist_ok=True)
    return path


def _make_placeholder_image(label: str, *, kind: str = "entry") -> str:
    safe = re.sub(r"[^a-zA-Z0-9_-]+", "_", f"{kind}_{label}")[:80] or "entry"
    path = os.path.join(_preview_cache_dir(), f"placeholder_{safe}.png")
    if os.path.exists(path):
        return path
    img = Image.new("RGBA", (160, 160), (15, 23, 42, 255))
    draw = ImageDraw.Draw(img)
    initials = "".join(part[:1].upper() for part in re.split(r"[_\\s:-]+", label) if part)[:3] or "?"
    draw.rounded_rectangle((8, 8, 152, 152), radius=24, outline=(56, 189, 248, 180), width=3, fill=(30, 41, 59, 255))
    draw.text((80, 80), initials, anchor="mm", fill=(226, 232, 240, 255))
    img.save(path)
    return path


def _cache_preview_image(url: str, cache_key: str, *, size: int = 160) -> Optional[str]:
    if not url or not url.startswith(("http://", "https://")):
        return None
    target_size = max(64, min(int(size or 160), 1024))
    digest = hashlib.sha256(f"{cache_key}:{target_size}:{url}".encode("utf-8")).hexdigest()[:24]
    path = os.path.join(_preview_cache_dir(), f"{digest}.png")
    if os.path.exists(path):
        return path
    try:
        response = _requests_get_with_tls_fallback(
            url,
            timeout=22,
            headers={"User-Agent": "ForagerAI/1.0 (pack thumbnail; +https://github.com/forager-ai)"},
        )
        if response is None or response.status_code >= 400:
            return None
        img = Image.open(io.BytesIO(response.content)).convert("RGBA")
        rs = getattr(getattr(Image, "Resampling", Image), "LANCZOS", getattr(Image, "LANCZOS", Image.BICUBIC))
        img.thumbnail((target_size, target_size), rs)
        canvas = Image.new("RGBA", (target_size, target_size), (12, 12, 16, 255))
        ox = (target_size - img.width) // 2
        oy = (target_size - img.height) // 2
        if img.mode == "RGBA":
            canvas.paste(img, (ox, oy), img.split()[3])
        else:
            canvas.paste(img, (ox, oy))
        canvas.save(path)
        return path
    except Exception:
        return None


def _pil_square_cover_rgba(img: Image.Image, box: int) -> Image.Image:
    """Scale and center-crop to a solid square (matches CSS object-fit: cover in the card)."""
    w, h = img.size
    if w < 1 or h < 1:
        return Image.new("RGBA", (box, box), (12, 12, 16, 255))
    rs = getattr(getattr(Image, "Resampling", Image), "LANCZOS", getattr(Image, "LANCZOS", Image.BICUBIC))
    scale = max(box / w, box / h)
    nw = max(1, int(w * scale + 0.5))
    nh = max(1, int(h * scale + 0.5))
    img = img.resize((nw, nh), rs)
    x0 = (nw - box) // 2
    y0 = (nh - box) // 2
    return img.crop((x0, y0, x0 + box, y0 + box))


def _download_pack_icon_cover_file(url: str, instance_name: str, *, box: int = 512) -> Optional[str]:
    """Download pack art and save as a square cover-cropped PNG (fills the frame, no letterboxing)."""
    safe = safe_http_icon_url(url)
    if not safe:
        return None
    box = max(96, min(int(box), 1024))
    key = re.sub(r"[^a-zA-Z0-9_-]+", "_", instance_name)[:64] or "pack"
    digest = hashlib.sha256(f"cover:{box}:{safe}:{key}".encode("utf-8")).hexdigest()[:26]
    path = os.path.join(_preview_cache_dir(), f"packcover_{digest}.png")
    if os.path.exists(path):
        return path
    try:
        response = _requests_get_with_tls_fallback(
            safe,
            timeout=28,
            headers={"User-Agent": "ForagerAI/1.0 (pack art; +https://github.com/forager-ai)"},
        )
        if response is None or response.status_code >= 400:
            return None
        img = Image.open(io.BytesIO(response.content)).convert("RGBA")
        out = _pil_square_cover_rgba(img, box)
        out.save(path)
        return path
    except Exception:
        return None


def _persist_pack_artwork_to_cache(url: str, instance_name: str) -> Optional[str]:
    """Store remote pack art locally so Streamlit/img can always load it (hotlink/CDN quirks)."""
    return _download_pack_icon_cover_file(url, instance_name, box=512)


def _pil_to_png_base64_for_viewer(img: Image.Image, *, max_dim: int = 256) -> str:
    """Downscale large procedurals so ``components.html`` stays under iframe limits."""
    img = img.convert("RGBA")
    w, h = img.size
    m = max(w, h, 1)
    if m > max_dim:
        scale = max_dim / float(m)
        nw = max(1, int(w * scale))
        nh = max(1, int(h * scale))
        resample = getattr(Image, "Resampling", Image).LANCZOS
        img = img.resize((nw, nh), resample)
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return base64.b64encode(buf.getvalue()).decode("ascii")


def _preview_data_url(path: str, *, target_size: int = 768) -> str:
    target = max(160, min(int(target_size or 768), 1024))
    try:
        img = Image.open(path).convert("RGBA")
        width, height = img.size
        scale = max(1, target // max(width, height, 1))
        out_w = max(1, width * scale)
        out_h = max(1, height * scale)
        if scale > 1:
            resample = getattr(Image, "Resampling", Image).NEAREST
            img = img.resize((out_w, out_h), resample)
        buf = io.BytesIO()
        img.save(buf, format="PNG")
        return "data:image/png;base64," + base64.b64encode(buf.getvalue()).decode("ascii")
    except Exception:
        return ""


def _render_texture_block_preview_css_cube(image_data_url: str, *, key: str, height: int = 370) -> None:
    """CSS-only textured cube (no CDN). Fallback when WebGL / Three.js is disabled or offline."""
    if not image_data_url:
        st.info("3D viewer unavailable for this entry image.")
        return
    safe_bg = html.escape(image_data_url, quote=True)
    viewer_html = f"""
<div style="height:{int(height)}px; border:1px solid rgba(148,163,184,0.28); border-radius:14px; overflow:hidden;
background:radial-gradient(circle at 25% 0%, rgba(15,23,42,0.92), rgba(2,6,23,0.96)); position:relative;">
  <style>
    .forager-cube-scene {{
      width: 100%;
      height: {int(height)}px;
      display:flex;
      align-items:center;
      justify-content:center;
      perspective: 820px;
      cursor: grab;
      user-select: none;
    }}
    .forager-cube {{
      width: 132px;
      height: 132px;
      position: relative;
      transform-style: preserve-3d;
      animation: forager-spin 12s linear infinite;
    }}
    .forager-cube .face {{
      position:absolute;
      width:132px;
      height:132px;
      border: 1px solid rgba(203, 213, 225, 0.42);
      box-shadow: inset 0 0 0 1px rgba(15, 23, 42, 0.68);
      background-image: url('{safe_bg}');
      background-size: cover;
      background-position: center;
      image-rendering: pixelated;
    }}
    .forager-cube .f1 {{ transform: translateZ(66px); }}
    .forager-cube .f2 {{ transform: rotateY(180deg) translateZ(66px); }}
    .forager-cube .f3 {{ transform: rotateY(90deg) translateZ(66px); }}
    .forager-cube .f4 {{ transform: rotateY(-90deg) translateZ(66px); }}
    .forager-cube .f5 {{ transform: rotateX(90deg) translateZ(66px); }}
    .forager-cube .f6 {{ transform: rotateX(-90deg) translateZ(66px); }}
    @keyframes forager-spin {{
      from {{ transform: rotateX(-16deg) rotateY(0deg); }}
      to {{ transform: rotateX(-16deg) rotateY(360deg); }}
    }}
  </style>
  <div class="forager-cube-scene" id="scene-{key}">
    <div class="forager-cube" id="cube-{key}">
      <div class="face f1"></div><div class="face f2"></div><div class="face f3"></div>
      <div class="face f4"></div><div class="face f5"></div><div class="face f6"></div>
    </div>
  </div>
</div>
<script>
(() => {{
  const scene = document.getElementById("scene-{key}");
  const cube = document.getElementById("cube-{key}");
  let dragging = false;
  let x = -16;
  let y = 34;
  let px = 0;
  let py = 0;
  const apply = () => {{
    cube.style.animation = "none";
    cube.style.transform = `rotateX(${{x}}deg) rotateY(${{y}}deg)`;
  }};
  scene.addEventListener("pointerdown", (ev) => {{
    dragging = true;
    px = ev.clientX;
    py = ev.clientY;
    scene.style.cursor = "grabbing";
  }});
  scene.addEventListener("pointermove", (ev) => {{
    if (!dragging) return;
    y += (ev.clientX - px) * 0.35;
    x -= (ev.clientY - py) * 0.35;
    px = ev.clientX;
    py = ev.clientY;
    apply();
  }});
  const stop = () => {{
    dragging = false;
    scene.style.cursor = "grab";
  }};
  scene.addEventListener("pointerup", stop);
  scene.addEventListener("pointerleave", stop);
}})();
</script>
"""
    components.html(viewer_html, height=height + 12, scrolling=False)


def _render_texture_block_3d_viewer(
    image_data_url: str,
    *,
    key: str,
    height: int = 400,
    prefer_webgl: bool = True,
    preview_mode: str = "texture_cube",
) -> None:
    """WebGL preview (bundled Three.js when ``static/vendor/three.min.js`` exists) or CSS cube fallback."""
    if not image_data_url:
        st.info("3D viewer unavailable for this entry image.")
        return
    if prefer_webgl:
        b64 = ""
        if image_data_url.startswith("data:image"):
            m = re.match(r"data:image/[^;]+;base64,(.+)", image_data_url, re.DOTALL)
            if m:
                b64 = re.sub(r"\s+", "", m.group(1))
        if b64:
            dom = re.sub(r"[^a-zA-Z0-9_-]+", "_", key)[:56] or "v"
            dom = dom + "_" + hashlib.sha1(b64[:2048].encode("ascii", errors="ignore")).hexdigest()[:10]
            h = max(220, min(int(height), 900))
            components.html(
                build_threejs_block_preview_html(
                    dom_id=dom,
                    png_base64=b64,
                    height=h,
                    three_script_src=_forager_three_script_src(),
                    preview_mode=preview_mode,
                ),
                height=h + 28,
                scrolling=False,
            )
            st.caption(
                "WebGL · drag to orbit · auto-rotate. "
                "This is a **texture-on-geometry shorthand** (cube or item quad), not full blockstates / entity rigs — "
                "use **Minecraft model UV preview** for ``elements`` meshes from your pack JSON."
            )
            return
    _render_texture_block_preview_css_cube(image_data_url, key=key, height=height)
    st.caption("CSS textured cube fallback (enable WebGL for lighting + orbit controls)")


def _render_pack_model_json_uv_preview(instance: MinecraftInstance, active_pack: str) -> None:
    """Preview ``assets/.../models/*.json`` with UV-aware mesh or ``item/generated`` quad when resolvable."""
    pd = _active_resource_pack_dir(active_pack)
    if not pd or not (pd / "assets").is_dir():
        st.caption("Pack assets folder not found.")
        return
    jsons = sorted((pd / "assets").rglob("models/**/*.json"))
    jsons = [p for p in jsons if p.is_file()][:140]
    if not jsons:
        st.caption("No `assets/.../models/*.json` files yet.")
        return
    labs = [str(p.relative_to(pd)) for p in jsons]
    ji = int(
        st.selectbox(
            "Model JSON",
            list(range(len(jsons))),
            format_func=lambda i: labs[i],
            key=f"cfg_tex_model_json_{instance.name}",
        )
    )
    path = jsons[ji]
    model = load_model_json(path)
    if not model:
        st.warning("Could not parse JSON.")
        return
    resolved = resolve_model_for_preview(model, pd)
    kind = infer_model_preview_kind(resolved)
    st.caption(
        f"Detected **{kind}** (after **parent chain** resolve). "
        "UV mesh: axis-aligned `elements`, face `uv`, and face `rotation` in 90° steps. "
        "`item/generated`-style parents use a textured quad. Unknown parents still need pack JSON or Blockbench."
    )
    tex_path = resolve_texture_path_from_model(resolved, pack_root=pd)
    if not tex_path or not tex_path.is_file():
        st.warning("Could not resolve a texture PNG from the model `textures` map under this pack.")
        return
    tw, th = texture_dimensions_from_png(tex_path)
    du = _preview_data_url(str(tex_path), target_size=min(768, max(tw, th, 16)))
    b64_match = re.match(r"data:image/[^;]+;base64,(.+)", du, re.DOTALL)
    b64_only = re.sub(r"\s+", "", b64_match.group(1)) if b64_match else ""
    if not b64_only:
        st.warning("Texture encoding failed.")
        return
    wg = st.checkbox("WebGL preview", value=True, key=f"cfg_tex_model_wg_{instance.name}")
    if not wg:
        st.image(str(tex_path), caption="Resolved texture (enable WebGL for 3D)", use_container_width=True)
        return
    dom_safe = "mdl_" + hashlib.sha1(str(path).encode("utf-8", errors="replace")).hexdigest()[:18]
    three_src = _forager_three_script_src()
    h = 420
    if kind == "item_plane":
        components.html(
            build_threejs_block_preview_html(
                dom_id=dom_safe + "_ip",
                png_base64=b64_only,
                height=h,
                three_script_src=three_src,
                preview_mode="item_plane",
            ),
            height=h + 28,
            scrolling=False,
        )
        st.caption("`item/generated`-style quad with resolved layer texture.")
        return
    mesh = mesh_from_java_model(resolved, texture_width=tw, texture_height=th)
    if mesh:
        components.html(
            build_threejs_uv_mesh_preview_html(
                dom_id=dom_safe + "_uv",
                mesh=mesh,
                png_base64=b64_only,
                height=h,
                three_script_src=three_src,
            ),
            height=h + 28,
            scrolling=False,
        )
        st.caption(f"UV mesh from model elements · texture {tw}×{th}")
    else:
        st.caption(
            "No UV mesh from `elements` (parent-only, rotations, or empty faces) — **textured cube** fallback using the resolved PNG."
        )
        components.html(
            build_threejs_block_preview_html(
                dom_id=dom_safe + "_fb",
                png_base64=b64_only,
                height=h,
                three_script_src=three_src,
                preview_mode="texture_cube",
            ),
            height=h + 28,
            scrolling=False,
        )


def _render_texture_model_viewer(image_data_url: str, *, key: str, height: int = 370) -> None:
    """Back-compat wrapper: WebGL when possible."""
    _render_texture_block_3d_viewer(image_data_url, key=key, height=height, prefer_webgl=True)


def _render_desktop_capture_vision_ui(
    *,
    key_root: str,
    api_key: str,
    default_vision_model: str = "openai/gpt-4o-mini",
) -> None:
    from datetime import datetime, timezone

    if not capture_supported():
        st.caption("Desktop screenshot (vision) is only enabled on Windows when Pillow supports screen capture.")
        return
    vmodel_key = f"{key_root}_vmodel"
    vfocus_key = f"{key_root}_vfocus"
    if vmodel_key not in st.session_state:
        st.session_state[vmodel_key] = default_vision_model
    if vfocus_key not in st.session_state:
        st.session_state[vfocus_key] = ""
    with st.expander("Desktop screenshot (Windows, one-shot)", expanded=False):
        st.caption(
            "Captures what is on screen (all monitors as one image when supported). "
            "Do not run in front of secrets; click Discard before leaving."
        )
        capt_key = f"{key_root}_cap_bytes"
        note_key = f"{key_root}_cap_note"
        c1, c2 = st.columns(2)
        if c1.button("Capture screen", key=f"{key_root}_capture_btn", use_container_width=True):
            try:
                data, mime = capture_primary_screen_png()
                st.session_state[capt_key] = data
                st.session_state[note_key] = (
                    f"{mime}, {len(data) // 1024} KB — {datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M UTC')}"
                )
            except Exception as cap_err:
                st.warning(f"Capture failed: {cap_err}")
        if c2.button("Discard screenshot", key=f"{key_root}_discard_capture", use_container_width=True):
            st.session_state.pop(capt_key, None)
            st.session_state.pop(note_key, None)
        cap_bytes = st.session_state.get(capt_key)
        if cap_bytes:
            st.image(io.BytesIO(cap_bytes), use_container_width=True, caption=st.session_state.get(note_key, ""))
        vmod = st.text_input(
            "Vision model (OpenRouter, must support images)",
            key=vmodel_key,
        )
        focus = st.text_area(
            "What should the model focus on?",
            key=vfocus_key,
            height=90,
            placeholder="e.g. read launcher errors, summarize visible mod list, describe the crash dialog",
        )
        if st.button(
            "Run vision pass",
            key=f"{key_root}_vision_run",
            disabled=not bool(cap_bytes and api_key and focus.strip()),
            use_container_width=True,
        ):
            user_text = focus.strip()
            sys_msg = (
                "You are helping a Minecraft modpack maintainer using Forager AI. "
                "Describe on-screen UI and any readable text; do not invent mod names not visible."
            )
            with st.spinner("Calling vision model…"):
                try:
                    result = chat_completion_with_images(
                        api_key=api_key,
                        model=vmod.strip() or default_vision_model,
                        system_prompt=sys_msg,
                        user_text=user_text,
                        images_png=[cap_bytes],
                        temperature=0.2,
                        max_tokens=1200,
                    )
                    st.markdown(result)
                except Exception as vis_err:
                    st.error(str(vis_err))


def _atlas_preview_path(
    entry: Dict[str, Any],
    mc_catalog: Dict[str, List[Dict[str, Any]]],
    *,
    pack_root: Optional[str] = None,
) -> str:
    entry_id = str(entry.get("id") or entry.get("file") or "entry")
    local_image = str(entry.get("image_path") or entry.get("image_file") or "").strip()
    if local_image and Path(local_image).is_file():
        return local_image
    if pack_root and str(entry.get("type") or "") == "mod_jar":
        jar_file = str(entry.get("file") or "").strip()
        mod_id = str(entry.get("mod_id") or entry_id).strip("_:") or "mod"
        if jar_file:
            jar_path = Path(pack_root) / "mods" / jar_file
            if jar_path.is_file():
                from forager_ai.catalog import indexer as catalog_indexer

                extractor = getattr(catalog_indexer, "extract_jar_preview_image", None)
                extracted = extractor(pack_root, str(jar_path), mod_id) if callable(extractor) else ""
                if extracted and Path(extracted).is_file():
                    entry["image_path"] = extracted
                    return extracted
    remote_image = str(entry.get("image") or entry.get("icon_url") or entry.get("remote_icon_url") or "").strip()
    if remote_image.startswith(("http://", "https://")):
        cached_remote = _cache_preview_image(remote_image, entry_id)
        if cached_remote:
            return cached_remote
    lookup_id = entry_id.split(":", 1)[-1].replace("_spawn_egg", "")
    candidates: List[Dict[str, Any]] = []
    for bucket in ("items", "blocks", "mobs", "structures"):
        candidates.extend(mc_catalog.get(bucket) or [])
    for row in candidates:
        rid = str(row.get("id") or "").split(":", 1)[-1]
        if rid == lookup_id or str(row.get("displayName") or "").lower().replace(" ", "_") == lookup_id:
            cached = _cache_preview_image(str(row.get("image") or row.get("image_fallback") or ""), entry_id)
            if cached:
                return cached
    return _make_placeholder_image(str(entry.get("displayName") or entry_id), kind=str(entry.get("type") or "entry"))


def _validated_atlas_preview_path(
    entry: Dict[str, Any],
    mc_catalog: Dict[str, List[Dict[str, Any]]],
    *,
    pack_root: Optional[str] = None,
) -> str:
    """Like ``_atlas_preview_path`` but guaranteed decodable by Pillow (placeholder on bad/missing files)."""
    label = str(entry.get("displayName") or entry.get("id") or entry.get("file") or "entry")
    kind = str(entry.get("type") or "entry")
    try:
        raw = _atlas_preview_path(entry, mc_catalog, pack_root=pack_root)
    except Exception:
        return _make_placeholder_image(label, kind=kind)
    if not raw or not isinstance(raw, str):
        return _make_placeholder_image(label, kind=kind)
    try:
        p = Path(raw)
        if not p.is_file():
            return _make_placeholder_image(label, kind=kind)
        with Image.open(p) as im:
            im.load()
        return str(p)
    except Exception:
        return _make_placeholder_image(label, kind=kind)


def _validated_disk_image_path(path: Optional[str], *, label: str, kind: str = "entry") -> str:
    """Ensure ``path`` is a readable raster; otherwise return a slate placeholder."""
    if not path or not isinstance(path, str):
        return _make_placeholder_image(label, kind=kind)
    try:
        p = Path(path)
        if not p.is_file():
            return _make_placeholder_image(label, kind=kind)
        with Image.open(p) as im:
            im.load()
        return str(p)
    except Exception:
        return _make_placeholder_image(label, kind=kind)


def render_resource_packs_workspace(
    *,
    heading: str,
    key_prefix: str,
    intro_headline: str | None = None,
    intro_lede: str | None = None,
    intro_anchor: str = "resource_packs",
) -> None:
    """Create/import resource packs + AI blueprint studio (Java edition). Namespace = mod / vanilla."""
    section_title(heading, "")
    if intro_headline:
        forager_page_intro(anchor=intro_anchor, headline=intro_headline, lede=intro_lede)
    packs = content_manager.list_resource_packs()
    c1, c2 = st.columns(2)
    with c1:
        st.subheader("Create pack")
        rp_name = st.text_input("Pack name", key=f"{key_prefix}_pack_name")
        rp_desc = st.text_input("Description", key=f"{key_prefix}_pack_desc")
        rp_author = st.text_input("Author", value="Forager AI", key=f"{key_prefix}_pack_author")
        if st.button("Create pack", key=f"{key_prefix}_create_pack"):
            if not rp_name.strip():
                st.warning("Pack name is required.")
            else:
                pack = content_manager.create_resource_pack(
                    name=rp_name.strip(),
                    description=rp_desc.strip() or f"{rp_name.strip()} resources",
                    author=rp_author.strip() or "Forager AI",
                )
                st.success(f"Created resource pack `{pack.name}`.")

        st.subheader("Import")
        import_path = st.text_input("Path to .zip or folder", key=f"{key_prefix}_import_path")
        if st.button("Import pack", key=f"{key_prefix}_import_pack"):
            imported = content_manager.import_resource_pack(import_path.strip())
            if imported:
                st.success(f"Imported `{imported.name}`.")
            else:
                st.error("Import failed. Verify path and pack.mcmeta.")

    with c2:
        st.subheader("Packs")
        if not packs:
            st.info("No resource packs yet — create or import one.")
        else:
            selected_rp = st.selectbox(
                "Active pack",
                [p.name for p in packs],
                key=f"{key_prefix}_selected_rp",
            )
            stats = content_manager.get_pack_statistics(selected_rp)
            st.write(f"Files: `{stats.get('total_files', 0)}` · Textures: `{stats.get('texture_files', 0)}` · "
                     f"Anim: `{stats.get('animated_textures', 0)}` · Size: `{stats.get('total_size_mb', 0)} MB`")
            if st.button("Scan textures", key=f"{key_prefix}_scan_textures"):
                textures = content_manager.scan_pack_textures(selected_rp)
                st.write(f"Found `{len(textures)}` textures.")

    st.divider()
    st.subheader("AI resource studio")
    st.caption(
        "Minecraft **resource packs** (textures, models, block animations, sound hooks). "
        "AI outputs a blueprint; Apply writes placeholders + JSON. Final PNG/OGG: add yourself or use `.forager/image_prompts.json`."
    )
    if packs:
        ai_pack = st.selectbox("Pack for AI", [p.name for p in packs], key=f"{key_prefix}_ai_pack")
        pack_obj_wp = content_manager.get_resource_pack(ai_pack)
        if pack_obj_wp:
            with st.expander("Particle stub (vanilla JSON + PNG)", expanded=False):
                st.caption(
                    "Writes `assets/<ns>/particles/<id>.json` plus a small placeholder texture. "
                    "Hooking it into mod-specific spells or events is still manual."
                )
                _pns = st.text_input("Namespace", value="forager_ai", key=f"{key_prefix}_pw_ns")
                _pid = st.text_input("Particle id", value="sparkle", key=f"{key_prefix}_pw_id")
                _ptx = st.text_input("Texture path (under textures/, no .png)", value="particle/sparkle", key=f"{key_prefix}_pw_tex")
                if st.button("Write particle files", key=f"{key_prefix}_pw_apply"):
                    rels, msg = write_vanilla_particle_stub(
                        pack_obj_wp.path,
                        namespace=_pns.strip() or "forager_ai",
                        particle_id=_pid.strip() or "sparkle",
                        texture_subpath=_ptx.strip() or "particle/sparkle",
                    )
                    st.success(msg)
                    st.text("\n".join(rels))
            with st.expander("Blockbench model summary (.bbmodel upload)", expanded=False):
                st.caption("Upload a `.bbmodel` JSON export for a compact text summary (useful before pasting into AI prompts).")
                up_bb = st.file_uploader("bbmodel file", type=["bbmodel", "json"], key=f"{key_prefix}_bb_upload")
                if up_bb is not None:
                    try:
                        raw_js = json.loads(up_bb.getvalue().decode("utf-8"))
                        if isinstance(raw_js, dict):
                            st.text(summarize_bbmodel(raw_js))
                        else:
                            st.warning("Root must be a JSON object.")
                    except json.JSONDecodeError as exc:
                        st.error(f"Invalid JSON: {exc}")
        assets = content_manager.index_pack_assets(ai_pack)
        if assets:
            try:
                import pandas as pd

                ns_opts = sorted({a["namespace"] for a in assets})
                filt = st.multiselect(
                    "Namespaces (mod sources)",
                    ns_opts,
                    default=ns_opts,
                    key=f"{key_prefix}_ai_ns",
                )
                view = [a for a in assets if a["namespace"] in filt]
                st.dataframe(
                    pd.DataFrame(view).head(5000),
                    use_container_width=True,
                    height=min(340, 80 + min(len(view), 25) * 28),
                )
            except Exception:
                st.json(assets[:400])
        else:
            st.caption("No `assets/` tree yet — Apply will create folders.")

        theme = content_manager.load_theme_manifest(ai_pack)
        if theme:
            with st.expander("Theme (.forager/theme.json)", expanded=False):
                st.json(theme)

        rp_prompt = st.text_area(
            "Theme / goals",
            height=100,
            key=f"{key_prefix}_rp_prompt",
            placeholder="e.g. dieselpunk retexture; animated gauge; block break SFX hook.",
        )
        g1, g2, g3 = st.columns(3)
        with g1:
            gen_rp = st.button("Generate AI blueprint", key=f"{key_prefix}_gen_rp")
        with g2:
            apply_rp = st.button("Apply blueprint to pack", key=f"{key_prefix}_apply_rp", type="primary")
        with g3:
            if st.button("Clear session plan", key=f"{key_prefix}_clear_rp"):
                st.session_state.pop("forager_rp_plan", None)
                st.rerun()

        api_rp = launcher.config.get("openrouter_api_key", "")
        model_rp = resolve_ai_model(launcher.config)

        if gen_rp:
            if not api_rp.strip():
                st.error("Set OpenRouter API key in Settings.")
            elif not (rp_prompt or "").strip():
                st.warning("Enter a theme or goals first.")
            else:
                with st.spinner("Generating resource pack plan…"):
                    try:
                        st.session_state["forager_rp_plan"] = generate_resource_pack_plan(
                            api_key=api_rp,
                            user_request=rp_prompt,
                            existing_assets_summary=assets,
                            model=model_rp,
                        )
                        st.success("Blueprint ready — review JSON, then Apply.")
                    except Exception as exc:
                        st.error(str(exc))

        plan = st.session_state.get("forager_rp_plan")
        if isinstance(plan, dict) and plan:
            with st.expander("Blueprint (JSON)", expanded=False):
                st.json(plan)

        if apply_rp:
            if not isinstance(plan, dict) or not plan:
                st.warning("Generate a blueprint first.")
            else:
                with st.spinner("Writing assets…"):
                    rep = content_manager.apply_ai_resource_plan(ai_pack, plan)
                    pack_obj = content_manager.get_resource_pack(ai_pack)
                    if pack_obj:
                        review = _run_quality_council_review(
                            pack_root=pack_obj.path,
                            pack_name=ai_pack,
                            title=f"Resource pack blueprint apply: {ai_pack}",
                            artifact_type="forager_resource_pack_apply",
                            subject=f"Resource pack apply: {ai_pack}",
                            payload={"blueprint": plan, "apply_report": rep},
                        )
                        _render_council_review_result(review, label="Resource pack Council review")
                    paths = rep.get("created") or []
                    if paths:
                        with st.expander(f"Created {len(paths)} paths", expanded=False):
                            st.text("\n".join(paths))
                    for w in rep.get("warnings") or []:
                        st.warning(w)
                    st.success("Apply finished.")
    else:
        st.info("Create a resource pack first.")


def _fmt_downloads(n: Optional[int]) -> str:
    if n is None:
        return "—"
    if n >= 1_000_000:
        return f"{n / 1_000_000:.1f}M"
    if n >= 1_000:
        return f"{n / 1_000:.1f}K"
    return str(n)


def _fmt_mod_date(s: Optional[str]) -> str:
    if not s:
        return "—"
    t = str(s).strip()
    return t[:10] if len(t) >= 10 else t


def _fmt_mod_updated_relative(s: Optional[str]) -> str:
    """Short relative label for catalog footers (e.g. '7 days ago'); falls back to trimmed raw."""
    if not s:
        return "—"
    raw = str(s).strip()
    try:
        from datetime import date, datetime

        d = None
        if "T" in raw:
            iso = raw.replace("Z", "+00:00")
            try:
                d = datetime.fromisoformat(iso).date()
            except ValueError:
                try:
                    d = datetime.strptime(raw[:19], "%Y-%m-%dT%H:%M:%S").date()
                except ValueError:
                    d = None
        if d is None and len(raw) >= 10 and raw[4] == "-" and raw[7] == "-":
            d = datetime.strptime(raw[:10], "%Y-%m-%d").date()
        if d is None:
            return raw[:16] if raw else "—"
        diff = (date.today() - d).days
        if diff < 0:
            return "just updated"
        if diff == 0:
            return "today"
        if diff == 1:
            return "1 day ago"
        if diff < 14:
            return f"{diff} days ago"
        if diff < 60:
            wk = max(1, diff // 7)
            return f"{wk} wk ago" if wk == 1 else f"{wk} wks ago"
        if diff < 365:
            mo = max(1, round(diff / 30))
            return f"{mo} mo ago"
        yr = diff // 365
        return f"{yr} yr ago" if yr == 1 else f"{yr} yrs ago"
    except (ValueError, TypeError, OSError):
        return raw[:16] if raw else "—"


def _mods_row_updated_within_days(s: Optional[str], *, days: int) -> bool:
    """Best-effort parse of API date strings for catalog ribbon hints."""
    if not s or days < 1:
        return False
    t = str(s).strip()[:10]
    if len(t) < 10:
        return False
    try:
        from datetime import date, datetime

        d = datetime.strptime(t, "%Y-%m-%d").date()
        return (date.today() - d).days <= days
    except ValueError:
        return False


def _modpack_estimate_ram_mb(
    *,
    mods_count: int = 0,
    size_mb: float = 0.0,
    file_size_bytes: int = 0,
) -> int:
    """Heuristic JVM heap need from mod count and on-disk / primary-file footprint."""
    file_mb = max(0.0, file_size_bytes / (1024 * 1024)) if file_size_bytes else 0.0
    footprint_mb = max(float(size_mb or 0), file_mb)
    mods = max(0, int(mods_count or 0))
    if mods or footprint_mb > 0:
        return int(2048 + mods * 14 + footprint_mb * 0.22)
    if file_mb >= 800:
        return int(6144 + file_mb * 0.15)
    if file_mb >= 350:
        return 5120
    if file_mb >= 120:
        return 4096
    return 3072


def _modpack_runnability_tier(
    *,
    default_memory_mb: int,
    java_count: int,
    mods_count: int = 0,
    size_mb: float = 0.0,
    file_size_bytes: int = 0,
    mc_version: Optional[str] = None,
    mc_versions: Optional[List[str]] = None,
    loader: Optional[str] = None,
    loaders: Optional[List[str]] = None,
    mc_filter: Optional[str] = None,
    loader_filter: Optional[str] = None,
) -> Tuple[str, str]:
    """Return ``green`` | ``yellow`` | ``orange`` | ``red`` plus a tooltip reason."""
    notes: List[str] = []
    est = _modpack_estimate_ram_mb(
        mods_count=mods_count,
        size_mb=size_mb,
        file_size_bytes=file_size_bytes,
    )
    try:
        dm = max(512, int(default_memory_mb or 4096))
    except (TypeError, ValueError):
        dm = 4096

    ratio = (dm / est) if est > 0 else 1.0

    if java_count <= 0:
        notes.append("No Java installation detected on this machine.")
    if dm < 2048:
        notes.append(f"Default heap {dm} MB is below a safe minimum for modded play.")

    if java_count <= 0 or dm < 2048 or ratio < 0.72:
        tier = "red"
    elif ratio < 0.88:
        tier = "orange"
    elif ratio < 1.0:
        tier = "yellow"
    else:
        tier = "green"

    if tier == "green" and mods_count >= 400 and ratio < 1.15:
        tier = "yellow"
        notes.append(f"Large mod count ({mods_count}) — expect longer loads even with enough heap.")
    elif tier in ("green", "yellow") and mods_count >= 280 and dm < 6144:
        tier = "yellow" if tier == "green" else "orange"
        notes.append(f"{mods_count} mods with {dm} MB heap may feel tight.")

    mf = (mc_filter or "").strip()
    if mf:
        pack_mcs = [str(v).strip() for v in (mc_versions or []) if str(v).strip()]
        if mc_version and not pack_mcs:
            pack_mcs = [str(mc_version).strip()]
        if pack_mcs and not any(mf in mc or mc.startswith(mf) for mc in pack_mcs):
            notes.append(
                f"Toolbar MC {mf} may not match pack versions ({', '.join(pack_mcs[:3])})."
            )
        elif not pack_mcs and mc_version and mf not in str(mc_version):
            notes.append(f"Pack MC {mc_version} differs from toolbar filter {mf}.")

    lf = (loader_filter or "").strip().lower()
    if lf and lf != "vanilla":
        pack_ld = [str(x).strip().lower() for x in (loaders or []) if str(x).strip()]
        if loader and not pack_ld:
            pack_ld = [str(loader).strip().lower()]
        if pack_ld and lf not in pack_ld:
            notes.append(
                f"Toolbar loader {lf} not listed for this pack ({', '.join(pack_ld[:3])})."
            )

    tier_blurb = {
        "green": f"Should run well — default heap {dm} MB vs ~{est} MB estimated for this pack.",
        "yellow": f"Should run — default heap {dm} MB is close to ~{est} MB estimated; close other apps if needed.",
        "orange": f"Marginal — default heap {dm} MB is below ~{est} MB estimated; raise RAM in Settings.",
        "red": f"Unlikely to run well — default heap {dm} MB is well below ~{est} MB estimated for this pack.",
    }[tier]
    if notes:
        return tier, f"{tier_blurb} {' '.join(notes)}"
    return tier, tier_blurb


def _modpack_runnability_ctx(launcher: Any) -> Dict[str, Any]:
    """Launcher + system snapshot for card-level runnability (one scan per page render)."""
    try:
        default_memory = int(launcher.config.get("default_memory") or 4096)
    except (TypeError, ValueError):
        default_memory = 4096
    java_installations = getattr(getattr(launcher, "version_manager", None), "java_installations", None) or []
    if not java_installations:
        try:
            java_installations = launcher.version_manager.scan_java_installations()
        except Exception:
            java_installations = []
    return {
        "default_memory_mb": default_memory,
        "java_count": len(java_installations),
    }


def _modpack_runnability_chip_html(tier: str, tooltip: str) -> str:
    tier_lc = str(tier or "green").lower()
    if tier_lc not in ("green", "yellow", "orange", "red"):
        tier_lc = "green"
    short = {"green": "Good", "yellow": "Fair", "orange": "Tight", "red": "Low RAM"}[tier_lc]
    tip = html.escape(str(tooltip or ""), quote=True)
    return (
        f'<span class="forager-run-indicator forager-run-{tier_lc}" title="{tip}" '
        f'aria-label="{html.escape(short)}: {tip}">'
        f'<span class="forager-run-dot" aria-hidden="true"></span></span>'
    )


def _mods_catalog_row_ribbons_html(mod: ModInfo) -> str:
    """Small heuristic badges (never sponsored)."""
    bits: List[str] = []
    try:
        dl = int(mod.download_total or 0)
    except (TypeError, ValueError):
        dl = 0
    if dl >= 800_000:
        bits.append('<span class="forager-mod-ribbon forager-mod-ribbon--popular">Popular</span>')
    if _mods_row_updated_within_days(mod.updated_at, days=14):
        bits.append('<span class="forager-mod-ribbon forager-mod-ribbon--fresh">Fresh</span>')
    if not bits:
        return ""
    return '<div class="forager-mod-ribbons">' + "".join(bits) + "</div>"


def _trusted_icon_url(u: Optional[str]) -> Optional[str]:
    if not u:
        return None
    t = str(u).strip()
    if t.startswith("https://"):
        return t
    if t.startswith("http://"):
        return t
    return None


def _modrinth_browse_url(query: str, mc_ver: str, loader: str, catalog_kind: str = "mods") -> str:
    """Best-effort Modrinth listing URL from current dashboard filters."""
    ck = (catalog_kind or "mods").strip().lower()
    base_paths = {
        "mods": "https://modrinth.com/mods",
        "resourcepack": "https://modrinth.com/resourcepacks",
        "shader": "https://modrinth.com/shaders",
        "datapack": "https://modrinth.com/datapacks",
        "modpack": "https://modrinth.com/modpacks",
    }
    base = base_paths.get(ck, base_paths["mods"])
    params: List[tuple[str, str]] = []
    q = (query or "").strip()
    if q:
        params.append(("q", q))
    gv = (mc_ver or "").strip()
    if gv:
        params.append(("g", gv))
    lo = (loader or "").strip().lower()
    if lo and lo != "vanilla" and ck in ("mods", "modpack"):
        params.append(("l", lo))
    if params:
        return base + "?" + urlencode(params)
    return base


def _curseforge_browse_url(query: str, mc_ver: str, catalog_kind: str = "mods") -> str:
    """Best-effort CurseForge web search URL (not the API — usable without a key)."""
    ck = (catalog_kind or "mods").strip().lower()
    class_slug = {
        "mods": "mc-mods",
        "resourcepack": "texture-packs",
        "shader": "mc-mods",
        "datapack": "mc-mods",
        "modpack": "modpacks",
    }.get(ck, "mc-mods")
    pairs: List[tuple[str, str]] = [("page", "1"), ("class", class_slug)]
    q = (query or "").strip()
    if q:
        pairs.append(("search", q))
    gv = (mc_ver or "").strip()
    if gv:
        pairs.append(("gameVersion", gv))
    return "https://www.curseforge.com/minecraft/search?" + urlencode(pairs)


def _mod_browser_card_html(
    mod: ModInfo,
    *,
    installed_jar_filename: Optional[str] = None,
    layout: str = "list",
    run_ctx: Optional[Dict[str, Any]] = None,
) -> str:
    layout_lc = (layout or "list").strip().lower()
    grid = layout_lc == "grid"
    icon = _trusted_icon_url(mod.icon_url)
    icon_inner = (
        f'<img class="forager-mod-icon" src="{html.escape(icon)}" alt="" loading="lazy" />'
        if icon
        else '<div class="forager-mod-icon"></div>'
    )
    ribbons = _mods_catalog_row_ribbons_html(mod)
    icon_block = f'<div class="forager-mod-thumb-wrap">{ribbons}{icon_inner}</div>'
    installed_pill = ""
    local_inst = ""
    if installed_jar_filename:
        pf = html.escape(str(installed_jar_filename))
        installed_pill = '<span class="forager-mod-installed-pill">Installed</span>'
        local_inst = (
            f'<span class="forager-mod-local-jar">matches <span class="forager-mod-local-jar-filename">{pf}</span></span>'
        )
    title = html.escape(mod.name or "")
    author = html.escape(mod.author or "")
    desc_raw = (mod.description or "").replace("\n", " ").strip()
    if grid:
        if len(desc_raw) > 120:
            desc_raw = desc_raw[:117] + "..."
    elif len(desc_raw) > 280:
        desc_raw = desc_raw[:277] + "..."
    desc = html.escape(desc_raw)
    loaders = list(mod.loaders or [])
    dl = _fmt_downloads(mod.download_total)
    gvers = mod.minecraft_versions or []
    gv_title = html.escape(", ".join(str(v) for v in gvers), True) if gvers else ""
    sz_raw = mod.file_size
    try:
        sz_i = int(sz_raw) if sz_raw is not None else 0
    except (TypeError, ValueError):
        sz_i = 0
    local_row = f'<div class="forager-mod-local-row">{local_inst}</div>' if local_inst else ""
    title_html = (
        f'<div class="forager-mod-titleline">'
        f'<span class="forager-mod-title" title="{html.escape(mod.name or "", True)}">{title}</span>'
        f'<span class="forager-mod-by">by {author or "—"}</span>'
        f"{installed_pill}"
        f"</div>"
    )
    rel_when_txt = _fmt_mod_updated_relative(mod.updated_at)
    rel_when = html.escape(rel_when_txt)
    _cat_list = [str(c).strip() for c in (mod.categories or []) if str(c).strip()]
    _cat_esc = [html.escape(c) for c in _cat_list]
    _tag_sep = '<span class="forager-mod-footer-tag-sep"> | </span>'
    cat_pipe_html = _tag_sep.join(_cat_esc) if _cat_esc else ""
    cat_full_title = html.escape(", ".join(_cat_list), True)
    abs_date_snip = _fmt_mod_date(mod.updated_at)
    abs_date_tt = html.escape(abs_date_snip, True)
    stat_sep = '<span class="forager-mod-footer-stat-sep" aria-hidden="true">|</span>'
    stat_parts: List[str] = []
    if run_ctx is not None:
        _rtier, _rtip = _modpack_runnability_tier(
            default_memory_mb=int(run_ctx.get("default_memory_mb") or 4096),
            java_count=int(run_ctx.get("java_count") or 0),
            file_size_bytes=sz_i,
            mc_versions=gvers,
            loaders=loaders,
            mc_filter=str(run_ctx.get("mc_filter") or ""),
            loader_filter=str(run_ctx.get("loader_filter") or ""),
        )
        stat_parts.append(_modpack_runnability_chip_html(_rtier, _rtip))
    stat_parts.extend(
        [
            f'<span class="forager-mod-footer-stat" title="Total downloads">⬇ {html.escape(dl)}</span>',
            f'<span class="forager-mod-footer-stat" title="Last updated {abs_date_tt}">🕐 {rel_when}</span>',
        ]
    )
    if sz_i > 0:
        stat_parts.append(
            f'<span class="forager-mod-footer-stat" title="Primary file size">💾 {html.escape(_fmt_jar_size(sz_i))}</span>'
        )
    mc_tt = gv_title if gv_title else html.escape("No Minecraft version list on this catalog row", True)
    mc1_disp = html.escape(str(gvers[0])) if gvers else "—"
    stat_parts.append(f'<span class="forager-mod-footer-stat" title="{mc_tt}">🎮 {mc1_disp}</span>')
    if loaders:
        ld1 = html.escape(str(loaders[0]).title())
        ld_all = html.escape(" · ".join(str(x) for x in loaders), True)
        stat_parts.append(f'<span class="forager-mod-footer-stat" title="{ld_all}">◇ {ld1}</span>')
    else:
        stat_parts.append('<span class="forager-mod-footer-stat" title="Loaders">◇ —</span>')
    stats_row_html = stat_sep.join(stat_parts)
    tags_cell = (
        f'<span class="forager-mod-footer-muted">{html.escape("No category tags")}</span>'
        if not cat_pipe_html
        else cat_pipe_html
    )

    def _catalog_row_footer(extra_cls: str) -> str:
        return (
            f'<div class="forager-mod-catalog-row-footer{extra_cls}">'
            f'<div class="forager-mod-catalog-row-footer-tags" title="{cat_full_title}">{tags_cell}</div>'
            f'<div class="forager-mod-catalog-row-footer-stats">{stats_row_html}</div>'
            "</div>"
        )

    if grid:
        parts: List[str] = [
            '<div class="forager-mod-row forager-mod-row--compact forager-mod-row--cf forager-mod-row--grid">',
            '<div class="forager-mod-grid-card">',
            '<div class="forager-mod-thumb-col forager-mod-thumb-col--grid">',
            icon_block,
            "</div>",
            '<div class="forager-mod-main-col forager-mod-main-col--grid">',
            title_html,
            local_row,
            f'<p class="forager-mod-desc forager-mod-desc--grid">{desc}</p>',
            _catalog_row_footer(" forager-mod-catalog-row-footer--grid"),
            "</div>",
            "</div>",
            "</div>",
        ]
        return "".join(p for p in parts if p)
    parts = [
        '<div class="forager-mod-row forager-mod-row--compact forager-mod-row--cf">',
        '<div class="forager-mod-thumb-col">',
        icon_block,
        "</div>",
        '<div class="forager-mod-main-col">',
        title_html,
        local_row,
        f'<p class="forager-mod-desc forager-mod-desc--clamp">{desc}</p>',
        _catalog_row_footer(""),
        "</div>",
        "</div>",
    ]
    return "".join(p for p in parts if p)


def _fmt_jar_size(num_bytes: int) -> str:
    if num_bytes >= 1024 * 1024:
        return f"{num_bytes / (1024 * 1024):.2f} MB"
    if num_bytes >= 1024:
        return f"{num_bytes / 1024:.1f} KB"
    return f"{num_bytes} B"


@st.cache_data(ttl=600, max_entries=8192, show_spinner=False)
def _jar_mod_meta_cached(jar_path: str, stat_key: str) -> Dict[str, Any]:
    return read_jar_mod_metadata(jar_path)


def _launcher_cfg_mtime_str(launcher: Any) -> str:
    try:
        return str(int(launcher.config_file.stat().st_mtime))
    except OSError:
        return "0"


@st.cache_data(ttl=1800, max_entries=8192, show_spinner=False)
def _remote_mod_enrich_cached(
    launcher_dir: str,
    cfg_mtime: str,
    mod_id: str,
    display_name: str,
    title: str,
    file_name: str,
    mc_version: str,
    loader: str,
) -> Dict[str, Any]:
    cache_root = os.path.join(launcher_dir, "cache")
    dl = ModDownloader(cache_root)
    cf_key = ""
    cfg_path = Path(launcher_dir) / "launcher_config.json"
    if cfg_path.is_file():
        try:
            with open(cfg_path, encoding="utf-8") as f:
                _cfg = json.load(f)
            cf_key = str(_cfg.get("curseforge_api_key") or "").strip()
        except (json.JSONDecodeError, OSError, TypeError):
            pass
    dl.set_curseforge_api_key(cf_key)
    return resolve_remote_mod_metadata(
        dl,
        mod_id=mod_id,
        display_name=display_name,
        file_stem=title,
        minecraft_version=mc_version or None,
        loader=loader or None,
    )


@st.cache_data(ttl=86400, max_entries=4096, show_spinner=False)
def _ai_mod_blurb_cached(launcher_dir: str, cfg_mtime: str, context_json: str) -> str:
    api_key = ""
    model = DEFAULT_AI_ROUTER_CHAT_MODEL
    cfg_path = Path(launcher_dir) / "launcher_config.json"
    if cfg_path.is_file():
        try:
            with open(cfg_path, encoding="utf-8") as f:
                _cfg = json.load(f)
            api_key = str(_cfg.get("openrouter_api_key") or "").strip()
            model = resolve_ai_model(_cfg)
        except (json.JSONDecodeError, OSError, TypeError):
            pass
    if not api_key:
        return ""
    try:
        ctx = json.loads(context_json)
    except json.JSONDecodeError:
        return ""
    return generate_mod_library_description(api_key=api_key, context=ctx, model=model, timeout_s=55)


def _apply_remote_and_ai_to_entry(
    entry: Dict[str, Any],
    launcher: Any,
    mc_version: str,
    loader: str,
    fetch_remote: bool,
    ai_blurbs: bool,
) -> Dict[str, Any]:
    e = {**entry}
    e.setdefault("remote_icon_url", None)
    e.setdefault("remote_summary", "")
    e.setdefault("remote_project_url", None)
    e.setdefault("remote_source", None)
    e.setdefault("remote_categories", [])

    jar_desc = str(e.get("description") or "").strip()
    logo = str(e.get("logo_data_uri") or "").strip()

    if fetch_remote and (not logo or len(jar_desc) < 55):
        r = _remote_mod_enrich_cached(
            str(launcher.launcher_dir),
            _launcher_cfg_mtime_str(launcher),
            str(e.get("mod_id") or ""),
            str(e.get("display_name") or ""),
            str(e.get("title") or ""),
            str(e.get("file_name") or ""),
            str(mc_version or ""),
            str(loader or ""),
        )
        e["remote_icon_url"] = safe_http_icon_url(r.get("remote_icon_url"))
        e["remote_summary"] = (r.get("remote_summary") or "").strip()
        e["remote_project_url"] = r.get("remote_project_url")
        e["remote_source"] = r.get("remote_source")
        rcats = r.get("remote_categories") or []
        e["remote_categories"] = rcats if isinstance(rcats, list) else []
        tag_set = {str(x).strip() for x in (e.get("tags") or []) if str(x).strip()}
        for c in e["remote_categories"]:
            s = str(c).strip()
            if s and len(s) < 60:
                tag_set.add(s)
        if e.get("remote_source"):
            tag_set.add(str(e["remote_source"]))
        e["tags"] = sorted(tag_set, key=str.lower)

    combined = jar_desc
    if len(combined) < 50 and e.get("remote_summary"):
        combined = str(e.get("remote_summary") or "")

    e["ai_blurb"] = ""
    if ai_blurbs and (launcher.config.get("openrouter_api_key") or "").strip():
        if len(re.sub(r"\s+", " ", combined).strip()) < 140:
            ctx: Dict[str, Any] = {
                "file_name": e.get("file_name"),
                "mod_id": e.get("mod_id"),
                "display_name": e.get("display_name") or e.get("title"),
                "jar_description_excerpt": jar_desc[:650],
                "catalog_summary_excerpt": str(e.get("remote_summary") or "")[:650],
                "catalog_categories": [str(x) for x in (e.get("remote_categories") or [])[:28]],
                "minecraft_version": mc_version,
                "loader": loader,
            }
            ctx_json = json.dumps(ctx, ensure_ascii=True, sort_keys=True)
            e["ai_blurb"] = _ai_mod_blurb_cached(
                str(launcher.launcher_dir),
                _launcher_cfg_mtime_str(launcher),
                ctx_json,
            ).strip()

    return e


def _list_mod_jars(mods_dir: str) -> List[Dict[str, Any]]:
    """List .jar files in a mods folder with size and mtime."""
    out: List[Dict[str, Any]] = []
    root = Path(mods_dir)
    if not root.is_dir():
        return out
    for f in root.iterdir():
        if not f.is_file():
            continue
        if f.suffix.lower() != ".jar":
            continue
        try:
            st = f.stat()
        except OSError:
            continue
        out.append(
            {
                "jar_path": str(f.resolve()),
                "file_name": f.name,
                "title": f.stem,
                "size_bytes": int(st.st_size),
                "mtime_ts": float(st.st_mtime),
                "mtime_iso": datetime.fromtimestamp(st.st_mtime, tz=timezone.utc).strftime("%Y-%m-%d"),
            }
        )
    return out


def _enrich_jar_entry(entry: Dict[str, Any]) -> Dict[str, Any]:
    jp = str(entry.get("jar_path") or "")
    if not jp:
        return entry
    sk = f"{entry.get('mtime_ts', 0)!s}:{entry.get('size_bytes', 0)!s}"
    meta = _jar_mod_meta_cached(jp, sk)
    merged = {**entry}
    for k in ("display_name", "mod_id", "description", "loader_kind", "tags", "logo_data_uri"):
        merged[k] = meta.get(k)
    if not merged.get("tags"):
        merged["tags"] = sorted({"mod", "local jar"}, key=str.lower)
    return merged


def _one_line_desc(raw: str, max_len: int = 220) -> str:
    if not raw:
        return ""
    t = re.sub(r"\s+", " ", html.unescape(str(raw))).strip()
    if len(t) <= max_len:
        return t
    return t[: max_len - 1] + "…"


def _local_mod_row_html(entry: Dict[str, Any]) -> str:
    display = str(entry.get("display_name") or "").strip() or str(entry.get("title") or "")
    title_esc = html.escape(display)
    fn = html.escape(str(entry.get("file_name") or ""))
    sz = html.escape(_fmt_jar_size(int(entry.get("size_bytes") or 0)))
    when = html.escape(str(entry.get("mtime_iso") or ""))
    initial_src = display or str(entry.get("title") or "")
    initial = html.escape((initial_src[:1] or "?").upper())
    stats = f"updated {when} &nbsp;·&nbsp; size {sz}"
    uri = str(entry.get("logo_data_uri") or "").strip()
    r_icon = safe_http_icon_url(entry.get("remote_icon_url"))
    if uri and len(uri) < 70_000:
        icon_block = (
            '<div class="forager-local-mod-icon">'
            f'<img src="{html.escape(uri, quote=True)}" alt="" loading="lazy" />'
            "</div>"
        )
    elif r_icon:
        icon_block = (
            '<div class="forager-local-mod-icon">'
            f'<img src="{html.escape(r_icon, quote=True)}" alt="" loading="lazy" referrerpolicy="no-referrer" />'
            "</div>"
        )
    else:
        icon_block = f'<div class="forager-local-mod-icon"><span>{initial}</span></div>'
    blur = str(entry.get("ai_blurb") or "").strip()
    remote = str(entry.get("remote_summary") or "").strip()
    jar_d = str(entry.get("description") or "").strip()
    desc_pick = blur or remote or jar_d
    desc_raw = _one_line_desc(desc_pick)
    desc_html = (
        f'<p class="forager-mod-desc">{html.escape(desc_raw)}</p>'
        if desc_raw
        else '<p class="forager-mod-desc" style="opacity:0.45;">No description available.</p>'
    )
    tags = entry.get("tags") if isinstance(entry.get("tags"), list) else []
    tag_parts = []
    for t in sorted({str(x).strip() for x in tags if str(x).strip()}, key=str.lower):
        tag_parts.append(f'<span class="forager-mod-cat">{html.escape(t)}</span>')
    tags_html = " ".join(tag_parts) if tag_parts else ""
    sub = fn
    mid = str(entry.get("mod_id") or "").strip()
    if mid and mid.lower() not in fn.lower():
        sub = f"{fn} &nbsp;·&nbsp; <span style=\"color:#6b7280;\">id {html.escape(mid)}</span>"
    rsite = ""
    rp = entry.get("remote_project_url")
    if isinstance(rp, str) and rp.startswith("http"):
        if "modrinth.com" in rp.lower():
            lbl = "Modrinth"
        elif "curseforge.com" in rp.lower():
            lbl = "CurseForge"
        else:
            lbl = "Project page"
        rsite = (
            f'<div><a class="forager-mod-site-link" href="{html.escape(rp, quote=True)}" '
            f'target="_blank" rel="noopener noreferrer">{html.escape(lbl)} →</a></div>'
        )
    return f"""<div class="forager-local-mod-row">
  {icon_block}
  <div class="forager-mod-body">
    <div class="forager-mod-title">{title_esc}</div>
    <div class="forager-mod-meta">{sub}</div>
    {desc_html}
    <div>{tags_html}</div>
    <div class="forager-mod-stats">{stats}</div>
    {rsite}
  </div>
</div>"""


def severity_line(level: str, message: str) -> None:
    level_norm = (level or "low").strip().lower()
    css = "forager-badge-low"
    label = level_norm.upper()
    if level_norm == "high":
        css = "forager-badge-high"
    elif level_norm == "medium":
        css = "forager-badge-medium"
    st.markdown(
        f'<div class="forager-severity-line">'
        f'<span class="forager-badge {css}">{label}</span>'
        f'<span class="forager-severity-line-msg">{message}</span></div>',
        unsafe_allow_html=True,
    )


def power_hero(title: str, body: str) -> None:
    st.markdown(
        f'<div class="forager-page-intro" style="margin-bottom:0.75rem;">'
        f'<p class="forager-page-intro-head">{html.escape(title)}</p>'
        f'<p class="forager-page-intro-lede">{html.escape(body)}</p></div>',
        unsafe_allow_html=True,
    )


def _power_tile_tone_class(tone: str) -> str:
    key = (tone or "ok").strip().lower()
    if key in ("bad", "critical"):
        return "forager-power-tile-bad"
    if key == "warn":
        return "forager-power-tile-warn"
    if key == "muted":
        return "forager-power-tile-muted"
    return "forager-power-tile-ok"


def _health_verdict_tone(health: Dict[str, Any]) -> str:
    verdict = str(health.get("verdict") or "").lower()
    score = health.get("score")
    if verdict == "critical":
        return "bad"
    if verdict in ("risky", "watch", "unknown"):
        return "warn"
    if isinstance(score, (int, float)) and score < 40:
        return "bad"
    if isinstance(score, (int, float)) and score < 75:
        return "warn"
    return "ok"


def _power_lab_alert_class(health: Dict[str, Any]) -> str:
    tone = _health_verdict_tone(health)
    if tone == "bad":
        return "forager-mod-alert forager-mod-alert-critical forager-power-lab-narrative"
    if tone == "warn":
        return "forager-mod-alert forager-mod-alert-warn forager-power-lab-narrative"
    return "forager-mod-alert forager-mod-alert-safe forager-power-lab-narrative"


def _parse_narrative_finding_line(line: str) -> Tuple[Optional[str], str]:
    raw = (line or "").strip()
    m = re.match(r"^[-–]\s*\[(\w+)\]\s*(.+)$", raw)
    if m:
        return m.group(1).lower(), m.group(2).strip()
    return None, raw.lstrip("-–").strip()


def _health_narrative_html(narrative: str, health: Dict[str, Any], *, max_findings: int = 6) -> str:
    lines = [ln.strip() for ln in (narrative or "").splitlines() if ln.strip()]
    if not lines:
        return ""
    lead: List[str] = []
    findings: List[Tuple[Optional[str], str]] = []
    for ln in lines:
        sev, msg = _parse_narrative_finding_line(ln)
        if sev:
            findings.append((sev, msg))
        elif msg:
            lead.append(msg)
    parts = [f'<div class="{_power_lab_alert_class(health)}">']
    for p in lead[:2]:
        parts.append(f'<p class="forager-power-lab-lead">{html.escape(p)}</p>')
    for sev, msg in findings[:max_findings]:
        bcls = _pack_health_badge_class(sev or "low")
        label = (sev or "info").upper()
        parts.append(
            f'<div class="forager-severity-line">'
            f'<span class="forager-badge {bcls}">{html.escape(label)}</span>'
            f'<span class="forager-severity-line-msg">{html.escape(msg)}</span></div>'
        )
    parts.append("</div>")
    return "\n".join(parts)


def _power_lab_tiles_from_context(
    health: Dict[str, Any],
    conflict_summary: Dict[str, Any],
    role_summary: Dict[str, Any],
    progression: Dict[str, Any],
    *,
    friendly: bool = False,
) -> List[Tuple[str, str, str]]:
    score = health.get("score", "?")
    verdict = str(health.get("verdict") or "unknown")
    tc = int((conflict_summary or {}).get("total_conflicts") or 0)
    roles = list((role_summary.get("role_counts") or {}).keys())[:4]
    pf = len((progression or {}).get("findings") or [])
    if friendly:
        _verdict_plain = {
            "critical": "Needs attention",
            "poor": "Needs attention",
            "fair": "Okay",
            "good": "Good",
            "unknown": "Checking",
        }
        vplain = _verdict_plain.get(str(verdict).lower(), str(verdict).replace("_", " ").title())
        return [
            ("Pack health", f"{score}/100 · {vplain}", _health_verdict_tone(health)),
            ("Issues found", f"{tc} item{'s' if tc != 1 else ''}" if tc else "None flagged", "warn" if tc else "ok"),
            ("Mod mix", ", ".join(roles) or "Not classified yet", "muted" if not roles else "ok"),
            (
                "Quest checks",
                f"{pf} note{'s' if pf != 1 else ''}" if pf else "Looks clear",
                "warn" if pf else "ok",
            ),
        ]
    return [
        ("Health", f"{score}/100 · {verdict}", _health_verdict_tone(health)),
        ("Conflicts", f"{tc} finding{'s' if tc != 1 else ''}", "warn" if tc else "ok"),
        ("Mod roles", ", ".join(roles) or "No roles yet", "muted" if not roles else "ok"),
        (
            "Progression",
            f"{pf} audit finding{'s' if pf != 1 else ''}",
            "warn" if pf else "ok",
        ),
    ]


