def _power_center_status_strip_html(
    health: Dict[str, Any],
    conflict_summary: Dict[str, Any],
    role_summary: Dict[str, Any],
    progression: Dict[str, Any],
    *,
    pack_name: str,
) -> str:
    tiles = _power_lab_tiles_from_context(health, conflict_summary, role_summary, progression, friendly=True)
    cells: List[str] = []
    for title, body, tone in tiles:
        mod = ""
        if tone == "bad":
            mod = " forager-hub-insights-cell--bad"
        elif tone == "warn":
            mod = " forager-hub-insights-cell--warn"
        cells.append(_pack_health_metric_cell(title, body, "", mod))
    return (
        '<div class="forager-pack-health-wrap">'
        '<p class="forager-hub-insights-kicker forager-pc-kicker">At a glance</p>'
        f'<div class="forager-hub-insights-grid">{"".join(cells)}</div>'
        "</div>"
    )


def _power_center_health_findings_html(
    narrative: str,
    conflicts: List[Dict[str, Any]],
) -> str:
    if conflicts:
        return _power_center_triage_html(conflicts)
    lines = [ln.strip() for ln in (narrative or "").splitlines() if ln.strip()]
    triage_rows: List[Dict[str, Any]] = []
    for ln in lines:
        sev, msg = _parse_narrative_finding_line(ln)
        if sev and msg:
            triage_rows.append({"severity": sev, "type": "audit", "description": msg, "affected_labels": []})
    if triage_rows:
        return _power_center_triage_html(triage_rows)
    if str(narrative or "").strip():
        return (
            '<div class="forager-pack-health-triage">'
            '<div class="forager-pack-health-triage-head">Findings<span class="muted">health narrative</span></div>'
            f'<div class="forager-pack-health-triage-msg">{_ph_esc(narrative, n=900)}</div>'
            "</div>"
        )
    return ""


