def _render_power_center_workspace(*, key_prefix: str = "power_center_lab") -> Optional[Dict[str, Any]]:
    try:
        _ws = st.container(border=True)
    except TypeError:
        _ws = st.container()
    with _ws:
        st.markdown(
            _power_center_workspace_head_html(pack_name=""),
            unsafe_allow_html=True,
        )
        pack_name, pack_root = _selected_power_pack(
            key_prefix,
            compact=False,
            unified_library=True,
            picker_mode="power_center",
        )
        if not pack_name or not pack_root:
            st.info(
                "No packs in your library yet — sync installs under **My Packs** or add a folder under **packs/**."
            )
            return None
        with st.spinner("Loading pack status…"):
            context = build_pack_ai_context(
                pack_root=pack_root,
                pack_name=pack_name,
                resolver=conflict_resolver,
                include_performance=True,
                cache_dir=str(launcher.mod_downloader.cache_dir),
                launcher=launcher,
                game_root=pack_root,
            )
        health = context.get("health_score") or {}
        conflict_summary = (context.get("conflict_scan") or {}).get("summary") or {}
        role_summary = (context.get("mod_roles") or {}).get("summary") or {}
        progression = context.get("progression") or {}
        narrative = str(context.get("health_narrative") or "").strip()
        conflicts = (context.get("conflict_scan") or {}).get("conflicts") or []
        st.markdown(
            _power_center_status_strip_html(
                health,
                conflict_summary,
                role_summary,
                progression,
                pack_name=str(pack_name or ""),
            ),
            unsafe_allow_html=True,
        )
        findings_html = _power_center_health_findings_html(narrative, conflicts)
        if findings_html:
            st.markdown(findings_html, unsafe_allow_html=True)
        tc = int((conflict_summary or {}).get("total_conflicts") or 0)
        ac1, ac2 = st.columns(2, gap="small")
        with ac1:
            if st.button("Open full Pack Health", key=f"{key_prefix}_ws_open_ph", use_container_width=True):
                st.session_state["forager_nav"] = "conflicts"
                st.rerun()
        with ac2:
            if tc > 0 and st.button(
                "Review issues",
                key=f"{key_prefix}_ws_open_ph_scan",
                use_container_width=True,
            ):
                st.session_state["forager_nav"] = "conflicts"
                st.session_state[PACK_HEALTH_FOCUS_SCAN_FLAG] = True
                st.rerun()
    return {
        "pack_name": pack_name,
        "pack_root": pack_root,
        "context": context,
    }


def _render_power_center_workflow_picker(options: List[str], state_key: str) -> str:
    cur = str(st.session_state.get(state_key) or (options[0] if options else ""))
    if cur not in options and options:
        st.session_state[state_key] = cur = options[0]
    st.markdown('<p class="forager-pc-tools-head">Tools</p>', unsafe_allow_html=True)
    def _wf_label(opt: str) -> str:
        return _POWER_WORKFLOW_PC_TITLES.get(opt, (opt, ""))[0]

    st.selectbox(
        "What do you want to do?",
        options,
        key=state_key,
        format_func=_wf_label,
        help="Pick a helper — each tool explains itself below.",
    )
    workflow = str(st.session_state.get(state_key) or cur)
    return workflow


def _render_power_lab_health_block(
    *,
    key_prefix: str,
    health: Dict[str, Any],
    conflict_summary: Dict[str, Any],
    role_summary: Dict[str, Any],
    progression: Dict[str, Any],
    narrative: str,
    compact: bool,
    pack_name: str = "",
    enhanced_ui: bool = False,
) -> None:
    tiles = _power_lab_tiles_from_context(health, conflict_summary, role_summary, progression)
    tiles_html = "\n".join(power_tile(title, body, tone=tone) for title, body, tone in tiles)
    narr_html = _health_narrative_html(narrative, health) if str(narrative or "").strip() else ""
    if compact:
        with st.expander("Pack context (snapshot + health text)", expanded=False):
            st.markdown(
                f'<div class="forager-power-grid">\n{tiles_html}\n</div>{narr_html}',
                unsafe_allow_html=True,
            )
        return

    tc = int((conflict_summary or {}).get("total_conflicts") or 0)

    if enhanced_ui:
        return

    st.markdown(
        '<p class="forager-hub-section-label forager-hub-risk-kicker">Launcher health summary</p>',
        unsafe_allow_html=True,
    )
    st.markdown(
        f'<div class="forager-power-lab-shell">'
        f'<div class="forager-power-grid">\n{tiles_html}\n</div>'
        f"{narr_html}"
        f"</div>",
        unsafe_allow_html=True,
    )
    ac1, ac2 = st.columns(2, gap="small")
    with ac1:
        if st.button("Open Pack Health", key=f"{key_prefix}_open_ph", use_container_width=True):
            st.session_state["forager_nav"] = "conflicts"
            st.rerun()
    with ac2:
        if tc > 0 and st.button(
            "Review conflict scan",
            key=f"{key_prefix}_open_ph_scan",
            use_container_width=True,
        ):
            st.session_state["forager_nav"] = "conflicts"
            st.session_state[PACK_HEALTH_FOCUS_SCAN_FLAG] = True
            st.rerun()


