def _render_streamlit_graphviz(dot_source: str) -> None:
    """Render Graphviz DOT via Streamlit; fall back to plain text if the chart engine errors."""
    try:
        st.graphviz_chart(dot_source)
    except Exception as exc:
        st.warning(
            f"Graph preview failed (`{exc}`). DOT source is shown below — **Resolver Scan** still has the full report."
        )
        st.code(dot_source, language="text")


