_PACK_HEALTH_HINT_BY_KEY = {row[0]: row[2] for row in _PACK_HEALTH_VIEW_ROWS}


def _pack_health_verdict(*, summary: Dict[str, Any], conflicts_n: int, mods_n: int) -> Tuple[str, str, str]:
    hs = str(summary.get("highest_severity") or "none").strip().lower()
    cn = int(conflicts_n)
    mn = int(mods_n)
    mod_line = f"{mn} mod{'s' if mn != 1 else ''} checked"
    if cn <= 0:
        return (
            "ok",
            "Pack looks healthy",
            f"No clashes found in the last scan · {mod_line}",
        )
    if hs in ("critical", "high"):
        return (
            "bad",
            "Needs attention",
            f"{cn} issue{'s' if cn != 1 else ''} found · {mod_line} · start with **What to fix first** below",
        )
    if hs == "medium":
        return (
            "warn",
            "Review recommended",
            f"{cn} issue{'s' if cn != 1 else ''} · mostly medium severity · {mod_line}",
        )
    return (
        "warn",
        "Minor issues only",
        f"{cn} low-priority note{'s' if cn != 1 else ''} · {mod_line}",
    )


def _pack_health_hero_html(
    *,
    pack_name: str,
    summary: Dict[str, Any],
    conflicts_n: int,
    compat_n: int,
    mods_n: int,
) -> str:
    tone, title, subtitle = _pack_health_verdict(summary=summary, conflicts_n=conflicts_n, mods_n=mods_n)
    hs = str(summary.get("highest_severity") or "none").strip().lower()
    man = int(summary.get("manual_required") or 0)
    auto = int(summary.get("auto_resolvable") or 0)
    tc = int(conflicts_n)
    m_warn = " forager-ph-metric--warn" if tc else ""
    m_bad = " forager-ph-metric--bad" if hs in ("critical", "high") else (
        " forager-ph-metric--warn" if hs == "medium" else ""
    )
    return (
        f'<div class="forager-ph-hero forager-ph-hero--{tone}">'
        f'<div>'
        f'<div class="forager-ph-hero-title">{_ph_esc(title)}</div>'
        f'<p class="forager-ph-hero-sub">{_ph_esc(subtitle)}</p>'
        f'<p class="forager-ph-hero-sub" style="margin-top:0.35rem;"><strong>{_ph_esc(pack_name)}</strong></p>'
        f'</div>'
        f'<div class="forager-ph-hero-metrics">'
        f'<div class="forager-ph-metric{m_warn}"><div class="lab">Issues</div>'
        f'<div class="val">{tc}</div>'
        f'<div class="sub">found in scan</div></div>'
        f'<div class="forager-ph-metric{m_bad}"><div class="lab">Worst level</div>'
        f'<div class="val">{_ph_esc((hs or "none").upper())}</div>'
        f'<div class="sub">highest severity</div></div>'
        f'<div class="forager-ph-metric"><div class="lab">Auto-fix</div>'
        f'<div class="val">{auto}</div><div class="sub">candidates</div></div>'
        f'<div class="forager-ph-metric"><div class="lab">Compat rules</div>'
        f'<div class="val">{int(compat_n)}</div><div class="sub">saved for this pack</div></div>'
        f'</div></div>'
    )


