def render_power_tool_shortcuts_grid(*, key_suffix: str) -> None:
    st.markdown('<div class="forager-kicker">Tool Shortcuts</div>', unsafe_allow_html=True)
    for row_start in range(0, len(_POWER_TOOL_SHORTCUT_ROUTES), 3):
        cols = st.columns(3, gap="medium")
        for idx, (label, route) in enumerate(_POWER_TOOL_SHORTCUT_ROUTES[row_start : row_start + 3]):
            with cols[idx]:
                sk = f"pc_shortcut_{route}" if key_suffix == "pc" else f"{key_suffix}_sc_{route}"
                if st.button(label, use_container_width=True, key=sk):
                    st.session_state["forager_nav"] = route
                    st.rerun()


def render_power_playwright_smoke_panel(*, key_suffix: str) -> None:
    with st.container():
        st.markdown('<div class="forager-kicker">Validation</div>', unsafe_allow_html=True)
        st.caption(
            "Optional **Playwright smoke** (needs Node + script on PATH): exercises a few real `?forager_nav=` routes in Chrome."
        )
        smoke_key = "pc_run_playwright_smoke" if key_suffix == "pc" else f"{key_suffix}_run_playwright_smoke"
        smoke_col, smoke_status_col = st.columns([1, 2], gap="medium")
        with smoke_col:
            if st.button("Run Playwright Smoke", use_container_width=True, key=smoke_key):
                st.session_state["forager_smoke_result"] = _run_dashboard_smoke_from_ui()
                st.rerun()
        with smoke_status_col:
            smoke_result = st.session_state.get("forager_smoke_result")
            if isinstance(smoke_result, dict):
                if smoke_result.get("ok"):
                    st.success(str(smoke_result.get("message") or "Smoke passed."))
                else:
                    st.warning(str(smoke_result.get("message") or "Smoke could not run."))
                if smoke_result.get("hint"):
                    st.caption(str(smoke_result.get("hint")))
        if isinstance(st.session_state.get("forager_smoke_result"), dict) and st.session_state[
            "forager_smoke_result"
        ].get("output"):
            with st.expander("Playwright smoke output", expanded=False):
                st.code(str(st.session_state["forager_smoke_result"].get("output")), language="json")


def _resolve_power_lab_pack_choice(raw: Any, packs: Sequence[str]) -> Optional[str]:
    """Map session/widget raw value to a canonical folder name in ``packs`` (or None).

    Older runs could leave an **integer index** or a string that only matches after
    ``strip()`` / case-fold — normalize so the keyed ``st.selectbox`` and downstream
    ``build_pack_ai_context`` always agree on one pack root.
    """
    if not packs:
        return None
    if isinstance(raw, int):
        if 0 <= raw < len(packs):
            return packs[raw]
        return None
    s = str(raw).strip()
    if s in packs:
        return s
    low = {p.lower(): p for p in packs}
    return low.get(s.lower())


def _selected_power_pack(
    key_prefix: str,
    *,
    compact: bool = False,
    unified_library: bool = False,
    picker_mode: str = "expander",
) -> Tuple[Optional[str], Optional[str]]:
    """Resolve workspace pack for **Power Center** / **AI · Architect**.

    ``unified_library=True`` (**AI · Architect** and **Power Center**) uses the same Hub rows as **My Packs**
    (linked installs + ``packs/``). Otherwise only ``packs/`` folder names are listed.
    """
    if unified_library:
        hub_packs = _workspace_pack_dir_names()
        hub_library = _build_forager_hub_unified_library(hub_packs, _forager_instance_list(launcher))
        if not hub_library:
            return None, None
        pick_by_label = {p.label: p for p in hub_library}
        labels = list(pick_by_label.keys())
        uk = FORAGER_POWER_LAB_UNIFIED_PACK_KEY
        sk = FORAGER_AI_POWER_LAB_PACK_KEY
        raw0 = st.session_state.get(uk)
        if not (isinstance(raw0, str) and raw0.strip()):
            raw0 = st.session_state.get(_LEGACY_ARCHITECT_UNIFIED_PACK_KEY)
        if not (isinstance(raw0, str) and raw0.strip()):
            raw0 = st.session_state.get(sk)
        canon_lbl = _resolve_pack_health_hub_label(raw0, pick_by_label, labels)
        if str(st.session_state.get(uk) or "") != canon_lbl:
            st.session_state[uk] = canon_lbl

        _ph = (
            "Same library as **Home** — **My Packs** (linked installs) plus workspace folders under **packs/**. "
            "Workspace picks stay aligned with **Power Center**."
        )
        if compact or picker_mode == "compact":
            st.selectbox(
                "Pack (My Packs + packs/)",
                labels,
                key=uk,
                filter_mode="fuzzy",
                help=_ph,
            )
        elif picker_mode == "power_center":
            st.selectbox(
                "Which pack?",
                labels,
                key=uk,
                filter_mode="fuzzy",
                help="Any install from My Packs or a folder under packs/.",
            )
        elif picker_mode == "inline":
            st.selectbox(
                "Workspace pack",
                labels,
                key=uk,
                filter_mode="fuzzy",
                help=_ph,
            )
        else:
            with st.expander("Change pack…", expanded=False):
                st.selectbox("Pack", labels, key=uk, filter_mode="fuzzy", help=_ph)
            st.caption(f"Active library row: **{canon_lbl[:120]}{'…' if len(canon_lbl) > 120 else ''}**")

        lbl = _resolve_pack_health_hub_label(st.session_state.get(uk), pick_by_label, labels)
        pick = pick_by_label[lbl]
        pack_root = pick.root
        pack_name = str(pick.brain_name).strip() or os.path.basename(pack_root.rstrip("\\/")) or "pack"

        if not pick.from_linked_launcher and str(pick.brain_name).strip():
            st.session_state[sk] = str(pick.brain_name).strip()

        _aprev = st.session_state.get(_FORAGER_POWER_LAB_UNIFIED_PACK_PREV_KEY)
        try:
            root_key = _forager_hub_norm_path(pack_root) or pack_root
        except OSError:
            root_key = pack_root
        if _aprev is not None and _aprev != root_key:
            for stale in ("forager_ai_power_artifact", "forager_generated_payload"):
                st.session_state.pop(stale, None)
        st.session_state[_FORAGER_POWER_LAB_UNIFIED_PACK_PREV_KEY] = root_key

        for obsolete in ("architect_page_pack", "power_center_lab_pack", f"{key_prefix}_pack"):
            st.session_state.pop(obsolete, None)

        if pick.use_instance_manifest_defaults:
            init_pack_manifest(
                pack_root,
                pack_id=pick.pack_id_slug,
                minecraft_version=pick.mc_ver,
                loader=pick.loader,
            )
        else:
            init_pack_manifest(pack_root)
        return pack_name, pack_root

    packs = _workspace_pack_dir_names()
    if not packs:
        return None, None
    sk = FORAGER_AI_POWER_LAB_PACK_KEY
    resolved = _resolve_power_lab_pack_choice(st.session_state.get(sk), packs)
    if resolved is None:
        migrated: Optional[str] = None
        for legacy in ("architect_page_pack", "power_center_lab_pack", f"{key_prefix}_pack"):
            migrated = _resolve_power_lab_pack_choice(st.session_state.get(legacy), packs)
            if migrated is not None:
                break
        resolved = migrated if migrated is not None else packs[0]
    # Bind the widget key to a real ``packs/<name>/`` folder (Hub may set a display name not in ``packs/``).
    if _resolve_power_lab_pack_choice(st.session_state.get(sk), packs) is None:
        st.session_state[sk] = resolved
    else:
        canon = _resolve_power_lab_pack_choice(st.session_state.get(sk), packs)
        if canon and str(st.session_state.get(sk)) != canon:
            st.session_state[sk] = canon

    if compact:
        st.selectbox(
            "Workspace pack (packs/)",
            packs,
            key=sk,
            help=(
                "Folder under **packs/** (manifest + jars + AI context). Shared with **Power Center**; "
                "use **My Packs → Forager** to align linked instances."
            ),
        )
    else:
        st.caption(
            f"Workspace pack (**packs/**): **{resolved}** — shared by **Power Center** and **AI · Architect**. "
            "Picking a **`packs/` folder** on **Forager** keeps this in sync; expand below to change manually."
        )
        with st.expander("Change workspace pack…", expanded=False):
            st.selectbox(
                "Pack",
                packs,
                key=sk,
                help=(
                    "Folder under **packs/** (manifest + jars + AI context). Separate from **Forager** library rows "
                    "that point at linked launchers."
                ),
            )
    pack_name = _resolve_power_lab_pack_choice(st.session_state.get(sk), packs) or packs[0]
    if not pack_name:
        return None, None
    _prev = st.session_state.get(_FORAGER_POWER_LAB_PACK_PREV_KEY)
    if _prev is not None and _prev != pack_name:
        for stale in ("forager_ai_power_artifact", "forager_generated_payload"):
            st.session_state.pop(stale, None)
    st.session_state[_FORAGER_POWER_LAB_PACK_PREV_KEY] = pack_name
    for obsolete in ("architect_page_pack", "power_center_lab_pack", f"{key_prefix}_pack"):
        if obsolete != sk:
            st.session_state.pop(obsolete, None)
    pack_root = os.path.join(PACKS_DIR, pack_name)
    init_pack_manifest(pack_root)
    return pack_name, pack_root


def _selected_pack_health_pack(launcher, hub_library: Optional[List[Any]] = None) -> Tuple[str, str]:
    """Pack Health route: same unified library as **Home / Hub** (My Packs + ``packs/``).

    Returns ``(brain_name, pack_root)`` for scans, tiles, and export keys. Clears Council
    handoff when the resolved **root path** changes.
    """
    if hub_library is None:
        hub_packs = _workspace_pack_dir_names()
        hub_library = _build_forager_hub_unified_library(hub_packs, _forager_instance_list(launcher))
    if not hub_library:
        return "", ""
    pick_by_label = {p.label: p for p in hub_library}
    labels = list(pick_by_label.keys())
    sk = PACK_HEALTH_PACK_SEL_KEY
    canon_lbl = _resolve_pack_health_hub_label(st.session_state.get(sk), pick_by_label, labels)
    if str(st.session_state.get(sk) or "") != canon_lbl:
        st.session_state[sk] = canon_lbl

    st.selectbox(
        "Pack",
        labels,
        key=sk,
        filter_mode="fuzzy",
        help="Same library as **Home** and **My Packs** — linked installs and workspace folders under **packs/**.",
    )
    lbl = _resolve_pack_health_hub_label(st.session_state.get(sk), pick_by_label, labels)
    pick = pick_by_label[lbl]
    pack_root = pick.root
    pack_name = str(pick.brain_name).strip() or os.path.basename(pack_root.rstrip("\\/")) or "pack"

    if not pick.from_linked_launcher and str(pick.brain_name).strip():
        st.session_state[FORAGER_AI_POWER_LAB_PACK_KEY] = str(pick.brain_name).strip()

    _prev_root = st.session_state.get(_FORAGER_PACK_HEALTH_PACK_PREV_KEY)
    try:
        root_key = _forager_hub_norm_path(pack_root) or pack_root
    except OSError:
        root_key = pack_root
    if _prev_root is not None and _prev_root != root_key:
        for stale in ("forager_conflict_council_artifact", "council_artifact_src"):
            st.session_state.pop(stale, None)
        for stale in (
            PACK_HEALTH_CTX_EXPORT_ROOT_KEY,
            PACK_HEALTH_CTX_EXPORT_HN_KEY,
            PACK_HEALTH_CTX_EXPORT_TXT_KEY,
            PACK_HEALTH_CTX_EXPORT_JSON_KEY,
            PACK_HEALTH_GRAPH_RENDER_KEY,
        ):
            st.session_state.pop(stale, None)
    st.session_state[_FORAGER_PACK_HEALTH_PACK_PREV_KEY] = root_key

    if pick.use_instance_manifest_defaults:
        init_pack_manifest(
            pack_root,
            pack_id=pick.pack_id_slug,
            minecraft_version=pick.mc_ver,
            loader=pick.loader,
        )
    else:
        init_pack_manifest(pack_root)

    return pack_name, pack_root


class _ForagerHubLibPick(NamedTuple):
    """One row in the Forager hub unified pack library (matches **My Packs** + workspace ``packs/``)."""

    label: str
    root: str
    brain_name: str
    mc_ver: str
    loader: str
    pack_id_slug: str
    from_linked_launcher: bool
    use_instance_manifest_defaults: bool


def _forager_hub_norm_path(p: str) -> str:
    try:
        return os.path.normcase(os.path.normpath(os.path.expanduser(str(p))))
    except OSError:
        return ""


def _forager_hub_pack_status_kicker_label(
    pack_name: str,
    mc_ver: str,
    loader: str,
) -> str:
    """One-line pack identity for hub Pack status (name + MC + loader; no path)."""
    name = str(pack_name or "").strip() or "pack"
    m = re.match(r"^(.+?)\s+-\s+(\S+)$", name)
    if m:
        base, suffix = m.group(1).strip(), m.group(2).strip()
        if base and suffix:
            suf_norm = re.sub(r"[^a-z0-9]", "", suffix.lower())
            base_norm = re.sub(r"[^a-z0-9]", "", base.lower())
            if suf_norm and all(ch.isdigit() or ch in base_norm for ch in suf_norm):
                name = base
    mc = re.sub(r"^mc\s+", "", str(mc_ver or "").strip(), flags=re.I) or "1.20.1"
    ld = str(loader or "").strip().lower() or "forge"
    return f"{name} {mc} {ld}".strip().lower()


def _build_forager_hub_unified_library(
    pack_dir_names: List[str],
    instances: List[MinecraftInstance],
) -> List[_ForagerHubLibPick]:
    picks: List[_ForagerHubLibPick] = []
    claimed_paths: set[str] = set()
    for inst in sorted(instances, key=lambda x: str(x.name).lower()):
        root = os.path.normpath(os.path.expanduser(str(inst.instance_path)))
        if not os.path.isdir(root):
            continue
        nk = _forager_hub_norm_path(root)
        if nk:
            claimed_paths.add(nk)
        ls = (inst.linked_source or "").strip().lower()
        if ls in ("curseforge", "modrinth"):
            origin = "CurseForge" if ls == "curseforge" else "Modrinth"
        else:
            origin = "Forager"
        mc = str(inst.minecraft_version or "").strip()
        if not mc or mc.lower() == "unknown":
            mc = "1.20.1"
        ld = str(inst.loader or "").strip()
        if not ld or ld.lower() == "unknown":
            ld = "forge"
        slug = re.sub(r"[^\w\-]+", "_", str(inst.name))[:72].strip("_") or "pack"
        tail = os.path.basename(root.rstrip("\\/")) or slug
        lbl = f"{inst.name} · {origin} · MC {mc} · {tail}"
        picks.append(
            _ForagerHubLibPick(
                label=lbl,
                root=root,
                brain_name=str(inst.name),
                mc_ver=mc,
                loader=ld,
                pack_id_slug=slug,
                from_linked_launcher=bool(inst.linked_source),
                use_instance_manifest_defaults=True,
            )
        )

    for dn in sorted(pack_dir_names):
        wr = os.path.normpath(os.path.join(PACKS_DIR, dn))
        if not os.path.isdir(wr):
            continue
        nk = _forager_hub_norm_path(wr)
        if nk and nk in claimed_paths:
            continue
        slug = re.sub(r"[^\w\-]+", "_", str(dn))[:72].strip("_") or "workspace"
        picks.append(
            _ForagerHubLibPick(
                label=f"{dn} · workspace packs/ · {slug}",
                root=wr,
                brain_name=str(dn),
                mc_ver="1.20.1",
                loader="forge",
                pack_id_slug=slug,
                from_linked_launcher=False,
                use_instance_manifest_defaults=False,
            )
        )

    uniq: List[_ForagerHubLibPick] = []
    picks.sort(key=lambda r: str(r.label).lower())
    seen_count: Dict[str, int] = {}
    for row in picks:
        base = row.label
        n = int(seen_count.get(base, 0))
        seen_count[base] = n + 1
        lab = base if n == 0 else f"{base} · #{n + 1}"
        uniq.append(row._replace(label=lab))
    return uniq


def _resolve_pack_health_hub_label(
    raw: Any,
    pick_by_label: Dict[str, _ForagerHubLibPick],
    ordered_labels: List[str],
) -> str:
    """Map session / legacy values onto a Hub library label (unique per row)."""
    if not ordered_labels or not pick_by_label:
        return ""
    if isinstance(raw, str) and raw in pick_by_label:
        return raw
    if isinstance(raw, int) and 0 <= raw < len(ordered_labels):
        return ordered_labels[raw]
    s = str(raw).strip() if raw is not None else ""
    if not s:
        return ordered_labels[0]
    for lbl in ordered_labels:
        p = pick_by_label[lbl]
        if p.brain_name == s:
            return lbl
    low = s.lower()
    for lbl in ordered_labels:
        if low == lbl.lower():
            return lbl
    nk = _forager_hub_norm_path(s)
    if nk:
        for lbl in ordered_labels:
            if _forager_hub_norm_path(pick_by_label[lbl].root) == nk:
                return lbl
    return ordered_labels[0]


