def _migrate_forager_hub_mode_segment_widget() -> None:
    seg_key = "forager_hub_mode_seg"
    if seg_key not in st.session_state and "forager_hub_mode" in st.session_state:
        leg = st.session_state.get("forager_hub_mode")
        if isinstance(leg, str):
            full_set = {row[1] for row in _FORAGER_HUB_MODE_ROWS}
            if leg in full_set:
                for short, full, _ in _FORAGER_HUB_MODE_ROWS:
                    if full == leg:
                        st.session_state[seg_key] = short
                        break


def _render_forager_hub_retrieval_sources_expander(rag_cite: Any, rag_meta: Any) -> None:
    cites = rag_cite if isinstance(rag_cite, list) else []
    meta = rag_meta if isinstance(rag_meta, dict) else {}
    with st.expander("Notebook sources · paths RAG used", expanded=False):
        if not cites:
            st.caption(
                "No citations this run — retrieval may be off, the corpus empty, or the fallback path "
                "returned unstructured hits only."
            )
        else:
            for row in cites[:18]:
                if not isinstance(row, dict):
                    st.write(row)
                    continue
                st.markdown(format_hub_retrieval_citation_markdown(row))
        if meta:
            st.caption("Diagnostics")
            st.json(meta)


_FORAGER_HUB_TAPE_DISK_FILE = "hub_chat_tape.json"
_FORAGER_HUB_TAPE_HYDRATED_KEY = "_forager_hub_tape_hydrated_pack_keys"
_FORAGER_DEFAULT_HUB_TAPE_TURNS = 260
_FORAGER_HUB_AUTO_COUNCIL_MIN_CHARS = 180
_FORAGER_HUB_TAPE_STATE_KEY = "forager_hub_turn_tape_dict"
_FORAGER_HUB_PRIOR_TAPE_PACK_KEY = "_forager_hub_prior_tape_pack_key"
_FORAGER_HUB_RESTORE_OFFER_KEY = "_forager_hub_restore_offer"
_FORAGER_HUB_LAST_RETRIEVAL_BY_PACK_KEY = "forager_hub_last_retrieval_by_pack"
_FORAGER_HUB_PROMPT_QUEUE_KEY = "_forager_hub_prompt_queue"


def _forager_hub_tape_pack_key(pack_root: str) -> str:
    nk = _forager_hub_norm_path(pack_root)
    return nk or f"path:{hashlib.sha256(str(pack_root).encode('utf-8', errors='ignore')).hexdigest()[:16]}"


def _forager_hub_tape_eff_max_turns(config: Dict[str, Any]) -> int:
    raw = config.get("hub_chat_turn_limit", _FORAGER_DEFAULT_HUB_TAPE_TURNS)
    try:
        n = int(raw)
    except (TypeError, ValueError):
        n = _FORAGER_DEFAULT_HUB_TAPE_TURNS
    return max(12, min(900, n))


def _forager_hub_tape_disk_path(pack_root: str) -> Path:
    return Path(os.path.expandvars(str(pack_root))).expanduser() / ".forager" / _FORAGER_HUB_TAPE_DISK_FILE


def _forager_hub_tape_normalize_turn_obj(row: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    q = str(row.get("q") or "").strip()
    a = str(row.get("a") or "").strip()
    if not q or not a:
        return None
    out = {
        "q": q[:12000],
        "a": a[:56000],
        "mode": str(row.get("mode") or "")[:240],
        "ts": str(row.get("ts") or "")[:64],
    }
    cv = str(row.get("council_verdict") or "").strip()
    if cv:
        out["council_verdict"] = cv[:64]
    cin = row.get("council_issues_n")
    if isinstance(cin, int) and cin >= 0:
        out["council_issues_n"] = cin
    return out


def _forager_hub_tape_load_from_disk(pack_root: str, *, max_turns: int) -> List[Dict[str, Any]]:
    p = _forager_hub_tape_disk_path(pack_root)
    if not p.is_file():
        return []
    try:
        raw = json.loads(p.read_text(encoding="utf-8", errors="replace"))
    except (OSError, json.JSONDecodeError):
        return []
    items: List[Any]
    if isinstance(raw, list):
        items = raw
    elif isinstance(raw, dict) and isinstance(raw.get("turns"), list):
        items = raw["turns"]
    else:
        return []
    normalized: List[Dict[str, Any]] = []
    for it in items:
        if isinstance(it, dict):
            row = _forager_hub_tape_normalize_turn_obj(it)
            if row:
                normalized.append(row)
    if not normalized:
        return []
    overflow = len(normalized) - max_turns
    if overflow > 0:
        normalized = normalized[overflow:]
    return normalized


def _forager_hub_tape_save_disk(pack_root: str, tape: List[Dict[str, Any]], *, max_turns: int) -> None:
    trimmed = tape[-max_turns:] if max_turns > 0 else list(tape)
    p = _forager_hub_tape_disk_path(pack_root)
    try:
        p.parent.mkdir(parents=True, exist_ok=True)
        payload = {
            "schema": 1,
            "saved_utc": datetime.now(timezone.utc).isoformat(),
            "pack_path_note": str(pack_root)[:500],
            "turns": trimmed,
        }
        write_text_utf8_nobom(str(p), json.dumps(payload, indent=2, ensure_ascii=False))
    except OSError:
        pass


def _forager_hub_tape_ensure_hydrated_from_disk(pack_root: str, *, max_turns: int) -> None:
    pk = _forager_hub_tape_pack_key(pack_root)
    hydrated = st.session_state.get(_FORAGER_HUB_TAPE_HYDRATED_KEY)
    if not isinstance(hydrated, set):
        hydrated = set()
    if pk in hydrated:
        return
    disk_turns = _forager_hub_tape_load_from_disk(pack_root, max_turns=max_turns)
    bucket = _forager_hub_tape_bucket()
    bucket[pk] = disk_turns
    hydrated.add(pk)
    st.session_state[_FORAGER_HUB_TAPE_HYDRATED_KEY] = hydrated


def _forager_hub_tape_bucket() -> Dict[str, List[Dict[str, Any]]]:
    raw = st.session_state.setdefault(_FORAGER_HUB_TAPE_STATE_KEY, {})
    if not isinstance(raw, dict):
        raw = {}
        st.session_state[_FORAGER_HUB_TAPE_STATE_KEY] = raw
    return raw  # type: ignore[return-value]


def _forager_hub_tape_get(pack_root: str) -> List[Dict[str, Any]]:
    pk = _forager_hub_tape_pack_key(pack_root)
    bucket = _forager_hub_tape_bucket()
    cur = bucket.get(pk)
    if not isinstance(cur, list):
        cur = []
        bucket[pk] = cur
    return cur


def _forager_hub_tape_append(
    pack_root: str,
    question: str,
    answer: str,
    mode: str,
    *,
    max_turns: int,
    council_verdict: str = "",
    council_issues_n: int = 0,
) -> None:
    q = str(question or "").strip()
    a = str(answer or "").strip()
    if not q or not a:
        return
    tape = _forager_hub_tape_get(pack_root)
    row = {
        "q": q[:12000],
        "a": a[:56000],
        "mode": str(mode or "")[:240],
        "ts": datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%MZ"),
    }
    cv = str(council_verdict or "").strip()
    if cv:
        row["council_verdict"] = cv[:96]
        try:
            row["council_issues_n"] = int(council_issues_n)
        except (TypeError, ValueError):
            row["council_issues_n"] = 0
    tape.append(row)
    overflow = len(tape) - max_turns
    if overflow > 0:
        del tape[:overflow]
    _forager_hub_tape_save_disk(pack_root, tape, max_turns=max_turns)


def _forager_hub_tape_clear(pack_root: str) -> None:
    pk = _forager_hub_tape_pack_key(pack_root)
    bucket = _forager_hub_tape_bucket()
    bucket[pk] = []
    hydrated = st.session_state.get(_FORAGER_HUB_TAPE_HYDRATED_KEY)
    if isinstance(hydrated, set):
        hydrated.discard(pk)
        st.session_state[_FORAGER_HUB_TAPE_HYDRATED_KEY] = hydrated
    try:
        p = _forager_hub_tape_disk_path(pack_root)
        if p.is_file():
            p.unlink()
    except OSError:
        pass


def _forager_hub_tape_stable_widget_suffix(pack_root: str) -> str:
    return hashlib.sha256(_forager_hub_tape_pack_key(pack_root).encode("utf-8", errors="ignore")).hexdigest()[:12]


def _forager_hub_snapshot_last_retrieval(pack_root: str, citations: Any, meta: Any) -> None:
    """Remember last hub retrieval for merging into the next context export (session only, per pack root)."""
    pk = _forager_hub_tape_pack_key(pack_root)
    bucket = st.session_state.setdefault(_FORAGER_HUB_LAST_RETRIEVAL_BY_PACK_KEY, {})
    if not isinstance(bucket, dict):
        bucket = {}
        st.session_state[_FORAGER_HUB_LAST_RETRIEVAL_BY_PACK_KEY] = bucket
    cites_list: List[Any] = []
    if isinstance(citations, list):
        cites_list = [dict(x) if isinstance(x, dict) else x for x in citations]
    meta_dict: Dict[str, Any] = dict(meta) if isinstance(meta, dict) else {}
    bucket[pk] = {"retrieval_citations": cites_list, "retrieval_meta": meta_dict}


def _forager_hub_merge_last_retrieval_into_export(pack_root: str, hub_ex: Dict[str, Any]) -> Dict[str, Any]:
    merged = dict(hub_ex)
    bucket = st.session_state.get(_FORAGER_HUB_LAST_RETRIEVAL_BY_PACK_KEY)
    if not isinstance(bucket, dict):
        return merged
    slot = bucket.get(_forager_hub_tape_pack_key(pack_root))
    if not isinstance(slot, dict):
        return merged
    rc = slot.get("retrieval_citations")
    rm = slot.get("retrieval_meta")
    if isinstance(rc, list):
        merged["retrieval_citations"] = rc
    if isinstance(rm, dict):
        merged["retrieval_meta"] = rm
    return merged


def _forager_hub_render_chat_history_from_tape(pack_root: str) -> None:
    """Render prior turns as Streamlit chat bubbles (session tape is the backing store)."""
    cm_fn = getattr(st, "chat_message", None)
    if not callable(cm_fn):
        return
    tape = _forager_hub_tape_get(pack_root)
    if not tape:
        st.caption("No messages yet.")
        return
    for turn in tape:
        if not isinstance(turn, dict):
            continue
        qv = str(turn.get("q") or "").strip()
        av = str(turn.get("a") or "").strip()
        if not qv:
            continue
        with cm_fn("user"):
            st.markdown(qv)
        if av:
            with cm_fn("assistant"):
                shown = av[:56000]
                if len(av) > 56000:
                    shown += "\n… (truncated here — full text remains in the hub tape file)"
                st.write(shown)
                _cv = str(turn.get("council_verdict") or "").strip()
                if _cv:
                    try:
                        _cn = int(turn.get("council_issues_n"))
                    except (TypeError, ValueError):
                        _cn = 0
                    _suffix = f"{_cn} issue(s) noted · " if _cn > 0 else ""
                    st.caption(f"{_suffix}Council validation: **{html.escape(_cv[:120])}**")


def _forager_hub_apply_pack_switch_restore_side_effect(
    *,
    pack_root: str,
    tape_pack_key: str,
    pack_switched_here: bool,
) -> None:
    if not pack_switched_here:
        return
    tape = _forager_hub_tape_get(pack_root)
    last_q = str(tape[-1].get("q") or "").strip() if tape else ""
    if last_q:
        st.session_state[_FORAGER_HUB_RESTORE_OFFER_KEY] = {"pk": tape_pack_key, "q": last_q}
    else:
        st.session_state.pop(_FORAGER_HUB_RESTORE_OFFER_KEY, None)


def _forager_hub_render_restore_offer_row_if_any(*, tape_pack_key: str) -> None:
    _offer = st.session_state.get(_FORAGER_HUB_RESTORE_OFFER_KEY)
    _show_restore = (
        isinstance(_offer, dict)
        and str(_offer.get("pk") or "") == tape_pack_key
        and str(_offer.get("q") or "").strip()
    )
    if _show_restore:
        _oq = str(_offer.get("q") or "").strip()
        _c1, _c2, _c3 = st.columns([2, 1, 1])
        with _c1:
            st.caption("Repeat last question for this pack, or dismiss.")
        with _c2:
            if st.button("Send last question", key="forager_hub_tape_restore_load", use_container_width=True):
                st.session_state[_FORAGER_HUB_PROMPT_QUEUE_KEY] = _oq
                st.session_state.pop(_FORAGER_HUB_RESTORE_OFFER_KEY, None)
                st.rerun()
        with _c3:
            if st.button("Dismiss", key="forager_hub_tape_restore_dismiss", use_container_width=True):
                st.session_state.pop(_FORAGER_HUB_RESTORE_OFFER_KEY, None)
                st.rerun()


