def _render_forager_hub_chat_tools_panel(*, pack_root: str) -> None:
    """Clear history / repeat last (Hub Session tab)."""
    tape = _forager_hub_tape_get(pack_root)
    _wkey = _forager_hub_tape_stable_widget_suffix(pack_root)
    last_q = str(tape[-1].get("q") or "").strip() if tape else ""
    _t1, _t2 = st.columns([1, 1])
    with _t1:
        if st.button(
            "Clear chat history (this pack)", key=f"forager_hub_tape_clear_{_wkey}", use_container_width=True
        ):
            _forager_hub_tape_clear(pack_root)
            st.session_state.pop(_FORAGER_HUB_RESTORE_OFFER_KEY, None)
            st.rerun()
    with _t2:
        if tape and last_q:
            if st.button(
                "Queue last question again",
                key=f"forager_hub_repeat_last_q_{_wkey}",
                use_container_width=True,
            ):
                st.session_state[_FORAGER_HUB_PROMPT_QUEUE_KEY] = last_q
                st.rerun()


def _render_forager_hub_reply_feedback_panel(*, pack_root: str) -> None:
    """Optional reply feedback row (Hub Session tab)."""
    _suf = _forager_hub_tape_stable_widget_suffix(pack_root)
