def _forager_hub_mods_dir_mtime(pack_root: str) -> float:
    mp = os.path.join(str(pack_root), "mods")
    try:
        return float(os.path.getmtime(mp))
    except OSError:
        return 0.0


def _forager_hub_compats_dir_mtime(pack_root: str) -> float:
    cp = os.path.join(str(pack_root), "compats")
    try:
        return float(os.path.getmtime(cp))
    except OSError:
        return 0.0


def _forager_hub_pack_manifest_mtime(pack_root: str) -> float:
    mp = os.path.join(str(pack_root), "pack.manifest.json")
    try:
        return float(os.path.getmtime(mp))
    except OSError:
        return 0.0


def _forager_hub_lockfile_mtime(pack_root: str) -> float:
    """Bust hub preflight cache when ``forager_mods.lock*.json`` changes."""
    root = str(pack_root or "").strip()
    mt = 0.0
    for name in ("forager_mods.lock.json", "forager_mods.lock.meta.json"):
        p = os.path.join(root, name)
        try:
            mt = max(mt, float(os.path.getmtime(p)))
        except OSError:
            continue
    return mt


def _forager_hub_scan_dismissals_mtime(pack_root: str) -> float:
    """Bust hub preflight cache when ``.forager/scan_dismissals.json`` changes."""
    return float(dismissals_file_mtime(str(pack_root or "").strip()))


def _render_forager_hub_readiness_insights_expander(
    *,
    rep: Dict[str, Any],
    sf: Dict[str, Any],
    hs: Dict[str, Any],
    pre_msg: str,
    tc: int,
    hi_sev: str,
    dec: str,
    eff_mc: str,
    eff_ld: str,
    widget_suffix: str,
) -> None:
    """Hub readiness detail: slate cards + tabs (matches ``forager-hub-risk-*`` chrome)."""

    def esc(s: Any, *, n: int = 900) -> str:
        return html.escape(str(s if s is not None else "")[:n], quote=False)

    hf_lines: List[str] = []
    for f in (hs.get("findings") or [])[:14]:
        if isinstance(f, dict) and f.get("message"):
            sev = str(f.get("severity") or "").strip()
            msg = str(f.get("message") or "").strip()
            hf_lines.append(f"{sev}: {msg}" if sev else msg)

    sf_reasons = sf.get("reasons") if isinstance(sf.get("reasons"), list) else []
    sf_reasons_clean = [str(x).strip() for x in sf_reasons if isinstance(x, str) and str(x).strip()]

    ll = rep.get("launch_log_signals") if isinstance(rep.get("launch_log_signals"), dict) else {}
    lv = rep.get("lock_verify") if isinstance(rep.get("lock_verify"), dict) else {}
    vp = rep.get("version_provenance") if isinstance(rep.get("version_provenance"), dict) else {}
    jva = rep.get("jar_version_audit") if isinstance(rep.get("jar_version_audit"), dict) else {}
    dismissed = rep.get("dismissed_conflict_ids") if isinstance(rep.get("dismissed_conflict_ids"), list) else []
    perf = rep.get("performance") if isinstance(rep.get("performance"), dict) else {}
    perf_findings = perf.get("findings") if isinstance(perf.get("findings"), list) else []

    conf_lvl = str(sf.get("confidence") or "").strip().lower()
    if conf_lvl not in ("high", "medium", "low"):
        conf_lvl = "unknown"
    conf_v = str(sf.get("confidence") or "—").strip().upper()

    def _cell(lab: str, val: str, sub: str = "", mod: str = "") -> str:
        sub_h = f'<div class="ih-sub">{esc(sub, n=160)}</div>' if str(sub).strip() else ""
        return (
            f'<div class="forager-hub-insights-cell{mod}">'
            f'<div class="ih-lab">{esc(lab)}</div>'
            f'<div class="ih-val">{esc(val)}</div>'
            f"{sub_h}</div>"
        )

    dec_s = dec if dec in ("allow", "warn", "block") else "allow"
    gate_cls = f"forager-hub-insights-gate forager-hub-insights-gate--{dec_s}"
    gate_title = {"allow": "Clear to proceed", "warn": "Review recommended", "block": "Install blocked"}.get(
        dec_s, dec_s.title()
    )
    gate_html = (
        f'<div class="{gate_cls}">'
        f'<div class="ih-gl">Preflight gate</div>'
        f'<div class="ih-gt">{esc(gate_title, n=120)}</div>'
        f'<div class="ih-gm">{esc(pre_msg or "—", n=520)}</div>'
        f"</div>"
    )

    st.markdown(
        f'<div class="forager-hub-insights-wrap">'
        f'<p class="forager-hub-insights-kicker">Readiness diagnostics</p>'
        f"{gate_html}</div>",
        unsafe_allow_html=True,
    )

    tab_ov, tab_log, tab_lock, tab_ver, tab_jar, tab_health = st.tabs(
        ["Summary", "Logs", "Lock", "Versions", "Jars", "Score"]
    )

    with tab_ov:
        note_txt = str(sf.get("confidence_note") or "").strip()
        note_html = (
            f'<p class="forager-hub-risk-fidelity-note">{esc(note_txt, n=260)}</p>' if note_txt else ""
        )
        fid_li = "".join(f"<li>{esc(line, n=380)}</li>" for line in sf_reasons_clean[:12])
        fid_block = (
            f'<ul class="forager-hub-risk-fidelity-ul">{fid_li}</ul>' if fid_li else '<p class="forager-hub-risk-fidelity-note">No extra fidelity lines.</p>'
        )
        ov_mc = esc(sf.get("minecraft_source"), n=40)
        ov_ld = esc(sf.get("loader_source"), n=40)
        fidelity_html = (
            f'<div class="forager-hub-risk-fidelity forager-hub-risk-fidelity--{esc(conf_lvl, n=12)} forager-hub-insights-fid">'
            f'<div class="forager-hub-risk-fidelity-top">'
            f'<span class="forager-hub-risk-fidelity-k">Scan fidelity</span>'
            f'<span class="forager-hub-risk-fidelity-tier">{esc(conf_v)}</span>'
            f'<span class="forager-hub-risk-fidelity-counts">{esc(sf.get("jar_mod_files"))} jars · {esc(sf.get("mods_indexed"))} indexed</span>'
            f"</div>"
            f"{note_html}"
            f'<p style="margin:0.15rem 0 0.05rem 0;font-size:0.72rem;color:#cbd5e1;line-height:1.45;">'
            f"MC <code>{ov_mc}</code> · loader <code>{ov_ld}</code> · hub override "
            f"<strong>{str(bool(sf.get('hub_row_overridden'))).lower()}</strong> · jar parity "
            f"<strong>{str(bool(sf.get('jar_mod_parity'))).lower()}</strong>"
            f"</p>"
            f"{fid_block}</div>"
        )
        st.markdown(fidelity_html, unsafe_allow_html=True)

    with tab_log:
        st.caption(esc(str(ll.get("note") or "Tail-only heuristics."), n=240))
        lp = str(ll.get("log_path") or "").strip()
        if lp:
            st.code(lp, language=None)
        hits = ll.get("hits") if isinstance(ll.get("hits"), list) else []
        if not hits:
            st.caption("No pattern hits in the latest log tail.")
        else:
            rows = []
            for i, h in enumerate(hits[:20]):
                if not isinstance(h, dict):
                    continue
                rows.append(
                    {
                        "#": i + 1,
                        "Severity": str(h.get("severity") or ""),
                        "Pattern": str(h.get("pattern_id") or ""),
                        "Snippet": str(h.get("snippet") or "")[:280],
                    }
                )
            if rows:
                st.dataframe(rows, use_container_width=True, hide_index=True, height=min(320, 44 + 32 * len(rows)))

    with tab_lock:
        if lv.get("skipped"):
            st.warning(esc(str(lv.get("reason") or "Lock verify skipped."), n=400))
        elif not lv:
            st.caption("No `forager_mods.lock.json` beside this pack.")
        elif lv.get("ok") is False and not lv.get("lock_path"):
            st.warning(esc(str(lv.get("message") or "Lock verify failed."), n=400))
        else:
            miss = lv.get("missing_on_disk") or []
            extra = lv.get("extra_on_disk") or []
            hm = lv.get("hash_mismatch") or []
            st.markdown(
                f"**Lock rows** · file {int(lv.get('lock_jar_rows') or 0)} · disk {int(lv.get('disk_jar_rows') or 0)} · "
                f"**hash_ok** {int(lv.get('hash_ok_count') or 0)}"
            )
            if lv.get("lock_path"):
                st.code(str(lv.get("lock_path")), language=None)
            c1, c2, c3 = st.columns(3)
            c1.metric("Missing", str(len(miss)))
            c2.metric("Extra", str(len(extra)))
            c3.metric("Mismatch", str(len(hm)))
            if miss:
                with st.expander(f"Missing ({len(miss)})", expanded=False):
                    st.text("\n".join(str(x) for x in miss[:80]))
            if extra:
                with st.expander(f"Extra ({len(extra)})", expanded=False):
                    st.text("\n".join(str(x) for x in extra[:80]))
            if hm:
                with st.expander(f"Hash mismatch ({len(hm)})", expanded=False):
                    st.json(hm[:40])

    with tab_ver:
        if not vp:
            st.caption("No provenance payload.")
        else:
            hr = vp.get("hub_row") or {}
            dm = vp.get("disk_manifest") or {}
            ls = vp.get("launcher_sidecar") or {}
            st.markdown(
                "| Source | Minecraft | Loader |\n| --- | --- | --- |\n"
                f"| Hub | `{esc(hr.get('minecraft_version'), n=24)}` | `{esc(hr.get('loader'), n=20)}` |\n"
                f"| Disk manifest | `{esc(dm.get('minecraft_version'), n=24)}` | `{esc(dm.get('loader'), n=20)}` |\n"
                f"| Launcher JSON | `{esc(ls.get('minecraft_version'), n=24)}` | `{esc(ls.get('loader'), n=20)}` |\n"
            )
            st.caption(f"Disk manifest on disk: **{bool(dm.get('present'))}**")
            for note_key in ("note", "loader_note"):
                nv = ls.get(note_key)
                if isinstance(nv, str) and nv.strip():
                    st.caption(esc(nv.strip(), n=360))
            disagreements = vp.get("disagreements") or []
            for dline in disagreements[:6]:
                if isinstance(dline, str) and dline.strip():
                    st.warning(esc(dline.strip(), n=480))

    with tab_jar:
        if not jva:
            st.caption("No jar audit payload.")
        else:
            mm_ct = int(jva.get("mismatch_count") or 0)
            co = int(jva.get("client_only") or 0)
            so = int(jva.get("server_only") or 0)
            jar_row = (
                '<div class="forager-hub-insights-grid" style="margin-top:0.2rem;">'
                + _cell("Sampled", str(int(jva.get("sampled_jars") or 0)), "jars", "")
                + _cell(
                    "MC mismatch",
                    str(mm_ct),
                    "in sample",
                    " forager-hub-insights-cell--warn" if mm_ct else "",
                )
                + _cell("Unknown ratio", str(jva.get("unknown_ratio")), "declarations", "")
                + _cell("Fabric env", f"{co}/{so}", "client / server", "")
                + "</div>"
            )
            st.markdown(jar_row, unsafe_allow_html=True)
            if not jva.get("dual_env_scan", False):
                st.caption(
                    "Single `mods/` tree: environment counts are hints only — no separate client/server scan."
                )
            notes = jva.get("notes") if isinstance(jva.get("notes"), list) else []
            if notes:
                with st.expander("Sample notes", expanded=False):
                    st.text("\n".join(str(n).strip()[:400] for n in notes[:12] if isinstance(n, str) and str(n).strip()))

    with tab_health:
        score_v = hs.get("score")
        ver = str(hs.get("verdict") or "unknown")
        h1, h2 = st.columns([1, 2])
        with h1:
            if score_v is None:
                st.metric("Health", "—", delta="unknown")
            else:
                st.metric("Health", f"{int(score_v)}/100", delta=ver[:14], delta_color="off")
        with h2:
            if hf_lines:
                with st.expander("Deductions", expanded=False):
                    st.text("\n".join(hf_lines))
            else:
                st.caption("No itemized deductions.")

    slim_export = {
        "scan_fidelity": sf,
        "preflight": {"decision": dec, "message": pre_msg},
        "resolver": {"total_conflicts": tc, "highest_severity": hi_sev},
        "launch_log": {
            "overall_severity": ll.get("overall_severity"),
            "log_path": ll.get("log_path"),
            "hits_count": len(ll.get("hits") or []) if isinstance(ll.get("hits"), list) else 0,
        },
        "lock_verify": {k: v for k, v in (lv or {}).items() if k not in ("missing_on_disk", "extra_on_disk", "hash_mismatch")}
        | {
            "missing_on_disk_count": len(lv.get("missing_on_disk") or []),
            "extra_on_disk_count": len(lv.get("extra_on_disk") or []),
            "hash_mismatch_count": len(lv.get("hash_mismatch") or []),
        },
        "version_provenance": vp,
        "jar_version_audit": {k: v for k, v in (jva or {}).items() if k != "notes"},
        "dismissed_conflict_ids": dismissed[:80],
    }
    try:
        st.download_button(
            label="Export JSON",
            data=json.dumps(slim_export, indent=2, ensure_ascii=False).encode("utf-8"),
            file_name="forager_hub_readiness_insights.json",
            mime="application/json",
            key=f"hub_rd_ins_json_{widget_suffix}",
        )
    except Exception:
        pass


def _render_forager_hub_risk_health_snapshot(*, pick: _ForagerHubLibPick) -> None:
    """Rich install-target readiness panel for the active Hub pack (ephemeral manifest scan)."""

    def _ico(kind: str) -> str:
        paths = {
            "health": (
                '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" '
                'stroke-linecap="round" stroke-linejoin="round">'
                '<path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z"/>'
                "</svg>"
            ),
            "conflicts": (
                '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" '
                'stroke-linecap="round" stroke-linejoin="round">'
                '<path d="M10.29 3.86 1.82 18a2 2 0 0 0 1.99 2.14h12.36a2 2 0 0 0 1.99-2.14L13.71 3.86a2 2 0 0 0-3.42 0z"/>'
                '<path d="M12 9v4"/><path d="M12 17h.01"/>'
                "</svg>"
            ),
            "perf": (
                '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" '
                'stroke-linecap="round" stroke-linejoin="round">'
                '<path d="M13 2 3 14h9l-1 8 10-12h-9l1-8z"/>'
                "</svg>"
            ),
            "preflight": (
                '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" '
                'stroke-linecap="round" stroke-linejoin="round">'
                '<path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/>'
                '<path d="m9 12 2 2 4-4"/>'
                "</svg>"
            ),
        }
        return f'<div class="forager-hub-risk-ico" aria-hidden="true">{paths[kind]}</div>'

    def _short(s: str, n: int) -> str:
        t = str(s or "").strip()
        if len(t) <= n:
            return t
        return t[: max(0, n - 1)] + "…"

    def _verdict_badge_cls(v: str) -> str:
        m = {
            "healthy": "forager-hub-risk-badge--healthy",
            "watch": "forager-hub-risk-badge--watch",
            "risky": "forager-hub-risk-badge--risky",
            "critical": "forager-hub-risk-badge--critical",
        }
        return m.get(str(v).strip().lower(), "")

    def _dial_color(score_cls: str) -> str:
        if "forager-hub-risk-tile--bad" in score_cls:
            return "#f87171"
        if "forager-hub-risk-tile--warn" in score_cls:
            return "#fbbf24"
        return "#34d399"

    def _sev_chips(summary: Dict[str, Any]) -> str:
        sc = summary.get("severity_counts") if isinstance(summary.get("severity_counts"), dict) else {}
        out: List[str] = []
        for key, lab in (
            ("critical", "CR"),
            ("high", "HI"),
            ("medium", "MD"),
            ("low", "LO"),
        ):
            n = int(sc.get(key, 0) or 0) if isinstance(sc, dict) else 0
            if n > 0:
                out.append(
                    f'<span class="forager-hub-risk-chip forager-hub-risk-chip--{html.escape(key)}">'
                    f"{html.escape(lab)} {n}</span>"
                )
        if out:
            return '<div class="forager-hub-risk-chips">' + "".join(out) + "</div>"
        tc0 = int(summary.get("total_conflicts") or 0)
        if tc0 == 0:
            return '<div class="forager-hub-risk-chips"><span class="forager-hub-risk-chip forager-hub-risk-chip--none">Clean</span></div>'
        return '<div class="forager-hub-risk-chips"><span class="forager-hub-risk-chip forager-hub-risk-chip--none">Mixed</span></div>'

    root = str(pick.root or "").strip()
    if not root or not os.path.isdir(root):
        st.info("Pick a valid **Active pack / instance** for a risk snapshot.")
        return
    suf = _forager_hub_tape_stable_widget_suffix(root)
    mc = str(pick.mc_ver or "1.20.1").strip() or "1.20.1"
    ld = str(pick.loader or "forge").strip() or "forge"
    lbl = str(pick.brain_name or pick.pack_id_slug or "pack").strip() or "pack"
    _hub_cfg = launcher.config
    try:
        rep = _forager_hub_cached_preflight(
            root,
            lbl,
            mc,
            ld,
            _forager_hub_mods_dir_mtime(root),
            _forager_hub_compats_dir_mtime(root),
            _forager_hub_pack_manifest_mtime(root),
            _forager_hub_lockfile_mtime(root),
            _forager_hub_scan_dismissals_mtime(root),
            bool(_hub_cfg.get("preflight_telemetry_enabled", False)),
            bool(_hub_cfg.get("preflight_telemetry_include_paths", False)),
        )
    except Exception as exc:
        st.warning(f"Risk snapshot failed: `{exc}`")
        return
    sf = rep.get("scan_fidelity") if isinstance(rep.get("scan_fidelity"), dict) else {}
    eff_mc = str(sf.get("effective_minecraft_version") or mc).strip() or mc
    eff_ld = str(sf.get("effective_loader") or ld).strip() or ld
    hs = rep.get("health_score") or {}
    cs = (rep.get("conflict_scan") or {}).get("summary") or {}
    if not isinstance(cs, dict):
        cs = {}
    score = hs.get("score")
    verdict = str(hs.get("verdict") or "unknown")
    try:
        sc_i = int(score) if score is not None else None
    except (TypeError, ValueError):
        sc_i = None
    tc = int(cs.get("total_conflicts") or 0)
    hi_sev = str(cs.get("highest_severity") or "none")
    pre = decide_preflight(cs)
    dec = str(pre.get("decision") or "allow")
    pre_msg = str(pre.get("message") or "").strip()
    perf = rep.get("performance") if isinstance(rep.get("performance"), dict) else {}
    perf_findings = perf.get("findings") if isinstance(perf.get("findings"), list) else []
    perf_n = len(perf_findings)
    score_cls = "forager-hub-risk-tile--ok"
    if sc_i is not None and sc_i < 60:
        score_cls = "forager-hub-risk-tile--bad"
    elif sc_i is not None and sc_i < 78:
        score_cls = "forager-hub-risk-tile--warn"
    conf_cls = "forager-hub-risk-tile--ok" if tc == 0 else "forager-hub-risk-tile--warn"
    if hi_sev in ("critical", "error") or dec == "block":
        conf_cls = "forager-hub-risk-tile--bad"
    pre_cls = "forager-hub-risk-tile--ok"
    if dec == "warn":
        pre_cls = "forager-hub-risk-tile--warn"
    elif dec == "block":
        pre_cls = "forager-hub-risk-tile--bad"
    perf_cls = "forager-hub-risk-tile--warn" if perf_n else "forager-hub-risk-tile--ok"

    score_disp = f"{sc_i}/100" if sc_i is not None else "—"
    bar_w = max(2, min(100, int(sc_i))) if sc_i is not None else 0
    dial_pct = max(0, min(100, int(sc_i))) if sc_i is not None else 0
    dial_fill = _dial_color(score_cls)
    vb = "forager-hub-risk-badge " + _verdict_badge_cls(verdict)
    hero_meta = html.escape(_forager_hub_pack_status_kicker_label(lbl, eff_mc, eff_ld))
    mods_n = int(cs.get("mods_scanned") or 0)
    auto_n = int(cs.get("auto_resolvable") or 0)
    man_n = int(cs.get("manual_required") or 0)
    conf_line = f"{mods_n} jars · peak {html.escape(hi_sev)} · {tc} finding(s)"
    conf_sub = f"{auto_n} auto-resolvable · {man_n} need manual review" if tc else "No resolver hits on this scan"

    perf_line = f"{perf_n} signal(s)" if perf_n else "No heavy folders flagged"
    perf_sub = ""
    if perf_n and isinstance(perf_findings[0], dict):
        perf_sub = str(perf_findings[0].get("message") or "").strip()
    perf_sub = html.escape(_short(perf_sub, 96)) if perf_sub else "Mods/config/resource footprint looks tame."

    dec_head = {"allow": "Clear to proceed", "warn": "Review recommended", "block": "Install blocked"}.get(dec, dec.title())
    dec_sub = html.escape(_short(pre_msg, 140)) if pre_msg else "Resolver-driven install gate from severity mix."
    dec_safe = dec if dec in ("allow", "warn", "block") else "allow"

    badge_ver = html.escape(_short(verdict.replace("_", " "), 14))

    if sc_i is not None:
        dial_html = (
            f'<div class="forager-hub-risk-dial-wrap"><div class="forager-hub-risk-dial" '
            f'style="--h-pct: {dial_pct}; --dial-fill: {dial_fill};">'
            f'<div class="forager-hub-risk-dial-inner"><span class="forager-hub-risk-dial-n">{int(sc_i)}</span>'
            f'<span class="forager-hub-risk-dial-sub">health</span></div></div></div>'
        )
        health_body_cls = "forager-hub-risk-card-body"
    else:
        dial_html = (
            '<div class="forager-hub-risk-dial-wrap"><div class="forager-hub-risk-dial forager-hub-risk-dial--empty" style="--h-pct: 0;">'
            '<div class="forager-hub-risk-dial-inner"><span class="forager-hub-risk-dial-n">—</span>'
            '<span class="forager-hub-risk-dial-sub">n/a</span></div></div></div>'
        )
        health_body_cls = "forager-hub-risk-card-body"

    health_inner = (
        f'<div class="{health_body_cls}">'
        f"{dial_html}"
        f'<div class="forager-hub-risk-card-col">'
        f'<div class="forager-hub-risk-tile-k">Pack health</div>'
        f'<div class="forager-hub-risk-tile-v">{html.escape(score_disp)}</div>'
        f'<div class="forager-hub-risk-bar"><span style="width: {bar_w}%;"></span></div>'
        f'<div class="forager-hub-risk-tile-sub">'
        f'{"Score withheld (unknown)" if verdict == "unknown" and sc_i is None else "Launcher score"} · {html.escape(verdict)}</div>'
        f"</div></div>"
    )

    ov_pill = ""
    if sf.get("hub_row_overridden"):
        ov_pill = (
            '<span class="forager-hub-risk-pill forager-hub-risk-pill--warn" '
            'title="pack.manifest.json on disk overrode the hub row for this scan">Manifest→scan</span>'
        )

    conf_lvl = str(sf.get("confidence") or "").strip().lower()
    conf_cls = (
        f"forager-hub-risk-fidelity--{conf_lvl}"
        if conf_lvl in ("high", "medium", "low")
        else "forager-hub-risk-fidelity--unknown"
    )
    jar_n = int(sf.get("jar_mod_files") or 0) if sf else 0
    mods_ix = int(sf.get("mods_indexed") or 0) if sf else 0
    parity_ok = bool(sf.get("jar_mod_parity")) if sf else True
    fid_li = ""
    for line in (sf.get("reasons") or [])[:5]:
        if isinstance(line, str) and line.strip():
            fid_li += f"<li>{html.escape(_short(line, 200))}</li>"
    note = html.escape(_short(str(sf.get("confidence_note") or ""), 200))
    fidelity_html = ""
    if sf:
        parity_label = "parity OK" if parity_ok else "jar vs index mismatch"
        fidelity_html = (
            f'<div class="forager-hub-risk-fidelity {conf_cls}">'
            f'<div class="forager-hub-risk-fidelity-top">'
            f'<span class="forager-hub-risk-fidelity-k">Signal confidence</span>'
            f'<span class="forager-hub-risk-fidelity-tier">{html.escape(conf_lvl.upper() or "—")}</span>'
            f'<span class="forager-hub-risk-fidelity-counts">'
            f"{jar_n} jars · {mods_ix} indexed · {html.escape(parity_label)}</span></div>"
            f'<p class="forager-hub-risk-fidelity-note">{note}</p>'
        )
        if fid_li:
            fidelity_html += f'<ul class="forager-hub-risk-fidelity-ul">{fid_li}</ul>'
        fidelity_html += "</div>"

    def _risk_tile_link(href: str, title: str, inner: str) -> str:
        return (
            f'<a class="forager-hub-risk-tile-link" target="_self" href="{html.escape(href, quote=True)}" '
            f'title="{html.escape(title, quote=True)}">{inner}</a>'
        )

    _lib_enc = quote_plus(pick.label)
    _row_q = f"&forager_library_row={_lib_enc}"
    _href_pack_health = f"?forager_nav=conflicts{_row_q}"
    _href_conflicts = f"?forager_nav=conflicts{_row_q}&forager_ph_view=scan"
    _ws_pack_dirs = set(_workspace_pack_dir_names())
    _brain = str(pick.brain_name or "").strip()
    if _brain and _brain in _ws_pack_dirs:
        _href_performance = f"?forager_nav=performance&forager_perf_pack={quote_plus(_brain)}{_row_q}"
    else:
        _href_performance = f"?forager_nav=power_center&forager_pc_expand=1{_row_q}"
    _href_preflight = f"?forager_nav=power_center&forager_pc_expand=1{_row_q}"

    _inner_health = (
        f'<div class="forager-hub-risk-tile {score_cls}">'
        f'<div class="forager-hub-risk-card-head">{_ico("health")}'
        f'<span class="{vb}" title="{html.escape(verdict)}">{badge_ver}</span></div>'
        f"{health_inner}</div>"
    )
    _inner_conf = (
        f'<div class="forager-hub-risk-tile {conf_cls}">'
        f'<div class="forager-hub-risk-card-head">{_ico("conflicts")}'
        f'<span class="forager-hub-risk-badge">{html.escape(hi_sev)}</span></div>'
        f'<div class="forager-hub-risk-card-body forager-hub-risk-card-body--stack">'
        f'<div class="forager-hub-risk-card-col">'
        f'<div class="forager-hub-risk-tile-k">Conflicts</div>'
        f'<div class="forager-hub-risk-tile-v">{tc}</div>'
        f'<div class="forager-hub-risk-tile-sub">{conf_line}</div>'
        f"{_sev_chips(cs)}"
        f"</div></div></div>"
    )
    _inner_perf = (
        f'<div class="forager-hub-risk-tile {perf_cls}">'
        f'<div class="forager-hub-risk-card-head">{_ico("perf")}'
        f'<span class="forager-hub-risk-badge">{perf_n}</span></div>'
        f'<div class="forager-hub-risk-card-body forager-hub-risk-card-body--stack">'
        f'<div class="forager-hub-risk-card-col">'
        f'<div class="forager-hub-risk-tile-k">Performance</div>'
        f'<div class="forager-hub-risk-tile-v">{html.escape(perf_line)}</div>'
        f'<div class="forager-hub-risk-tile-sub">{perf_sub}</div>'
        f"</div></div></div>"
    )
    _inner_pre = (
        f'<div class="forager-hub-risk-tile {pre_cls}">'
        f'<div class="forager-hub-risk-card-head">{_ico("preflight")}'
        f'<span class="forager-hub-risk-badge forager-hub-risk-badge--pf-{html.escape(dec_safe)}">'
        f"{html.escape(dec.upper())}</span></div>"
        f'<div class="forager-hub-risk-card-body forager-hub-risk-card-body--stack">'
        f'<div class="forager-hub-risk-card-col">'
        f'<div class="forager-hub-risk-tile-k">Preflight gate</div>'
        f'<div class="forager-hub-risk-tile-v">{html.escape(dec_head)}</div>'
        f'<div class="forager-hub-risk-tile-sub">{dec_sub}</div>'
        f"</div></div></div>"
    )

    _hi_mod = score_cls.replace("forager-hub-risk-tile", "forager-hub-insights-cell")
    _cf_mod = conf_cls.replace("forager-hub-risk-tile", "forager-hub-insights-cell")
    _pf_mod = pre_cls.replace("forager-hub-risk-tile", "forager-hub-insights-cell")
    _pr_mod = perf_cls.replace("forager-hub-risk-tile", "forager-hub-insights-cell")
    tiles_html = (
        '<div class="forager-pack-health-wrap" role="region" aria-label="Pack status">'
        '<p class="forager-hub-insights-kicker forager-pc-kicker">At a glance</p>'
        f'<p class="forager-hub-insights-kicker" style="margin:0 0 0.45rem;font-size:0.72rem;">{hero_meta}</p>'
        '<div class="forager-hub-insights-grid">'
        + _pack_health_metric_cell("Health", score_disp, verdict, " " + _hi_mod if "bad" in score_cls or "warn" in score_cls else "")
        + _pack_health_metric_cell("Conflicts", str(tc), hi_sev, " " + _cf_mod if tc else "")
        + _pack_health_metric_cell("Preflight", dec_head, _short(pre_msg, 48) if pre_msg else dec, " " + _pf_mod if dec != "allow" else "")
        + _pack_health_metric_cell("Performance", perf_line, _short(perf_sub, 48), " " + _pr_mod if perf_n else "")
        + "</div>"
        + (fidelity_html if fidelity_html else "")
        + "</div>"
    )
    st.markdown(tiles_html, unsafe_allow_html=True)
    with st.expander("Readiness insights", expanded=False):
        _render_forager_hub_readiness_insights_expander(
            rep=rep,
            sf=sf,
            hs=hs,
            pre_msg=pre_msg,
            tc=tc,
            hi_sev=hi_sev,
            dec=dec,
            eff_mc=eff_mc,
            eff_ld=eff_ld,
            widget_suffix=suf,
        )

    rb1, rb2, rb3 = st.columns([1, 1, 1], gap="small")
    with rb1:
        if st.button("Pack Health", key=f"hub_risk_nav_ph_{suf}", use_container_width=True, type="primary"):
            st.session_state["forager_nav"] = "conflicts"
            st.rerun()
    with rb2:
        if st.button("Power Center", key=f"hub_risk_nav_pc_{suf}", use_container_width=True, type="secondary"):
            st.session_state["forager_nav"] = "power_center"
            st.rerun()
    with rb3:
        if st.button("Refresh snapshot", key=f"hub_risk_rf_{suf}", use_container_width=True, type="secondary"):
            _forager_hub_cached_preflight.clear()
            st.rerun()


def _render_forager_hub_authoring_panel(*, pack_root: str) -> None:
    """Authoring brief + decision log (Hub **Prompts** panel)."""
    _suf = _forager_hub_tape_stable_widget_suffix(pack_root)
    gk = f"fab_goals_{_suf}"
    fk = f"fab_focus_{_suf}"
    if gk not in st.session_state:
        b0 = load_authoring_brief(pack_root)
        _brief_parts: List[str] = []
        if str(b0.get("goals") or "").strip():
            _brief_parts.append(str(b0["goals"]).strip())
        if str(b0.get("non_goals") or "").strip():
            _brief_parts.append(f"Out of scope: {b0['non_goals'].strip()}")
        if str(b0.get("target_audience") or "").strip():
            _brief_parts.append(f"Audience: {b0['target_audience'].strip()}")
        st.session_state[gk] = "\n\n".join(_brief_parts)
        st.session_state[fk] = b0["today_focus"]

    st.caption("Steers Hub replies · saved under `.forager/`.")
    st.text_area(
        "Pack brief",
        height=80,
        key=gk,
        placeholder="Goals, audience, out-of-scope — what the AI should assume about this pack.",
        help="Merged into every Hub answer.",
    )
    st.text_input(
        "Today's focus",
        key=fk,
        placeholder="e.g. stabilize crashes before adding mods",
    )
    if st.button("Save brief", key=f"fab_sv_{_suf}", use_container_width=True):
        save_authoring_brief(
            pack_root,
            {
                "goals": str(st.session_state.get(gk, "")),
                "non_goals": "",
                "target_audience": "",
                "today_focus": str(st.session_state.get(fk, "")),
            },
        )
        st.success("Brief saved.")
        st.rerun()

    _dek = f"fab_dec_line_{_suf}"
    _dc1, _dc2 = st.columns([5, 1], gap="small")
    with _dc1:
        st.text_input(
            "Settled decision",
            key=_dek,
            label_visibility="collapsed",
            placeholder="Settled call the AI should honor…",
        )
    with _dc2:
        if st.button("Add", key=f"fab_deca_{_suf}", use_container_width=True):
            append_decision_log(pack_root, summary=str(st.session_state.get(_dek, "") or "").strip())
            st.session_state[_dek] = ""
            st.rerun()
    _recent = load_recent_decisions(pack_root, max_entries=3)
    for _row in _recent:
        if not isinstance(_row, dict):
            continue
        _sm = str(_row.get("summary") or "").strip()
        if _sm:
            st.caption(f"· {html.escape(_sm[:200])}")


def _compute_hub_reference_pair_diff(
    *,
    pack_root: str,
    pack_brain_name: str,
    pick_by_label: Dict[str, Any],
) -> str:
    """Mods / shallow-folder delta vs Hub **reference** pick (fresh read from session widgets)."""
    ref_lbl = str(st.session_state.get("forager_hub_compare_ref_label") or "").strip()
    if not ref_lbl or ref_lbl == "— None —":
        return ""
    ref_pick = pick_by_label.get(ref_lbl)
    if ref_pick is None or not getattr(ref_pick, "root", None):
        return ""
    ref_root = str(ref_pick.root).strip()
    if not os.path.isdir(ref_root) or os.path.normpath(ref_root) == os.path.normpath(pack_root):
        return ""
    try:
        _cm_diff = compare_mods_roots(pack_root, ref_root, max_files=1400)
        _cs_diff = compare_surface_folders(pack_root, ref_root, max_names=1200)
        ref_name = str(getattr(ref_pick, "brain_name", "") or Path(ref_root).name)
        return format_hub_reference_diff_narrative(
            mods_cmp=_cm_diff,
            surface_cmp=_cs_diff,
            label_active=str(pack_brain_name),
            label_reference=ref_name,
        )
    except Exception:
        return ""


def _render_forager_hub_golden_prompts_panel(*, pack_root: str) -> None:
    """Saved regression prompts (Hub **Prompts** panel)."""
    suf = _forager_hub_tape_stable_widget_suffix(pack_root)
    gp_area = f"gp_area_{suf}"
    if gp_area not in st.session_state:
        _gp0 = load_golden_prompts(pack_root).get("prompts")
        _pls = [_ for _ in (_gp0 or []) if str(_).strip()] if isinstance(_gp0, list) else []
        st.session_state[gp_area] = "\n".join(str(x) for x in _pls)

    st.caption("Re-run after pack or prompt changes · one question per line.")
    st.text_area(
        "Saved questions",
        height=96,
        key=gp_area,
        placeholder="Which mods conflict on upgrade?\nIs Create pacing fair for casual players?",
    )
    if st.button("Save list", key=f"gq_sv_{suf}", use_container_width=True):
        _raw = str(st.session_state.get(gp_area) or "")
        save_golden_prompts(pack_root, [ln.strip() for ln in _raw.splitlines() if ln.strip()])
        st.success("List saved.")
        st.rerun()
    _qlines = [ln.strip() for ln in str(st.session_state.get(gp_area) or "").splitlines() if ln.strip()]
    for _qi, _ln in enumerate(_qlines[:8]):
        _btn_lbl = _ln if len(_ln) <= 46 else f"{_ln[:43]}…"
        if st.button(
            _btn_lbl,
            key=f"gq_bt_{suf}_{_qi}",
            use_container_width=True,
            help=_ln[:560],
        ):
            st.session_state[_FORAGER_HUB_PROMPT_QUEUE_KEY] = _ln
            st.rerun()



def _render_forager_hub_prompt_controls_panel() -> str:
    """RAG, answer shape, quick prompts (Hub **Prompts** panel). Returns hub mode full label."""
    if "forager_hub_use_rag" not in st.session_state:
        st.session_state["forager_hub_use_rag"] = bool(launcher.config.get("embedding_rag", True))
    with st.container(border=True, gap="small"):
        st.markdown('<p class="forager-hub-tune-caption">Tune the reply</p>', unsafe_allow_html=True)
        _tog = getattr(st, "toggle", None)
        if callable(_tog):
            _tog(
                "Retrieve from notes & corpus (RAG)",
                key="forager_hub_use_rag",
                help="Per-screen preference; mirrors Settings by default.",
            )
        else:
            st.checkbox(
                "Retrieve from notes & corpus (RAG)",
                key="forager_hub_use_rag",
                help="Per-screen preference.",
            )

        mode_full = _pick_forager_hub_mode()

        st.markdown("**Example questions**")
        for _qrow in range(0, len(_FORAGER_HUB_QUICK_PROMPTS), 2):
            _qr = st.columns(2)
            for _k in range(2):
                _qi = _qrow + _k
                if _qi >= len(_FORAGER_HUB_QUICK_PROMPTS):
                    break
                _ql, _qt, _qh = _FORAGER_HUB_QUICK_PROMPTS[_qi]
                with _qr[_k]:
                    if st.button(
                        _ql,
                        key=f"forager_hub_qp{_qi}",
                        use_container_width=True,
                        help=_qh,
                    ):
                        st.session_state[_FORAGER_HUB_PROMPT_QUEUE_KEY] = _qt
                        st.rerun()
    return mode_full


