def _forager_make_sidebar_nav_on_change(state_key: str):
    """Return an ``on_change`` handler bound to the active rail widget's session key.

    Hidden routes (Configure Pack, Approvals, …) mount the rail under
    ``_forager_sidebar_choice_hidden``; the visible loop uses ``_forager_sidebar_choice``.
    A single handler that always read the visible key broke navigation from secondary screens
    because that key stayed stale while the hidden radio was the widget actually updating.
    """

    def _on_change() -> None:
        st.session_state["_forager_nav_from_sidebar_widget"] = True
        picked = st.session_state.get(state_key)
        if picked in FORGER_NAV_KEY_BY_LABEL:
            st.session_state["forager_nav"] = FORGER_NAV_KEY_BY_LABEL[str(picked)]

    return _on_change


