    kind_labels = {
        "mods": "Mods",
        "resourcepack": "Resource packs",
        "shader": "Shader packs",
        "datapack": "Datapacks",
        "modpack": "Modpacks",
    }
    if "mods_mc_ver" not in st.session_state:
        st.session_state["mods_mc_ver"] = "1.20.1"

    query = ""

    browse_popular = True
    run_search = False
    mr_listing = False
    cf_listing = False

    _lim_list = [24, 48, 72, 96, 120, 200, 300, 400, 600, 800, 1200, 1600, 2000]
    _mlim_raw = st.session_state.get("mods_limit", 200)
