    if st.button("Save retrieval folders", key="settings_save_rag_roots"):
        set_rag_roots([ln.strip() for ln in rag_roots_in.splitlines() if ln.strip()])
        st.success("Retrieval folders saved.")

    with st.expander("Confirmed facts for AI", expanded=False):
        st.caption("Short truths you want every assistant call to respect (e.g. “Server runs Java 17”).")
        _facts = list_facts(pack_key=None) or []
        for _fi, _f in enumerate(_facts[-40:]):
            _fid = str(_f.get("id") or "")
            _ft = str(_f.get("text") or "")[:300]
            _fpk = str(_f.get("pack_key") or "") or "global"
            c0, c1 = st.columns([4, 1])
            with c0:
                st.write(f"**{_fpk}** — {_ft}")
            with c1:
                if st.button("Del", key=f"fdel_{_fi}_{_fid}"):
                    delete_fact(_fid)
                    st.rerun()
        _nf = st.text_input("New fact", key="settings_new_fact", placeholder="Never delete worldwithout backup")
        _nf_pk = st.text_input("Pack name scope (blank = global)", key="settings_new_fact_pk", placeholder="")
        if st.button("Add fact", key="settings_add_fact"):
            if add_fact(_nf, pack_key=_nf_pk.strip()):
                st.success("Fact saved.")
                st.rerun()
            else:
                st.warning("Enter a longer fact.")
        _bulk = st.text_area(
            "Bulk import (one fact per line)",
            height=88,
            key="settings_bulk_facts",
            placeholder="Server runs Java 17\nWorld backups live on D:\\backups",
        )
        _bulk_pk = st.text_input(
            "Pack scope for bulk lines (blank = global)",
            key="settings_bulk_facts_pk",
            placeholder="",
        )
        if st.button("Import lines as facts", key="settings_bulk_facts_run"):
            _n = import_facts_from_lines(_bulk, pack_key=_bulk_pk.strip())
